        self.conn.execute("CREATE INDEX IF NOT EXISTS idx_duties_assigned_car ON duties(assigned_car_id)")
        self.conn.execute("CREATE INDEX IF NOT EXISTS idx_duties_assigned_vehicle_type ON duties(assigned_vehicle_type)")
