    @staticmethod
    def strip_version_info_from_business_text(value: object) -> str:
        """Usuń oznaczenia wersji z tekstów biznesowych: nazw, planów i uwag."""
        text = str(value or "")
        if not text:
            return text
        patterns = [
            (r"\s*\(?\bwersj(?:a|i|e|ę|ą|ach)?\s+v\d{1,4}(?:_recomp)?\b\)?", ""),
            (r"\s*\(?\bversion\s+v\d{1,4}(?:_recomp)?\b\)?", ""),
            (r"\s*\(?\bwg\s+zasad\s+v\d{1,4}(?:_recomp)?\b\)?", " wg zasad"),
            (r"\s*\(?\bv\d{1,4}(?:_recomp)?\b\)?", ""),
        ]
        cleaned = text
        for pattern, replacement in patterns:
            cleaned = re.sub(pattern, replacement, cleaned, flags=re.IGNORECASE)
        cleaned = re.sub(r"[ \t]{2,}", " ", cleaned)
        cleaned = re.sub(r"\s+([,.;:])", r"\1", cleaned)
        cleaned = cleaned.replace(" - ", " - ").strip()
        return cleaned

    def remove_version_info_from_business_data(self) -> None:
        """Oczyść istniejącą bazę z oznaczeń wersji w danych widocznych dla użytkownika."""
        target_columns = {
            "drivers": {"name"},
            "duties": {"name", "duty_type", "line"},
            "original_schedule": {"code", "name", "duty_name", "driver_name", "driver", "note", "description", "line", "remarks"},
            "planned_schedule": {"note"},
            "planned_schedule_backup": {"note"},
            "driver_pairs": {"pair_no", "note"},
            "permanent_driver_pairs": {"pair_no", "note"},
            "duty_blocks": {"note"},
            "cars": {"description"},
            "compliance_violations": {"message", "details", "suggestion"},
        }
        changed = False
        for table, wanted_columns in target_columns.items():
            try:
                column_rows = list(self.conn.execute(f'PRAGMA table_info("{table}")'))
            except sqlite3.Error:
                continue
            existing = {str(row[1]) for row in column_rows}
            for column in sorted(wanted_columns & existing):
                try:
                    rows = list(self.conn.execute(f'SELECT rowid, "{column}" FROM "{table}" WHERE "{column}" IS NOT NULL'))
                except sqlite3.Error:
                    continue
                for rowid, old_value in rows:
                    new_value = self.strip_version_info_from_business_text(old_value)
                    if new_value != str(old_value):
                        self.conn.execute(f'UPDATE "{table}" SET "{column}"=? WHERE rowid=?', (new_value, rowid))
                        changed = True
        if changed:
            self.conn.commit()

    def ensure_bus_division_v169(self) -> None:
        """Jednorazowo wprowadź do bazy podział autobusów z arkusza użytkownika.

        Import działa tylko raz dla danej bazy, aby późniejsze ręczne zmiany
        użytkownika nie były nadpisywane przy każdym uruchomieniu programu.
        Dodawane są autobusy oraz stałe pary kierowców przypisane do autobusów.
        Dodatkowe autobusy dopisane ręcznie przez użytkownika pozostają w bazie.
        """
        meta_key = "bus_division_imported_v169"
        already = self.one_value("SELECT value FROM app_meta WHERE key=?", (meta_key,), default="")
        if already == "1":
            return
        imported_cars = 0
        imported_pairs = 0
        missing_drivers: list[str] = []
        for sort_order, (registration_no, first_shift_driver, second_shift_driver) in enumerate(DEFAULT_BUS_DIVISION_V169, start=1):
            reg = str(registration_no or "").strip().upper()
            if not reg:
                continue
            description = "Autobus - podział wg arkusza"
            self.conn.execute(
                """
                INSERT INTO cars(registration_no, description, active, sort_order, updated_at)
                VALUES (?, ?, 1, ?, CURRENT_TIMESTAMP)
                ON CONFLICT(registration_no) DO UPDATE SET
                    description=excluded.description,
                    active=1,
                    sort_order=excluded.sort_order,
                    updated_at=CURRENT_TIMESTAMP
                """,
                (reg, description, sort_order),
            )
            car_id = int(self.one_value("SELECT id FROM cars WHERE registration_no=?", (reg,), default="0") or 0)
            if not car_id:
                continue
            imported_cars += 1
            driver1_id = self.resolve_bus_division_driver_id(first_shift_driver)
            driver2_id = self.resolve_bus_division_driver_id(second_shift_driver)
            if first_shift_driver and not driver1_id:
                missing_drivers.append(str(first_shift_driver).strip())
            if second_shift_driver and not driver2_id:
                missing_drivers.append(str(second_shift_driver).strip())
            # Jeśli arkusz ma kierowcę tylko w kolumnie II zmiany, zapisz go jako
            # pierwszego kierowcę pary. Dzięki temu autobus będzie widoczny w
            # stałych parach i można go później ręcznie uzupełnić/zmienić.
            if driver1_id is None and driver2_id is not None:
                driver1_id, driver2_id = driver2_id, None
            if driver1_id is not None:
                note = "podział autobusów"
                self.save_permanent_driver_pair(str(sort_order), car_id, int(driver1_id), int(driver2_id) if driver2_id else None, note)
                imported_pairs += 1
        self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES (?, '1')", (meta_key,))
        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('bus_division_imported_v169_count', ?)",
            (str(imported_cars),),
        )
        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('bus_division_imported_v169_pair_count', ?)",
            (str(imported_pairs),),
        )
        if missing_drivers:
            unique_missing = ", ".join(sorted(set(missing_drivers)))
            self.conn.execute(
                "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('bus_division_imported_v169_missing_drivers', ?)",
                (unique_missing,),
            )
        self.conn.commit()

    def resolve_bus_division_driver_id(self, name: object) -> int | None:
        """Znajdź kierowcę z arkusza podziału autobusów po nazwisku/inicjale."""
        raw = str(name or "").replace(",", " ").strip()
        if not raw:
            return None
        target_norm = self.normalize_code(raw)
        target_tokens = self.normalized_tokens(raw)
        if not target_tokens:
            return None
        rows = self.rows("SELECT id, name FROM drivers ORDER BY name COLLATE NOCASE")
        exact_matches: list[int] = []
        subset_matches: list[int] = []
        contains_matches: list[int] = []
        for row in rows:
            driver_id = int(row["id"])
            driver_name = str(row["name"] or "")
            driver_norm = self.normalize_code(driver_name)
            driver_tokens = self.normalized_tokens(driver_name)
            if driver_norm == target_norm:
                exact_matches.append(driver_id)
                continue
            if target_tokens and target_tokens.issubset(driver_tokens):
                subset_matches.append(driver_id)
                continue
            if target_norm and target_norm in driver_norm:
                contains_matches.append(driver_id)
        for matches in (exact_matches, subset_matches, contains_matches):
            if len(matches) == 1:
                return matches[0]
        return None

    def ensure_car_list_reset_v86(self) -> None:
        """Jednorazowo wyczyść starą listę aut, aby można ją było wprowadzić od nowa.

        Poprzednie wersje mogły zostawić niewidoczne lub nieczytelne wpisy aut.
        Wersja v86 resetuje listę tylko raz dla danej bazy użytkownika.
        Pary miesięczne zostają, ale tracą przypisanie do auta; stałe pary aut są czyszczone.
        """
        already = self.one_value("SELECT value FROM app_meta WHERE key='cars_reset_v86'", default="")
        if already == "1":
            return
        self.reset_cars_tables_v86(commit=False)
        self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('cars_reset_v86', '1')")
        self.conn.commit()

    def reset_cars_tables_v86(self, *, commit: bool = True) -> None:
        """Wyczyść listę aut i stałe pary, bez usuwania kierowców ani planu służb."""
        try:
            self.conn.execute("DELETE FROM permanent_driver_pairs")
        except sqlite3.OperationalError:
            pass
        try:
            self.conn.execute("UPDATE driver_pairs SET car_id=NULL, updated_at=CURRENT_TIMESTAMP")
        except sqlite3.OperationalError:
            pass
        try:
            self.conn.execute("DELETE FROM cars")
        except sqlite3.OperationalError:
            pass
        try:
            self.conn.execute("UPDATE planned_schedule SET car_id=NULL WHERE car_id IS NOT NULL")
        except sqlite3.OperationalError:
            pass
        if commit:
            self.conn.commit()

