    def ensure_permanent_pairs_from_existing_months_v84(self) -> None:
        """Uzupełnij stałe pary z istniejących par miesięcznych, jeśli ich jeszcze nie ma."""
        try:
            permanent_count = int(self.one_value("SELECT COUNT(*) FROM permanent_driver_pairs", default="0") or 0)
        except sqlite3.OperationalError:
            return
        if permanent_count > 0:
            return
        month_row = self.conn.execute(
            """
            SELECT month_key, COUNT(*) AS cnt
            FROM driver_pairs
            WHERE car_id IS NOT NULL AND driver1_id IS NOT NULL
            GROUP BY month_key
            ORDER BY month_key ASC
            LIMIT 1
            """
        ).fetchone()
        if not month_row:
            return
        saved = self.save_month_pairs_as_permanent(str(month_row["month_key"]))
        if saved:
            self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('permanent_pairs_initialized_v84', ?)", (str(month_row["month_key"]),))
            self.conn.commit()

    def replace_permanent_pairs_from_month_v291(self, month_key: str) -> int:
        """Przenieś pary z dawnej kopii miesięcznej do globalnej tabeli par."""
        rows = self.rows(
            """
            SELECT pair_no, COALESCE(pair_order, 0) AS pair_order, car_id, driver1_id, driver2_id, COALESCE(note, '') AS note
            FROM driver_pairs
            WHERE month_key=? AND car_id IS NOT NULL AND driver1_id IS NOT NULL
            ORDER BY CASE WHEN COALESCE(pair_order, 0)>0 THEN 0 ELSE 1 END,
                     CASE WHEN COALESCE(pair_order, 0)>0 THEN COALESCE(pair_order, 0) ELSE CAST(CASE WHEN pair_no GLOB '[0-9]*' THEN pair_no ELSE '999999' END AS INTEGER) END,
                     pair_no
            """,
            (month_key,),
        )
        if not rows:
            return 0
        self.conn.execute("DELETE FROM permanent_driver_pairs")
        saved = 0
        for row in rows:
            old_order = int(row["pair_order"] or 0)
            # v293: jeżeli stara baza miała oddzielną kolumnę Kolejność druku,
            # przejmujemy ją jako nowy Nr pary / druk.
            merged_pair_no = str(old_order) if old_order > 0 else (row["pair_no"] or "")
            self.save_permanent_driver_pair(
                merged_pair_no,
                int(row["car_id"]),
                int(row["driver1_id"]),
                int(row["driver2_id"]) if row["driver2_id"] is not None else None,
                row["note"] or "",
                old_order,
            )
            saved += 1
        if saved:
            self.conn.commit()
        return saved

    def known_pair_month_keys_v291(self, include_month_key: str | None = None) -> list[str]:
        """Miesiące, dla których trzeba odbudować techniczną kopię par."""
        keys: set[str] = set()
        if include_month_key:
            keys.add(str(include_month_key))
        try:
            current = self.target_month_key()
            if current:
                keys.add(current)
        except Exception:
            pass
        try:
            for row in self.rows("SELECT DISTINCT month_key FROM driver_pairs WHERE month_key IS NOT NULL AND TRIM(month_key)<>''"):
                keys.add(str(row["month_key"]))
        except Exception:
            pass
        try:
            for row in self.rows("SELECT DISTINCT substr(plan_date, 1, 7) AS month_key FROM planned_schedule WHERE plan_date IS NOT NULL AND TRIM(plan_date)<>''"):
                if row["month_key"]:
                    keys.add(str(row["month_key"]))
        except Exception:
            pass
        try:
            year = str(self.one_value("SELECT value FROM app_meta WHERE key='last_target_year'", default="") or "").strip()
            month = str(self.one_value("SELECT value FROM app_meta WHERE key='last_target_month'", default="") or "").strip()
            if re.fullmatch(r"\d{4}", year) and re.fullmatch(r"\d{1,2}", month):
                keys.add(f"{int(year):04d}-{int(month):02d}")
        except Exception:
            pass
        return sorted(k for k in keys if re.fullmatch(r"\d{4}-\d{2}", k))

    def sync_global_pairs_to_all_months(self, include_month_key: str | None = None) -> None:
        """Odbuduj miesięczne kopie z globalnych par, bez zmiany źródła prawdy."""
        if getattr(self, "_syncing_global_pairs_v291", False):
            return
        self._syncing_global_pairs_v291 = True
        try:
            if not self.permanent_pair_rows():
                return
            for month_key in self.known_pair_month_keys_v291(include_month_key):
                self.copy_permanent_pairs_to_month(month_key, overwrite=True)
        finally:
            self._syncing_global_pairs_v291 = False

    def ensure_global_pair_storage_v291(self) -> None:
        """Jednorazowo zamień dawne pary miesięczne na pary globalne.

        Od tej wersji użytkownik zapisuje pary tylko globalnie. Jeżeli w starszej
        bazie były pary wpisane wyłącznie w konkretnym miesiącu, pierwsze
        uruchomienie bierze najnowszą/najpełniejszą kopię miesięczną jako globalny
        wzorzec i potem odbudowuje z niego techniczne kopie dla miesięcy.
        """
        try:
            already = str(self.one_value("SELECT value FROM app_meta WHERE key='global_pair_storage_v291'", default="") or "")
            latest_month = self.conn.execute(
                """
                SELECT month_key, COUNT(*) AS cnt, MAX(COALESCE(updated_at, created_at, '')) AS last_update
                FROM driver_pairs
                WHERE car_id IS NOT NULL AND driver1_id IS NOT NULL
                GROUP BY month_key
                ORDER BY last_update DESC, cnt DESC, month_key DESC
                LIMIT 1
                """
            ).fetchone()
            permanent_count = int(self.one_value("SELECT COUNT(*) FROM permanent_driver_pairs", default="0") or 0)
            if already != "1" and latest_month is not None:
                # Pierwsza migracja v291: jeśli użytkownik miał zapis tylko w miesiącu,
                # traktujemy najnowszy kompletny miesiąc jako globalny wzorzec.
                self.replace_permanent_pairs_from_month_v291(str(latest_month["month_key"]))
                self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('global_pair_storage_v291_source_month', ?)", (str(latest_month["month_key"]),))
            elif permanent_count == 0 and latest_month is not None:
                self.replace_permanent_pairs_from_month_v291(str(latest_month["month_key"]))
            self.sync_global_pairs_to_all_months()
            self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('global_pair_storage_v291', '1')")
            self.conn.commit()
        except Exception as exc:
            self.log_error("ensure_global_pair_storage_v291", exc)

    def repair_global_pair_print_orders_v292(self) -> None:
        """Napraw globalną kolumnę Kolejność druku używaną przez podgląd i wydruk.

        Starsze wersje mogły mieć kolejność wpisaną w technicznej kopii
        driver_pairs, a wydruk przy brakach potrafił wracać do kolejności aut.
        Od v292 źródłem sortowania jest wyłącznie permanent_driver_pairs.pair_order.
        Jeżeli globalna para nie ma tej wartości, przenosimy ją z najnowszej
        kopii miesięcznej tego samego auta.
        """
        try:
            rows = self.rows(
                """
                SELECT pp.id, COALESCE(pp.pair_order, 0) AS permanent_order,
                       (
                           SELECT COALESCE(dp.pair_order, 0)
                           FROM driver_pairs dp
                           WHERE dp.car_id=pp.car_id AND COALESCE(dp.pair_order, 0)>0
                           ORDER BY COALESCE(dp.updated_at, dp.created_at, '') DESC, dp.id DESC
                           LIMIT 1
                       ) AS copied_order
                FROM permanent_driver_pairs pp
                """
            )
            changed = 0
            for row in rows:
                current_order = int(row["permanent_order"] or 0)
                copied_order = int(row["copied_order"] or 0)
                if current_order <= 0 and copied_order > 0:
                    self.conn.execute(
                        "UPDATE permanent_driver_pairs SET pair_order=?, updated_at=CURRENT_TIMESTAMP WHERE id=?",
                        (copied_order, int(row["id"])),
                    )
                    changed += 1
            if changed:
                self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('global_pair_print_order_repaired_v292', ?)", (str(changed),))
                self.conn.commit()
                self.sync_global_pairs_to_all_months()
        except Exception as exc:
            self.log_error("repair_global_pair_print_orders_v292", exc)

    def unify_pair_no_and_print_order_v293(self) -> None:
        """Połącz numer pary z kolejnością druku.

        Od v293 użytkownik wpisuje tylko Nr pary / druk. Kolumna pair_order
        zostaje w bazie wyłącznie dla zgodności technicznej i jest nadpisywana
        wartością wynikającą z pair_no. Dzięki temu podgląd, wydruk HTML i PDF
        nie mogą już użyć innej kolejności niż numer pary z zakładki par.
        """
        try:
            # Najpierw zachowaj starą ręcznie wpisaną Kolejność druku jako nowy numer pary.
            self.conn.execute(
                """
                UPDATE permanent_driver_pairs
                SET pair_no = CAST(pair_order AS TEXT)
                WHERE COALESCE(pair_order, 0)>0
                """
            )
            self.conn.execute(
                """
                UPDATE driver_pairs
                SET pair_no = CAST(pair_order AS TEXT)
                WHERE COALESCE(pair_order, 0)>0
                """
            )
            # Od tego miejsca pair_order jest tylko techniczną kopią Nr pary / druk.
            self.conn.execute(
                """
                UPDATE permanent_driver_pairs
                SET pair_order = CAST(pair_no AS INTEGER)
                WHERE TRIM(COALESCE(pair_no, '')) GLOB '[0-9]*'
                """
            )
            self.conn.execute(
                """
                UPDATE driver_pairs
                SET pair_order = CAST(pair_no AS INTEGER)
                WHERE TRIM(COALESCE(pair_no, '')) GLOB '[0-9]*'
                """
            )
            self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('pair_no_is_print_order_v293', '1')")
            self.conn.commit()
            self.sync_global_pairs_to_all_months()
        except Exception as exc:
            self.log_error("unify_pair_no_and_print_order_v293", exc)

