    def ensure_default_reserve_duty(self) -> None:
        """Upewnij się, że w bazie istnieją rezerwy R i R2.

        R jest rezerwą poranną, a R2 rezerwą popołudniową 14:00-22:00.
        Automat planuje je na końcu jako uzupełnienie brakujących rbh, tylko do
        miesięcznej normy oraz z zachowaniem odpoczynków.
        """
        existing = {self.normalize_code(row["code"]): int(row["id"]) for row in self.rows("SELECT id, code FROM duties")}
        reserve_defaults = {
            "R": ("R", "Rezerwa", "04:40", "14:40", "10", "8"),
            "R2": ("R2", "Rezerwa popołudniowa", "14:00", "22:00", "8", "8"),
        }
        for code, (name, shift, start_time, end_time, total_time, work_hours) in reserve_defaults.items():
            if code not in existing:
                self.conn.execute(
                    """
                    INSERT INTO duties(code, name, duty_type, shift, line, start_time, end_time, total_time, work_hours,
                                       can_plan_weekdays, can_plan_saturday, can_plan_sunday, source_sheet)
                    VALUES (?, ?, 'rezerwa', ?, '', ?, ?, ?, ?, 1, 0, 0, 'app')
                    """,
                    (code, name, shift, start_time, end_time, total_time, work_hours),
                )
            else:
                self.conn.execute(
                    """
                    UPDATE duties
                    SET duty_type=COALESCE(NULLIF(duty_type, ''), 'rezerwa'),
                        shift=COALESCE(NULLIF(shift, ''), ?),
                        start_time=COALESCE(NULLIF(start_time, ''), ?),
                        end_time=COALESCE(NULLIF(end_time, ''), ?),
                        total_time=COALESCE(NULLIF(total_time, ''), ?),
                        work_hours=COALESCE(NULLIF(work_hours, ''), ?),
                        can_plan_weekdays=COALESCE(can_plan_weekdays, 1),
                        can_plan_saturday=COALESCE(can_plan_saturday, 0),
                        can_plan_sunday=COALESCE(can_plan_sunday, 0)
                    WHERE UPPER(code)=?
                    """,
                    (shift, start_time, end_time, total_time, work_hours, code),
                )
        self.conn.execute(
            """
            UPDATE duties
            SET name='R2',
                duty_type='rezerwa',
                shift='Rezerwa popołudniowa',
                start_time='14:00',
                end_time='22:00',
                work_range='14:00-22:00',
                total_time='8',
                work_hours='8',
                can_plan_weekdays=1,
                can_plan_saturday=0,
                can_plan_sunday=0
            WHERE UPPER(code)='R2'
            """
        )
        self.conn.commit()

