    def ensure_all_service_work_hours_v69(self) -> None:
        """v113: ustaw wszystkie służby robocze na dokładnie 8 rbh.

        Każda służba/rezerwa/szkolenie/liczona nieobecność ma 8 rbh, aby
        automat mógł domykać miesięczny nominał co do 8 godzin.
        Tylko W, WG i UB pozostają 0 rbh, bo nie zwiększają nominału pracy.
        Ta korekta jest wykonywana przy każdym starcie, żeby starsze bazy
        i ręcznie zmienione wartości nie zaburzały planowania nominalnego.
        """
        self.conn.execute(
            """
            UPDATE duties
            SET work_hours='8'
            WHERE UPPER(TRIM(COALESCE(code, ''))) NOT IN ('W', 'WG', 'UB')
            """
        )
        self.conn.execute(
            """
            UPDATE duties
            SET work_hours='0'
            WHERE UPPER(TRIM(COALESCE(code, ''))) IN ('W', 'WG', 'UB')
            """
        )
        self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('all_duties_8h_v113', '1')")
        self.conn.commit()

