    def ensure_default_duty_day_flags(self) -> None:
        """Ustaw domyślne dni planowania dla starszych baz.

        Reguły startowe v10:
        - opis zawiera „sobota” -> tylko sobota,
        - kod jest numerem i opis nie zawiera tokenu „SW” ani „sobota" -> tylko pn.-pt.,
        - pozostałe służby zostają dostępne według dotychczasowych flag.
        Użytkownik może później ręcznie zmienić flagi w zakładce Baza służb.
        """
        self.conn.execute("UPDATE duties SET can_plan_weekdays=1 WHERE can_plan_weekdays IS NULL")
        self.conn.execute("UPDATE duties SET can_plan_saturday=1 WHERE can_plan_saturday IS NULL")
        self.conn.execute("UPDATE duties SET can_plan_sunday=1 WHERE can_plan_sunday IS NULL")
        initialized = self.one_value("SELECT value FROM app_meta WHERE key='default_day_flags_initialized_v10_2'", default="")
        if initialized != "1":
            rows = self.rows("SELECT id, code, name, duty_type, shift, line FROM duties")
            for row in rows:
                weekdays, saturday, sunday, _reason = self.suggest_day_flags_for_duty(row)
                self.conn.execute(
                    "UPDATE duties SET can_plan_weekdays=?, can_plan_saturday=?, can_plan_sunday=? WHERE id=?",
                    (weekdays, saturday, sunday, int(row["id"])),
                )
            self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('default_day_flags_initialized_v10_2', '1')")
        self.conn.commit()

    def normalize_code(self, value: object) -> str:
        text = "" if value is None else str(value)
        text = text.replace("Ł", "L").replace("ł", "l")
        text = unicodedata.normalize("NFKD", text)
        text = "".join(ch for ch in text if not unicodedata.combining(ch))
        return text.strip().upper()

    def normalize_text(self, value: object) -> str:
        """Zwróć tekst bez polskich znaków, bez zmiany wielkości liter."""
        text = "" if value is None else str(value)
        text = text.replace("Ł", "L").replace("ł", "l")
        text = unicodedata.normalize("NFKD", text)
        text = "".join(ch for ch in text if not unicodedata.combining(ch))
        return text.strip()

    def normalized_tokens(self, value: object) -> set[str]:
        normalized = self.normalize_code(value)
        return {part for part in re.split(r"[^A-Z0-9]+", normalized) if part}

    def normalize_display_text(self, value: object) -> str:
        """Ujednolić tekst pokazywany w UI: bez nadmiarowych spacji."""
        text = "" if value is None else str(value)
        return re.sub(r"\s+", " ", text).strip()

    def ui_driver_label_from_row(self, row: sqlite3.Row | dict[str, object]) -> str:
        """Kierowca w UI: tylko nazwisko/nazwa, bez LP i numeru pracownika."""
        try:
            driver_id = row["id"]
        except Exception:
            driver_id = ""
        try:
            name = row["name"]
        except Exception:
            name = ""
        label = self.normalize_display_text(name)
        return label or (f"kierowca {driver_id}" if driver_id not in (None, "") else "kierowca")

    def ui_driver_label_by_id(self, driver_id: int | None) -> str:
        if driver_id is None:
            return NO_DRIVER
        row = self.conn.execute("SELECT id, name FROM drivers WHERE id=?", (int(driver_id),)).fetchone()
        if row is None:
            return f"kierowca {driver_id}"
        return self.ui_driver_label_from_row(row)

    def ui_duty_code_text(self, code: object) -> str:
        """Służba w UI: numery jako 'SŁ. 12', kody specjalne jako sam kod."""
        raw = self.normalize_display_text(code).upper()
        if not raw:
            return "SŁ. ?"
        number_match = re.search(r"\d+", raw)
        normalized = self.normalize_code(raw)
        if raw.isdigit():
            return f"SŁ. {raw}"
        if normalized.startswith("SL") and number_match:
            return f"SŁ. {number_match.group(0)}"
        return raw

    def ui_duty_label_from_row(self, row: sqlite3.Row | dict[str, object]) -> str:
        try:
            code = row["code"]
        except Exception:
            code = ""
        try:
            duty_id = row["id"]
        except Exception:
            duty_id = ""
        label = self.ui_duty_code_text(code)
        return label if label != "SŁ. ?" else f"SŁ. {duty_id}"

    def ui_duty_label_from_parts(self, code: object = "", duty_id: object = "") -> str:
        label = self.ui_duty_code_text(code)
        return label if label != "SŁ. ?" else (f"SŁ. {duty_id}" if duty_id not in (None, "") else "SŁ. ?")

    def extract_duty_lookup_code(self, value: object) -> str:
        """Zwróć kod do wyszukiwania służby z tekstu typu 'SŁ. 12', 'SL 12', '12', 'RN'."""
        text = self.normalize_display_text(value)
        if not text:
            return ""
        normalized = self.normalize_code(text)
        number_match = re.search(r"\d+", normalized)
        if normalized.startswith("SL") and number_match:
            return number_match.group(0)
        if normalized.isdigit():
            return normalized
        return normalized

    def auto_fit_tree_columns(self, tree: ttk.Treeview, *, max_width: int = 520, min_width: int = 52, padding: int = 34) -> None:
        """Dopasuj szerokości kolumn do nagłówków i aktualnej zawartości tabeli."""
        try:
            font = tkfont.nametofont("TkDefaultFont")
            heading_font = tkfont.nametofont("TkHeadingFont")
        except Exception:
            font = None
            heading_font = None

        try:
            displaycolumns_raw = list(tree.tk.splitlist(tree.cget("displaycolumns")))
            all_columns = list(tree.tk.splitlist(tree.cget("columns")))
        except Exception:
            return

        if not all_columns:
            return

        if displaycolumns_raw and displaycolumns_raw != ["#all"]:
            columns = [col for col in displaycolumns_raw if col in all_columns]
        else:
            columns = all_columns

        def walk_items(parent: str = "") -> list[str]:
            result: list[str] = []
            try:
                children = list(tree.get_children(parent))
            except tk.TclError:
                return result
            for child in children:
                result.append(child)
                result.extend(walk_items(child))
            return result

        item_ids = walk_items("")

        for col in columns:
            try:
                heading = str(tree.heading(col).get("text") or col)
            except Exception:
                heading = str(col)
            values = [heading]
            for iid in item_ids:
                try:
                    values.append(str(tree.set(iid, col) or ""))
                except Exception:
                    pass

            if font is not None:
                data_width = max((font.measure(value.replace("\n", " ")) for value in values), default=0)
                if heading_font is not None:
                    data_width = max(data_width, heading_font.measure(heading.replace("\n", " ")))
                width = data_width + self.scaled(padding)
            else:
                width = max((len(value.replace("\n", " ")) for value in values), default=0) * 8 + padding

            # Bardzo długie opisy zostają ograniczone, żeby tabela nie znikała poza ekranem.
            normalized_col = str(col).lower()
            local_max_width = max_width
            if any(token in normalized_col for token in ("name", "opis", "uwagi", "reason", "description")):
                local_max_width = max(local_max_width, 680)
            if normalized_col in {"date", "data", "day", "dzien", "dzień", "month", "miesiac", "miesiąc"}:
                local_max_width = min(local_max_width, 170)

            width = max(self.scaled(min_width), min(self.scaled(local_max_width), int(width)))
            try:
                tree.column(col, width=width, minwidth=max(self.scaled(42), min(width, self.scaled(90))))
            except tk.TclError:
                pass

        self.draw_tree_vertical_separators(tree)

    def schedule_auto_fit_tree_columns(self, tree: ttk.Treeview) -> None:
        """Zaplanuj dopasowanie kolumn po zakończeniu bieżącego odświeżania tabeli."""
        if getattr(tree, "_planer_autofit_pending", False):
            return
        tree._planer_autofit_pending = True  # type: ignore[attr-defined]

        def run() -> None:
            try:
                tree._planer_autofit_pending = False  # type: ignore[attr-defined]
                self.auto_fit_tree_columns(tree)
            except tk.TclError:
                pass
            except Exception:
                # Dopasowanie jest funkcją wizualną, więc nie może blokować działania programu.
                try:
                    tree._planer_autofit_pending = False  # type: ignore[attr-defined]
                except Exception:
                    pass

        try:
            tree.after_idle(run)
        except tk.TclError:
            pass

    def visible_tree_columns(self, tree: ttk.Treeview) -> list[str]:
        """Zwróć kolumny w kolejności widocznej w tabeli."""
        try:
            all_columns = list(tree.tk.splitlist(tree.cget("columns")))
            displaycolumns = list(tree.tk.splitlist(tree.cget("displaycolumns")))
        except tk.TclError:
            return []
        if displaycolumns and displaycolumns != ["#all"]:
            return [col for col in displaycolumns if col in all_columns]
        return all_columns

    def draw_tree_vertical_separators(self, tree: ttk.Treeview) -> None:
        """Narysuj pionowe linie pomiędzy kolumnami Treeview.

        Tkinterowy ttk.Treeview nie ma natywnej opcji pionowej siatki komórek,
        dlatego program dokłada cienkie, nieaktywne separatory nakładane na tabelę.
        """
        try:
            if not tree.winfo_exists() or tree.winfo_width() <= 1:
                return
        except tk.TclError:
            return

        try:
            separators = list(getattr(tree, "_planer_vertical_separators", []))
        except Exception:
            separators = []

        columns = self.visible_tree_columns(tree)
        needed = max(0, len(columns) - 1)

        while len(separators) < needed:
            try:
                sep = tk.Frame(tree, width=max(1, self.scaled(1)), bg="#64748b", cursor="")
                try:
                    sep.lower()
                except tk.TclError:
                    pass
                separators.append(sep)
            except tk.TclError:
                break
        while len(separators) > needed:
            sep = separators.pop()
            try:
                sep.destroy()
            except tk.TclError:
                pass

        try:
            tree._planer_vertical_separators = separators  # type: ignore[attr-defined]
        except Exception:
            pass

        if not separators:
            return

        try:
            total_width = sum(max(0, int(tree.column(col, "width") or 0)) for col in columns)
            view_width = max(1, int(tree.winfo_width()))
            xview = tree.xview()
            x_offset = int(float(xview[0]) * max(0, total_width - view_width)) if xview else 0
            height = max(1, int(tree.winfo_height()))
        except Exception:
            return

        x = 0
        sep_index = 0
        for col in columns[:-1]:
            try:
                x += int(tree.column(col, "width") or 0)
            except tk.TclError:
                continue
            sep_x = x - x_offset
            sep = separators[sep_index]
            sep_index += 1
            try:
                if 0 <= sep_x <= view_width:
                    sep.place(x=sep_x, y=0, width=max(1, self.scaled(1)), height=height)
                    sep.lift()
                else:
                    sep.place_forget()
            except tk.TclError:
                pass

        for sep in separators[sep_index:]:
            try:
                sep.place_forget()
            except tk.TclError:
                pass

    def install_tree_vertical_grid(self, tree: ttk.Treeview) -> None:
        """Włącz pionowe separatory i ich odświeżanie dla pojedynczej tabeli."""
        if getattr(tree, "_planer_vertical_grid_installed", False):
            return
        tree._planer_vertical_grid_installed = True  # type: ignore[attr-defined]

        def refresh(_event=None) -> None:
            try:
                self.schedule_auto_fit_tree_columns(tree)
                tree.after_idle(lambda t=tree: self.draw_tree_vertical_separators(t))
            except tk.TclError:
                pass

        try:
            tree.bind("<Map>", refresh, add="+")
            tree.bind("<Configure>", refresh, add="+")
            tree.bind("<Expose>", refresh, add="+")
            tree.bind("<ButtonRelease-1>", refresh, add="+")
            tree.bind("<MouseWheel>", lambda event: tree.after_idle(lambda t=tree: self.draw_tree_vertical_separators(t)), add="+")
            tree.bind("<Shift-MouseWheel>", lambda event: tree.after_idle(lambda t=tree: self.draw_tree_vertical_separators(t)), add="+")
        except tk.TclError:
            pass
        self.schedule_auto_fit_tree_columns(tree)

    def suggest_day_flags_for_duty(self, duty: sqlite3.Row | dict[str, object]) -> tuple[int, int, int, str]:
        def read(key: str) -> str:
            try:
                return str(duty[key] or "")
            except Exception:
                return ""

        code = self.normalize_code(read("code"))
        text = " ".join(read(key) for key in ("code", "name", "duty_type", "shift", "line"))
        normalized_text = self.normalize_code(text)
        tokens = self.normalized_tokens(text)
        if "SOBOTA" in normalized_text:
            return 0, 1, 0, "opis zawiera sobota"
        if code.isdigit() and "SW" not in tokens:
            return 1, 0, 0, "numer bez SW/sobota"
        return 1, 1, 1, "standard"

    def ensure_default_global_duty_exclusions(self) -> None:
        """Zachowaj starsze globalne wyłączenia, ale tylko jako ustawienie startowe.

        Od v325 użytkownik może sam zdecydować przy każdej służbie, czy automat
        może ją planować. Dlatego domyślnych wyłączeń nie odtwarzamy w kółko po
        ręcznej zmianie użytkownika.
        """
        initialized = self.one_value("SELECT value FROM app_meta WHERE key='default_global_duty_exclusions_v325'", default="")
        if initialized == "1":
            return
        rows = self.rows("SELECT id, code FROM duties")
        target = {self.normalize_code(code) for code in DEFAULT_EXCLUDED_DUTY_CODES}
        matched_ids = [int(row["id"]) for row in rows if self.normalize_code(row["code"]) in target]
        for duty_id in matched_ids:
            self.conn.execute("INSERT OR IGNORE INTO excluded_duties(duty_id) VALUES (?)", (duty_id,))
            self.conn.execute("UPDATE duties SET auto_plan_enabled=0 WHERE id=?", (duty_id,))
        self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('default_global_duty_exclusions_v325', '1')")
        self.conn.commit()

    def ensure_manual_only_special_duties_v325(self) -> None:
        """Ustaw jako tylko ręczne typowe nieobecności i służby Rezerwacja.

        Działa jednorazowo dla istniejących baz. Później użytkownik może zmienić
        decyzję przy konkretnej służbie w formularzu „Baza służb”.
        """
        initialized = self.one_value("SELECT value FROM app_meta WHERE key='manual_only_special_duties_v325'", default="")
        if initialized == "1":
            return
        target_codes = {self.normalize_code(code) for code in DEFAULT_EXCLUDED_DUTY_CODES}
        rows = self.rows("SELECT id, code, name, duty_type, shift, line FROM duties")
        matched_ids: list[int] = []
        for row in rows:
            code = self.normalize_code(row["code"])
            text = " ".join(str(row[key] or "") for key in ("code", "name", "duty_type", "shift", "line"))
            normalized_text = self.normalize_code(text)
            if code in target_codes or "REZERWACJA" in normalized_text:
                matched_ids.append(int(row["id"]))
        for duty_id in matched_ids:
            self.conn.execute("UPDATE duties SET auto_plan_enabled=0 WHERE id=?", (duty_id,))
            self.conn.execute("INSERT OR IGNORE INTO excluded_duties(duty_id) VALUES (?)", (duty_id,))
        self.conn.execute("INSERT OR REPLACE INTO app_meta(key, value) VALUES ('manual_only_special_duties_v325', '1')")
        self.conn.commit()

    def rows(self, sql: str, params: tuple = ()) -> list[sqlite3.Row]:
        return list(self.conn.execute(sql, params))

    def one_value(self, sql: str, params: tuple = (), default: str = "") -> str:
        row = self.conn.execute(sql, params).fetchone()
        if not row:
            return default
        value = row[0]
        return default if value is None else str(value)


    def ensure_compliance_defaults(self) -> None:
        cur = self.conn.cursor()
        for key, value in COMPLIANCE_DEFAULTS.items():
            cur.execute("INSERT OR IGNORE INTO compliance_settings(key, value) VALUES (?, ?)", (key, value))
        self.conn.commit()

    def compliance_setting(self, key: str, default: str = "") -> str:
        return self.one_value("SELECT value FROM compliance_settings WHERE key=?", (key,), default=default)

    def compliance_float(self, key: str, default: float) -> float:
        raw = self.compliance_setting(key, str(default)).replace(",", ".").strip()
        try:
            return float(raw)
        except ValueError:
            return default

    def compliance_bool(self, key: str, default: bool = True) -> bool:
        raw = self.compliance_setting(key, "1" if default else "0").strip().lower()
        return raw in {"1", "true", "tak", "yes", "on"}


