    def set_plan_date_month_end(self) -> None:
        rng = self.selected_month_range()
        if rng:
            self.plan_end_date_var.set(rng[1]) if hasattr(self, "plan_end_date_var") else None
            if not self.plan_date_var.get().strip():
                self.plan_date_var.set(rng[1])

    def clear_manual_dates(self) -> None:
        if hasattr(self, "plan_date_var"):
            self.plan_date_var.set("")
        if hasattr(self, "plan_end_date_var"):
            self.plan_end_date_var.set("")

    def parse_manual_calendar_initial_date(self, target_var: tk.StringVar) -> date:
        """Wyznacz datę startową dla kalendarza ręcznego planowania."""
        raw = target_var.get().strip() if target_var is not None else ""
        if raw:
            try:
                return datetime.strptime(raw, "%Y-%m-%d").date()
            except ValueError:
                pass
        rng = self.selected_month_range()
        if rng:
            try:
                return datetime.strptime(rng[0], "%Y-%m-%d").date()
            except ValueError:
                pass
        return date.today()

    def open_manual_date_calendar(self, target_var: tk.StringVar, anchor_widget: tk.Widget | None = None) -> None:
        """Otwórz mały kalendarz wyboru daty dla ręcznego planowania."""
        if target_var is None:
            return
        selected_date = self.parse_manual_calendar_initial_date(target_var)
        visible_year = tk.IntVar(value=selected_date.year)
        visible_month = tk.IntVar(value=selected_date.month)

        dialog = tk.Toplevel(self)
        dialog.title("Wybierz datę")
        dialog.transient(self)
        dialog.grab_set()
        dialog.resizable(False, False)

        container = ttk.Frame(dialog, padding=10)
        container.pack(fill="both", expand=True)

        header = ttk.Frame(container)
        header.pack(fill="x", pady=(0, 8))

        title_var = tk.StringVar()
        days_frame = ttk.Frame(container)
        days_frame.pack(fill="both", expand=True)

        def month_name(month: int) -> str:
            return dict(POLISH_MONTHS).get(f"{month:02d}", str(month))

        def shift_month(delta: int) -> None:
            year = int(visible_year.get())
            month = int(visible_month.get()) + delta
            while month < 1:
                month += 12
                year -= 1
            while month > 12:
                month -= 12
                year += 1
            visible_year.set(year)
            visible_month.set(month)
            render_days()

        def choose(day: int) -> None:
            try:
                chosen = date(int(visible_year.get()), int(visible_month.get()), int(day))
            except ValueError:
                return
            target_var.set(chosen.isoformat())
            dialog.destroy()

        def render_days() -> None:
            for child in days_frame.winfo_children():
                child.destroy()
            year = int(visible_year.get())
            month = int(visible_month.get())
            title_var.set(f"{month_name(month).upper()} {year}")
            for col, label in enumerate(POLISH_WEEKDAYS):
                ttk.Label(days_frame, text=label, width=4, anchor="center", style="Hint.TLabel").grid(row=0, column=col, padx=1, pady=(0, 3))
            month_calendar = calendar.Calendar(firstweekday=0).monthdayscalendar(year, month)
            today = date.today()
            for row_idx, week in enumerate(month_calendar, start=1):
                for col_idx, day_no in enumerate(week):
                    if not day_no:
                        ttk.Label(days_frame, text="", width=4).grid(row=row_idx, column=col_idx, padx=1, pady=1)
                        continue
                    button_text = str(day_no)
                    style_name = "TButton"
                    if date(year, month, day_no) == today:
                        button_text = f"•{day_no}"
                    ttk.Button(days_frame, text=button_text, width=4, style=style_name, command=lambda d=day_no: choose(d)).grid(row=row_idx, column=col_idx, padx=1, pady=1)

        ttk.Button(header, text="‹", width=3, command=lambda: shift_month(-1)).pack(side="left")
        ttk.Label(header, textvariable=title_var, width=22, anchor="center", font=("Segoe UI", 10, "bold")).pack(side="left", padx=6)
        ttk.Button(header, text="›", width=3, command=lambda: shift_month(1)).pack(side="left")

        footer = ttk.Frame(container)
        footer.pack(fill="x", pady=(8, 0))
        ttk.Button(footer, text="Dziś", command=lambda: (visible_year.set(date.today().year), visible_month.set(date.today().month), render_days())).pack(side="left")
        ttk.Button(footer, text="Wyczyść", command=lambda: (target_var.set(""), dialog.destroy())).pack(side="left", padx=(6, 0))
        ttk.Button(footer, text="Anuluj", command=dialog.destroy).pack(side="right")

        render_days()
        dialog.update_idletasks()
        try:
            if anchor_widget is not None:
                x = anchor_widget.winfo_rootx()
                y = anchor_widget.winfo_rooty() + anchor_widget.winfo_height() + 2
                width = max(dialog.winfo_width(), dialog.winfo_reqwidth())
                height = max(dialog.winfo_height(), dialog.winfo_reqheight())
                screen_w = dialog.winfo_screenwidth()
                screen_h = dialog.winfo_screenheight()
                x = max(0, min(x, max(screen_w - width, 0)))
                y = max(0, min(y, max(screen_h - height, 0)))
                dialog.geometry(f"{width}x{height}+{x}+{y}")
            else:
                self.center_child_window(dialog)
        except tk.TclError:
            self.center_child_window(dialog)
        dialog.bind("<Escape>", lambda _event: dialog.destroy())
        dialog.wait_window()

    def set_result_range_today(self) -> None:
        today = date.today().isoformat()
        self.result_start_var.set(today)
        self.result_end_var.set(today)
        self.load_result_plan_tree()

    def tree_sort_value(self, value: object) -> tuple[int, object]:
        text = "" if value is None else str(value).strip()
        if not text:
            return (0, "")
        try:
            return (1, datetime.strptime(text, "%Y-%m-%d"))
        except ValueError:
            pass
        normalized = text.replace(" ", "").replace(",", ".")
        if re.fullmatch(r"-?\d+(\.\d+)?", normalized):
            try:
                return (2, float(normalized))
            except ValueError:
                pass
        return (3, text.lower())

    def sort_tree_by_column(self, tree: ttk.Treeview, column: str) -> None:
        key = (id(tree), column)
        reverse = self._tree_sort_state.get(key, False)
        rows = [(self.tree_sort_value(tree.set(item, column)), item) for item in tree.get_children("")]
        rows.sort(key=lambda item: item[0], reverse=reverse)
        for index, (_value, item) in enumerate(rows):
            tree.move(item, "", index)
            current_tags = tuple(tag for tag in tree.item(item, "tags") if tag not in {"oddrow", "evenrow"})
            zebra_tag = "oddrow" if index % 2 == 0 else "evenrow"
            tree.item(item, tags=(zebra_tag,) + current_tags)
        self._tree_sort_state[key] = not reverse
        self.set_status(f"Posortowano kolumnę: {tree.heading(column, option='text')}.")

    def set_sortable_heading(self, tree: ttk.Treeview, column: str, text: str) -> None:
        tree.heading(column, text=text, command=lambda c=column, t=tree: self.sort_tree_by_column(t, c))

    def begin_long_operation(self, text: str = "Trwa praca...") -> None:
        """Rozpocznij długą operację bez okna statusu.

        v102: użytkownik chce tylko komunikat po zakończeniu planowania,
        dlatego nie otwieramy dodatkowego okienka postępu. Zostaje jedynie
        krótki status w głównym oknie i blokada przycisku planowania.
        """
        self.set_status(text)
        if hasattr(self, "auto_plan_button"):
            self.auto_plan_button.configure(state="disabled")
        self._busy_window = None
        self._busy_status_var = None
        self._busy_detail_var = None
        self._busy_progress_var = None
        self._busy_progress_bar = None
        self._busy_log_widget = None
        try:
            self.update_idletasks()
        except tk.TclError:
            pass


    def update_long_operation_status(self, text: str, detail: str = "", progress: float | None = None) -> None:
        """Aktualizuj pasek statusu i odśwież GUI podczas długiego planowania.

        v357: nie wykonuj pełnego self.update() przy każdym impulsie. Zbyt częste
        przetwarzanie całej kolejki zdarzeń potrafi spowolnić planowanie albo dać
        wrażenie zawieszenia. Pełne odświeżenie robimy najwyżej raz na sekundę.
        """
        if hasattr(self, "status_var"):
            self.status_var.set(text if not detail else f"{text} — {detail}")
        try:
            self.update_idletasks()
            now = time.monotonic()
            last_full_update = float(getattr(self, "_last_long_operation_full_update", 0.0) or 0.0)
            if now - last_full_update >= 1.0:
                self._last_long_operation_full_update = now
                self.update()
        except tk.TclError:
            pass
    def end_long_operation(self) -> None:
        if hasattr(self, "auto_plan_button"):
            self.auto_plan_button.configure(state="normal")
        if self._busy_window is not None:
            try:
                self._busy_window.grab_release()
                self._busy_window.destroy()
            except tk.TclError:
                pass
        self._busy_window = None
        self._busy_status_var = None
        self._busy_detail_var = None
        self._busy_progress_var = None
        self._busy_progress_bar = None
        self._busy_log_widget = None

    def auto_generated_plan_condition_sql(self, alias: str = "") -> str:
        """Warunek SQL dla wpisów automatu/technicznych, które nie mogą przetrwać replanowania.

        Starsze wersje potrafiły zostawić część wpisów automatu z `entry_source='manual'`
        albo z notatką inną niż dokładne `Automatycznie...`. Przy ponownym planowaniu
        takie rekordy zachowywały się jak bufor starego miesiąca i blokowały m.in. RN.
        Ten warunek celowo rozpoznaje także typowe ślady notatek automatu.
        """
        prefix = f"{alias}." if alias else ""
        note = f"COALESCE({prefix}note, '')"
        source = f"LOWER(COALESCE(NULLIF(TRIM({prefix}entry_source), ''), 'manual'))"
        return f"""
        (
            {source}='auto'
            OR {note} LIKE 'Automatycznie%'
            OR {note} LIKE '%dzień wzoru%'
            OR {note} LIKE '%RN obowiązkowe%'
            OR {note} LIKE '%NADGODZINY - RN%'
            OR {note} LIKE '%wolne przy urlopie%'
            OR {note} LIKE '%WG - wolne grafikowe%'
            OR {note} LIKE '%uzupełnienie pustego pola%'
            OR {note} LIKE '%awaryjna zmiana%'
            OR {note} LIKE '%zdjęto % na RN%'
        )
        """

    def manual_plan_keep_condition_sql(self, alias: str = "") -> str:
        """Warunek SQL określający prawdziwe wpisy ręczne zachowywane przy replanowaniu.

        v300: nie wolno już zostawiać każdego rekordu z `entry_source='manual'`,
        bo starsze wersje potrafiły tak oznaczyć wpisy automatu. To właśnie
        dawało efekt starego bufora: miesiąc był niby czyszczony, ale część
        starego planu zostawała jako ręczna blokada. Od tej wersji zachowujemy
        tylko wpisy jawnie ręczne: z notatką `Ręcznie...`, ręczne pary RN albo
        typowe nieobecności/blokady ręczne. Reszta starego miesiąca jest usuwana
        przed ponownym planowaniem.
        """
        prefix = f"{alias}." if alias else ""
        auto_generated = self.auto_generated_plan_condition_sql(alias)
        note = f"COALESCE({prefix}note, '')"
        pair_no = f"COALESCE(NULLIF(TRIM({prefix}pair_no), ''), '')"
        source = f"LOWER(COALESCE(NULLIF(TRIM({prefix}entry_source), ''), 'manual'))"
        duty_code_expr = f"UPPER(COALESCE((SELECT code FROM duties WHERE id={prefix}duty_id), ''))"
        is_rn_duty = f"{duty_code_expr}='RN'"
        # v320: stary znacznik RNPAIR albo notatka 'Ręcznie: RN' nie może
        # zachować wpisu, który po edycji nie jest już RN. To była główna
        # przyczyna błędnego ponownego planowania: nie-RN przeżywały reset jako
        # sztuczne ręczne RN i blokowały nowy automat.
        stale_rn_marker = f"""
        (
            ({pair_no} LIKE 'RNPAIR-%' OR {pair_no} LIKE 'RN-%' OR {note} LIKE 'Ręcznie: RN%' OR {note} LIKE 'Recznie: RN%')
            AND NOT ({is_rn_duty})
        )
        """
        manual_special_codes = "'UW','UO','CH','SZK','NAJEM','NAJEM2','BO','UB','BHP','ZAGLEBIE'"
        explicit_manual = f"""
        (
            {note} LIKE 'Ręcznie%'
            OR {note} LIKE 'Recznie%'
            OR (({pair_no} LIKE 'RNPAIR-%' OR {pair_no} LIKE 'RN-%') AND {is_rn_duty})
            OR {prefix}duty_id IN (
                SELECT id FROM duties
                WHERE UPPER(COALESCE(code, '')) IN ({manual_special_codes})
            )
        )
        """
        return f"""
        (
            {source}='manual'
            AND {explicit_manual}
            AND NOT {auto_generated}
            AND NOT {stale_rn_marker}
        )
        """


    def clear_auto_plan_runtime_buffers(self, month_key: str | None = None) -> None:
        """Wyczyść roboczy stan automatu przed ponownym planowaniem.

        v283: ponowne planowanie ma startować od zera. Baza jest czyszczona
        osobnym resetem, a ta metoda zeruje zmienne pomocnicze trzymane w
        pamięci aplikacji, żeby żaden poprzedni przebieg nie wpływał na nowy
        miesiąc. Nie ruszamy konfiguracji użytkownika ani wpisów ręcznych.
        """
        self._active_month_start_shifts = {}
        self.monthly_excluded_duty_ids = set()
        self.monthly_excluded_driver_ids = set()
        for attr in (
            "_auto_plan_last_entries",
            "_auto_plan_last_context_entries",
            "_auto_plan_last_unfilled",
            "_auto_plan_last_summary",
            "_auto_plan_runtime_cache",
            "_auto_plan_rn_week_drivers",
            "_auto_plan_month_required_duties",
            "_auto_plan_month_rn_required_counts",
            "_auto_plan_planned_context_entries",
            "_auto_plan_manual_context_by_date",
            "_auto_plan_manual_rows",
            "_auto_plan_manual_context_entries",
            "_auto_plan_existing_month_entries",
            "_auto_plan_existing_plan_rows",
            "_auto_plan_existing_driver_days",
            "_auto_plan_day_context",
            "_auto_plan_schedule_by_date",
            "_auto_plan_plan_by_driver_date",
            "_auto_plan_preloaded_entries",
            "_auto_plan_recent_context",
            "_auto_plan_rest_context",
            "_auto_plan_weekend_context",
            "_auto_plan_weekly_duty_driver",
            "_auto_plan_weekly_driver_duty",
            "_auto_plan_entries",
            "_auto_plan_driver_work_intervals",
            "_auto_plan_driver_work_dates",
            "_auto_plan_driver_week_work_count",
            "_auto_plan_driver_month_work_count",
            "_auto_plan_driver_month_work_hours",
            "_auto_plan_run_token",
            "_auto_plan_cold_start_month_key",
            "_auto_plan_followup_running",
            "_auto_plan_cached_manual_ids",
            "_auto_plan_cached_rn_pairs",
            "_auto_plan_cached_rn_counts",
            "_auto_plan_cached_month_context",
            "_manual_plan_context_cache",
            "_manual_plan_rows_cache",
            "_manual_schedule_cache",
            "_planned_schedule_cache",
            "_replan_manual_keep_cache",
            "_replan_month_reset_cache",
        ):
            if hasattr(self, attr):
                try:
                    delattr(self, attr)
                except Exception:
                    try:
                        setattr(self, attr, None)
                    except Exception:
                        pass
        # v297: kasowanie ręcznych wpisów mogło zostawić zaznaczenie edycji i
        # pomocnicze listy z formularza. To nie są dane planu, ale potrafiły
        # kierować następną operację w stronę nieistniejących już rekordów.
        self._manual_edit_plan_id = None
        self._manual_edit_plan_ids = []

    def clear_manual_entry_buffers_before_auto_plan(
        self,
        start: str | None = None,
        end: str | None = None,
        month_key: str | None = None,
        *,
        commit: bool = False,
    ) -> None:
        """Wyczyść wyłącznie pamięciowy bufor wpisów ręcznych przed automatem.

        v370: ręczne wpisy mają zostać w tabeli `planned_schedule`, ale automat
        nie może korzystać z żadnego starego kontekstu z poprzedniego przebiegu
        ani z bufora utworzonego przed dopisaniem/edycją wpisu ręcznego. Dlatego
        przed każdym planowaniem kasujemy stan pamięciowy i znaczniki diagnostyczne,
        a właściwe ręczne blokady czytamy później od nowa z aktualnej bazy.
        """
        self.clear_auto_plan_runtime_buffers(month_key)
        for attr in (
            "_auto_plan_manual_context_by_date",
            "_auto_plan_cached_manual_ids",
            "_auto_plan_cached_month_context",
            "_auto_plan_cached_rn_pairs",
            "_auto_plan_cached_rn_counts",
            "_manual_multi_driver_count_choice",
            "_manual_pair_unavailable_note",
        ):
            if hasattr(self, attr):
                try:
                    delattr(self, attr)
                except Exception:
                    try:
                        setattr(self, attr, None)
                    except Exception:
                        pass
        try:
            self.conn.execute(
                "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_manual_buffer_clear_before_auto_plan_month_v370', ?)",
                (str(month_key or ""),),
            )
            self.conn.execute(
                "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_manual_buffer_clear_before_auto_plan_at_v370', ?)",
                (datetime.now().isoformat(timespec="seconds"),),
            )
            if start and end:
                manual_count = int(self.one_value(
                    f"""
                    SELECT COUNT(*)
                    FROM planned_schedule
                    WHERE plan_date BETWEEN ? AND ?
                      AND {self.manual_plan_keep_condition_sql()}
                    """,
                    (start, end),
                    default="0",
                ) or 0)
                self.conn.execute(
                    "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_manual_buffer_clear_before_auto_plan_manual_count_v370', ?)",
                    (str(max(manual_count, 0)),),
                )
            if commit:
                self.conn.commit()
        except Exception as exc:
            self.log_exception("clear_manual_entry_buffers_before_auto_plan", exc)
            if commit:
                try:
                    self.conn.rollback()
                except Exception:
                    pass

    def force_cold_start_month_context(self, start: str | None = None, end: str | None = None, month_key: str | None = None, *, commit: bool = False) -> None:
        """Twardo wyczyść każdy stan pomocniczy związany z planowaniem miesiąca.

        To nie usuwa ręcznych wpisów użytkownika. Usuwa natomiast pamięć przebiegu
        automatu, stare raporty kontroli oraz metadane ostatniego przebiegu, żeby
        kolejne planowanie zaczynało się tak, jakby miesiąc nie był wcześniej
        planowany. Używane przed każdym automatem oraz po kasowaniu wpisów ręcznych.
        """
        self.clear_auto_plan_runtime_buffers(month_key)
        try:
            if start and end:
                self.conn.execute("DELETE FROM compliance_violations WHERE scope_start=? AND scope_end=?", (start, end))
                self.conn.execute("DELETE FROM compliance_violations WHERE plan_date BETWEEN ? AND ?", (start, end))
        except Exception as exc:
            self.log_exception("force_cold_start_month_context_violations", exc)
        try:
            for key in (
                "last_auto_plan_seed",
                "last_full_replan_reset_month",
                "last_full_replan_reset_removed",
                "last_auto_plan_generated_month",
                "last_auto_plan_generated_at",
                "last_auto_plan_rn_unfilled",
            ):
                self.conn.execute("DELETE FROM app_meta WHERE key=?", (key,))
        except Exception as exc:
            self.log_exception("force_cold_start_month_context_meta", exc)
        if commit:
            try:
                self.conn.commit()
            except Exception as exc:
                self.log_exception("force_cold_start_month_context_commit", exc)

    def affected_month_keys_from_dates(self, dates: list[str] | set[str] | tuple[str, ...] | None) -> list[str]:
        """Zamień listę dat na posortowane klucze miesięcy YYYY-MM.

        Funkcja celowo waliduje daty, bo po ręcznym planowaniu mogły zostać
        przekazane wartości z formularza, filtra albo starego zaznaczenia listy.
        Do resetu pamięciowego bierzemy tylko faktyczne daty planu.
        """
        result: set[str] = set()
        for value in dates or []:
            text = str(value or "").strip()
            if not text:
                continue
            parsed = self.validate_date(text)
            if not parsed:
                continue
            try:
                day = datetime.strptime(parsed, "%Y-%m-%d").date()
            except Exception:
                continue
            result.add(f"{day.year:04d}-{day.month:02d}")
        return sorted(result)

    def reload_manual_plan_context_after_change(
        self,
        dates: list[str] | set[str] | tuple[str, ...] | None = None,
        month_keys: list[str] | set[str] | tuple[str, ...] | None = None,
        *,
        commit: bool = True,
        refresh_reference: bool = False,
        refresh_ui: bool = False,
    ) -> None:
        """Wyczyść pamięć roboczą po każdej zmianie ręcznego planowania.

        v301: ręczne planowanie nie może dopisywać się do starego kontekstu RN,
        R/R2, WG, par ani liczników z poprzedniej próby. Nie usuwamy żadnych
        rekordów `planned_schedule`; zerujemy tylko cache i wymuszamy, żeby kolejne
        planowanie automatyczne zbudowało kontekst ręczny od nowa z aktualnej bazy.
        """
        # Najpierw zawsze wyczyść globalne cache automatu/par, nawet gdy nie
        # potrafimy jeszcze wskazać konkretnego miesiąca. Ręczny plan w bazie
        # zostaje bez zmian.
        self.clear_auto_plan_runtime_buffers(None)
        keys: set[str] = set()
        for key in month_keys or []:
            text = str(key or "").strip()
            if re.match(r"^\d{4}-\d{2}$", text):
                keys.add(text)
        keys.update(self.affected_month_keys_from_dates(dates))
        if not keys:
            target = self.get_target_year_month() if hasattr(self, "get_target_year_month") else None
            if target is not None:
                y, m = target
                keys.add(f"{int(y):04d}-{int(m):02d}")
        try:
            for month_key in sorted(keys):
                try:
                    y, m = [int(part) for part in month_key.split("-", 1)]
                    start, end = self.month_range(y, m)
                    self.force_cold_start_month_context(start, end, month_key, commit=False)
                except Exception as exc:
                    self.log_exception("reload_manual_plan_context_after_change_month", exc)
            # Te wartości są wyłącznie listami/stanami interfejsu i cache; ich
            # wyczyszczenie nie usuwa ręcznych wpisów z planu.
            for attr in (
                "_rn_active_pair_list_ids",
                "_manual_conflict_replace_decision",
                "_manual_cancel_range_save",
                "_manual_conflict_message_shown",
                "_manual_preview_snapshot_path",
            ):
                if hasattr(self, attr):
                    try:
                        if attr == "_rn_active_pair_list_ids":
                            setattr(self, attr, [])
                        elif attr == "_manual_conflict_message_shown":
                            setattr(self, attr, False)
                        else:
                            setattr(self, attr, None)
                    except Exception:
                        pass
            if commit:
                self.conn.commit()
        except Exception as exc:
            self.log_exception("reload_manual_plan_context_after_change", exc)
            if commit:
                try:
                    self.conn.rollback()
                except Exception:
                    pass
        if refresh_reference:
            try:
                self.load_reference_data(update_month=False)
            except Exception as exc:
                self.log_exception("reload_manual_plan_context_after_change_reference", exc)
        if refresh_ui:
            try:
                self.refresh_all()
            except Exception as exc:
                self.log_exception("reload_manual_plan_context_after_change_ui", exc)
            try:
                if hasattr(self, "refresh_manual_rn_pair_section"):
                    self.refresh_manual_rn_pair_section()
            except Exception as exc:
                self.log_exception("reload_manual_plan_context_after_change_rn_section", exc)

    def cleanup_stale_manual_rn_markers_before_replan(self, start: str, end: str) -> int:
        """Usuń stare techniczne znaczniki RNPAIR/RN z wpisów, które nie są już RN.

        v320: przy edycji ręcznej starsze wersje potrafiły zostawić `pair_no`
        RNPAIR oraz notatkę `Ręcznie: RN...` przy wpisie zmienionym później na
        WG, W, NAJEM, UW itd. Taki wpis przeżywał reset miesiąca i kolejne
        planowanie startowało z fałszywą ręczną blokadą. Czyścimy tylko marker,
        nie usuwamy prawdziwego ręcznego wpisu.
        """
        try:
            rn_ids = self.rn_duty_ids_from_db()
            changed = 0
            if rn_ids:
                placeholders = ",".join("?" for _ in rn_ids)
                params = [start, end, *sorted(int(x) for x in rn_ids)]
                cur = self.conn.execute(
                    f"""
                    UPDATE planned_schedule
                    SET pair_no=NULL,
                        updated_at=CURRENT_TIMESTAMP
                    WHERE plan_date BETWEEN ? AND ?
                      AND duty_id NOT IN ({placeholders})
                      AND (
                          COALESCE(NULLIF(TRIM(pair_no), ''), '') LIKE 'RNPAIR-%'
                          OR COALESCE(NULLIF(TRIM(pair_no), ''), '') LIKE 'RN-%'
                      )
                    """,
                    tuple(params),
                )
                changed += max(0, int(cur.rowcount or 0))
            else:
                cur = self.conn.execute(
                    """
                    UPDATE planned_schedule
                    SET pair_no=NULL,
                        updated_at=CURRENT_TIMESTAMP
                    WHERE plan_date BETWEEN ? AND ?
                      AND (
                          COALESCE(NULLIF(TRIM(pair_no), ''), '') LIKE 'RNPAIR-%'
                          OR COALESCE(NULLIF(TRIM(pair_no), ''), '') LIKE 'RN-%'
                      )
                    """,
                    (start, end),
                )
                changed += max(0, int(cur.rowcount or 0))
            self.conn.execute(
                "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_stale_rn_markers_cleared_v320', ?)",
                (str(changed),),
            )
            return changed
        except Exception as exc:
            self.log_exception("cleanup_stale_manual_rn_markers_before_replan", exc)
            return 0

    def reset_month_before_replan(self, start: str, end: str, month_key: str) -> dict[str, int]:
        """Fizycznie wyczyść miesiąc przed ponownym planowaniem.

        v316: poprzednie wersje kasowały głównie rekordy spełniające warunek
        "nie jest jawnie ręczny". Przy nietypowych/starych bazach mogły jednak
        zostać rekordy wyglądające jak ręczne albo techniczne kopie starego
        planu. To dawało efekt, że drugie planowanie po uruchomieniu programu
        korzystało z resztek miesiąca zamiast zaczynać od zera.

        Dlatego reset jest teraz fizyczny i atomowy:
        1. skopiuj do tabeli tymczasowej wyłącznie prawdziwe wpisy ręczne,
        2. usuń cały miesiąc z planned_schedule bez warunków,
        3. wstaw z powrotem tylko skopiowane wpisy ręczne,
        4. dopiero potem buduj nowy automat.
        """
        # v372: reset miesiąca musi zaczynać się od pustego kontekstu pamięciowego.
        # Same wpisy ręczne zostają w planned_schedule; niżej kopiujemy je do tabeli
        # tymczasowej i odczytujemy ponownie z bazy po fizycznym skasowaniu miesiąca.
        self.clear_manual_entry_buffers_before_auto_plan(start, end, month_key, commit=False)

        keep_manual = self.manual_plan_keep_condition_sql()
        auto_generated = self.auto_generated_plan_condition_sql()
        cur = self.conn.cursor()
        temp_table = "_manual_keep_replan_v316"
        stale_rn_markers_cleared = self.cleanup_stale_manual_rn_markers_before_replan(start, end)

        total_before = int(self.one_value(
            "SELECT COUNT(*) FROM planned_schedule WHERE plan_date BETWEEN ? AND ?",
            (start, end),
            default="0",
        ) or 0)
        manual_before = int(self.one_value(
            f"""
            SELECT COUNT(*)
            FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND {keep_manual}
            """,
            (start, end),
            default="0",
        ) or 0)
        auto_like_before = int(self.one_value(
            f"""
            SELECT COUNT(*)
            FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND {auto_generated}
            """,
            (start, end),
            default="0",
        ) or 0)

        cur.execute(f"DROP TABLE IF EXISTS temp.{temp_table}")
        cur.execute(
            f"""
            CREATE TEMP TABLE {temp_table} AS
            SELECT id, plan_date, driver_id, duty_id, note, entry_source, car_id, pair_no, created_at, updated_at
            FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND {keep_manual}
            """,
            (start, end),
        )
        kept_in_temp = int(self.one_value(f"SELECT COUNT(*) FROM temp.{temp_table}", default="0") or 0)

        # Najważniejsza zmiana v316: usuń cały miesiąc bez polegania na entry_source/note.
        cur.execute("DELETE FROM planned_schedule WHERE plan_date BETWEEN ? AND ?", (start, end))
        deleted_all = int(cur.rowcount if cur.rowcount is not None else total_before)

        # Przywróć tylko wpisy ręczne skopiowane przed resetem. Zachowujemy id, aby
        # lista ręcznych wpisów i edycje nie odwoływały się do nowych identyfikatorów.
        cur.execute(
            f"""
            INSERT OR REPLACE INTO planned_schedule
                (id, plan_date, driver_id, duty_id, note, entry_source, car_id, pair_no, created_at, updated_at)
            SELECT id, plan_date, driver_id, duty_id, note, COALESCE(NULLIF(TRIM(entry_source), ''), 'manual'), car_id, pair_no, created_at, updated_at
            FROM temp.{temp_table}
            """
        )
        restored_manual = int(cur.rowcount if cur.rowcount is not None else kept_in_temp)
        cur.execute(f"DROP TABLE IF EXISTS temp.{temp_table}")

        cur.execute("DELETE FROM compliance_violations WHERE scope_start=? AND scope_end=?", (start, end))
        removed_scope_violations = int(cur.rowcount if cur.rowcount is not None else 0)
        cur.execute("DELETE FROM compliance_violations WHERE plan_date BETWEEN ? AND ?", (start, end))
        removed_day_violations = int(cur.rowcount if cur.rowcount is not None else 0)

        # Kontrola po fizycznym resecie: w miesiącu mogą zostać tylko wpisy jawnie ręczne.
        remaining_non_manual = int(self.one_value(
            f"""
            SELECT COUNT(*)
            FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND NOT {keep_manual}
            """,
            (start, end),
            default="0",
        ) or 0)
        if remaining_non_manual > 0:
            cur.execute(
                f"""
                DELETE FROM planned_schedule
                WHERE plan_date BETWEEN ? AND ?
                  AND NOT {keep_manual}
                """,
                (start, end),
            )
            deleted_all += max(0, int(cur.rowcount or 0))

        manual_after = int(self.one_value(
            f"""
            SELECT COUNT(*)
            FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND {keep_manual}
            """,
            (start, end),
            default="0",
        ) or 0)
        total_after = int(self.one_value(
            "SELECT COUNT(*) FROM planned_schedule WHERE plan_date BETWEEN ? AND ?",
            (start, end),
            default="0",
        ) or 0)

        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_full_replan_reset_month', ?)",
            (month_key,),
        )
        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_full_replan_reset_removed', ?)",
            (str(max(total_before - manual_after, 0)),),
        )
        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_full_replan_manual_after', ?)",
            (str(max(manual_after, 0)),),
        )
        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_full_replan_total_after_reset', ?)",
            (str(max(total_after, 0)),),
        )
        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_full_replan_reset_mode', 'physical_v372')"
        )
        self.conn.execute(
            "INSERT OR REPLACE INTO app_meta(key, value) VALUES ('last_full_replan_buffer_clear_mode', 'v372_before_and_after_physical_reset')"
        )

        # v372: po fizycznym resecie ponownie wyczyść pamięć automatu.
        # To zabezpiecza przypadek, w którym poprzedni przebieg albo podgląd
        # trzymał w RAM-ie stare ręczne blokady/RN/R/R2/WG mimo że baza jest już
        # wyczyszczona i zawiera tylko przywrócone wpisy ręczne.
        self.clear_auto_plan_runtime_buffers(month_key)

        return {
            "total_before": total_before,
            "manual_kept": manual_after,
            "manual_before": manual_before,
            "manual_copied_to_temp": kept_in_temp,
            "manual_restored": restored_manual,
            "plan_removed": max(total_before - manual_after, 0),
            "rows_deleted_physical": max(deleted_all, 0),
            "auto_like_before": max(auto_like_before, 0),
            "auto_like_extra_removed": 0,
            "remaining_non_manual_after_first_delete": max(remaining_non_manual, 0),
            "violations_removed": max(removed_scope_violations, 0) + max(removed_day_violations, 0),
            "stale_rn_markers_cleared": max(int(stale_rn_markers_cleared or 0), 0),
        }

    def create_plan_backup(self, start: str, end: str, month_key: str) -> tuple[str, int]:
        """Zapisz kopię aktualnego planu przed automatycznym nadpisaniem."""
        backup_id = datetime.now().strftime("%Y%m%d_%H%M%S_%f") + "_" + secrets.token_hex(3)
        cur = self.conn.cursor()
        cur.execute("DELETE FROM planned_schedule_backup WHERE created_at < datetime('now', '-90 days')")
        cur.execute(
            """
            INSERT INTO planned_schedule_backup(backup_id, original_id, month_key, plan_date, driver_id, duty_id, note, entry_source, car_id, pair_no)
            SELECT ?, id, ?, plan_date, driver_id, duty_id, note, COALESCE(entry_source, 'auto'), car_id, pair_no
            FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND COALESCE(entry_source, 'manual')='auto'
            """,
            (backup_id, month_key, start, end),
        )
        count = cur.rowcount if cur.rowcount is not None else 0
        self.set_meta("last_auto_backup_id", backup_id)
        self.set_meta("last_auto_backup_month", month_key)
        self.set_meta("last_auto_backup_start", start)
        self.set_meta("last_auto_backup_end", end)
        self.set_meta("last_auto_backup_count", str(max(count, 0)))
        return backup_id, max(count, 0)

    def undo_last_auto_plan(self) -> None:
        backup_id = self.get_meta("last_auto_backup_id", "")
        start = self.get_meta("last_auto_backup_start", "")
        end = self.get_meta("last_auto_backup_end", "")
        month_key = self.get_meta("last_auto_backup_month", "")
        if not backup_id or not start or not end:
            messagebox.showinfo("Cofnij planowanie", "Brak zapisanej kopii do przywrócenia.")
            return
        backup_count = int(self.get_meta("last_auto_backup_count", "0") or "0")
        prompt = (
            f"Przywrócić automatyczne wpisy sprzed ostatniego planowania dla miesiąca {month_key}?\n\n"
            f"Ręczne dni wolne, urlopy i ręczne zmiany zostaną bez zmian. "
            f"Z kopii zostanie przywróconych {backup_count} wcześniejszych wpisów automatu."
        )
        if not messagebox.askyesno("Cofnij ostatnie planowanie", prompt):
            return
        cur = self.conn.cursor()
        cur.execute("DELETE FROM planned_schedule WHERE plan_date BETWEEN ? AND ? AND COALESCE(entry_source, 'manual')='auto'", (start, end))
        cur.execute(
            """
            INSERT INTO planned_schedule(plan_date, driver_id, duty_id, note, entry_source, car_id, pair_no)
            SELECT plan_date, driver_id, duty_id, note, COALESCE(entry_source, 'auto'), car_id, pair_no
            FROM planned_schedule_backup
            WHERE backup_id=?
            ORDER BY original_id
            """,
            (backup_id,),
        )
        self.conn.commit()
        self.audit_and_store(start, end)
        self.load_reference_data(update_month=False)
        self.refresh_all()
        self.set_status(f"Przywrócono poprzedni plan dla {month_key}. Wpisów: {backup_count}.", "Good.TLabel")
        messagebox.showinfo("Cofnięto planowanie", f"Przywrócono poprzedni plan dla {month_key}. Wpisów: {backup_count}.")

    def show_auto_plan_summary(self, summary: dict[str, object], detail_status: str) -> None:
        window = tk.Toplevel(self)
        window.title("Podsumowanie planowania")
        try:
            screen_w = max(760, int(window.winfo_screenwidth()))
            screen_h = max(560, int(window.winfo_screenheight()))
        except tk.TclError:
            screen_w, screen_h = 1024, 768
        width = min(760, max(620, screen_w - 80))
        height = min(620, max(460, screen_h - 120))
        window.geometry(f"{width}x{height}")
        window.minsize(620, 430)
        window.transient(self)

        frame = ttk.Frame(window, padding=14)
        frame.pack(fill="both", expand=True)
        frame.rowconfigure(1, weight=1)
        frame.columnconfigure(0, weight=1)

