            ("WG przed prac. weekendem", summary.get("weekend_pre_rest_swaps", 0)),
            ("R/R2 przeniesione po WG", summary.get("weekend_pre_rest_reserve_moves", 0)),
            ("R/R2 skorygowane do zmiany", summary.get("wrong_reserve_shift_fixed", 0)),
            ("R/R2 usunięte jako niezgodne", summary.get("wrong_reserve_shift_removed", 0)),
            ("R/R2 pominięte limit dzienny", summary.get("reserve_skipped_daily_limit", 0)),
            ("Poniżej normy RBH", summary.get("below_nominal_rbh", 0)),
            ("Powyżej normy RBH", summary.get("above_nominal_rbh", 0)),
            ("Nieobsadzone służby", summary.get("unfilled", 0)),
            ("Niski priorytet po pozostałych", summary.get("low_priority_deferred_planned", 0)),
            ("Zamiany niskiego priorytetu", summary.get("low_priority_swaps", 0)),
