            ("Pominięte weekendowe 80/86/139", summary.get("weekend_80_86_139_skipped", 0)),
            ("Zamiany WG/W", summary.get("wg_swaps", 0)),
            ("Służby przed WG", summary.get("wg_before_write", 0)),
            ("Przeniesione WG", summary.get("wg_relocated", 0)),
            ("Łańcuch WG/R->służba", summary.get("wg_chain_rebalanced", 0)),
            ("WG bez przeniesienia", summary.get("wg_relocation_failed", 0)),
            ("Usunięte techniczne WG/W", summary.get("technical_wg_removed_before_save", 0)),
            ("Dni z niepełną RN", summary.get("rn_unfilled", 0)),
            ("Automatyczne dopuszczenia 561 do 6 h", summary.get("short_compensation_overrides", 0)),
            ("Ostrzeżenia", summary.get("violation_count", 0)),
            ("Kopia przed planowaniem", f"{summary.get('backup_count', 0)} wpisów"),
            ("Seed losowania", str(summary.get('plan_seed', ''))),
