    def create_widgets(self) -> None:
        header = ttk.Frame(self, padding=(12, 10, 12, 0))
        header.pack(fill="x")
        ttk.Label(header, text=APP_TITLE, style="Title.TLabel").pack(side="left")
        # v126: zmienna zostaje tylko wewnętrznie do zapamiętywania ostatniej zakładki.
        # Pole wyboru "Zakładka" nie jest już pokazywane w górnym pasku.
        self.tab_selector_var = tk.StringVar(value="")
