        self.meta_label.pack(side="right")

        status_bar = ttk.Frame(self, padding=(10, 4, 10, 6))
        status_bar.pack(side="bottom", fill="x")
        self.status_var = tk.StringVar(value="")
        self.status_label = ttk.Label(status_bar, textvariable=self.status_var, style="Hint.TLabel")
        self.status_label.pack(side="left", fill="x", expand=True)

        # v91: zamiast jednej długiej listy kilkunastu zakładek używamy
        # trzech głównych obszarów i podzakładek. To poprawia czytelność
        # na mniejszych ekranach oraz w wersji EXE.
        self.tab_registry: list[tuple[str, ttk.Notebook, tk.Widget]] = []
        self.main_notebook = ttk.Notebook(self)
        self.main_notebook.pack(fill="both", expand=True, padx=10, pady=10)

        self.plan_group = ttk.Frame(self.main_notebook)
        self.settings_group = ttk.Frame(self.main_notebook)
        self.reports_group = ttk.Frame(self.main_notebook)
        self.main_notebook.add(self.plan_group, text="Planowanie")
        self.main_notebook.add(self.settings_group, text="Ustawienia")
        self.main_notebook.add(self.reports_group, text="Raporty i wydruki")

        self.plan_notebook = ttk.Notebook(self.plan_group)
        self.settings_notebook = ttk.Notebook(self.settings_group)
        self.reports_notebook = ttk.Notebook(self.reports_group)
        for nb in (self.plan_notebook, self.settings_notebook, self.reports_notebook):
            nb.pack(fill="both", expand=True, padx=6, pady=6)

        self.all_notebooks = [self.plan_notebook, self.settings_notebook, self.reports_notebook]

        self.notebook = self.plan_notebook
        self._current_group_name = "Planowanie"
        self.create_start_tab()
