    def available_year_values(self) -> list[str]:
        """Lista lat do wyboru w polu miesiąca.

        Zawiera lata z danych źródłowych/planu oraz kilka lat wstecz i naprzód,
        żeby użytkownik nie musiał wpisywać roku ręcznie.
        """
        today_year = date.today().year
        years = set(range(today_year - 5, today_year + 8))
        for table, column in (("original_schedule", "date_iso"), ("planned_schedule", "plan_date")):
            try:
                row = self.conn.execute(f"SELECT MIN({column}), MAX({column}) FROM {table}").fetchone()
            except sqlite3.Error:
                continue
            if not row:
                continue
            for value in row:
                if value:
                    try:
                        years.add(int(str(value)[:4]))
                    except ValueError:
                        pass
        try:
            years.add(int(self.target_year_var.get().strip()))
        except ValueError:
            pass
        return [str(year) for year in sorted(years) if 1900 <= year <= 2100]

    def print_year_option_values(self, default_year: int | None = None) -> list[str]:
        """Lista lat do okna wydruku.

        Oprócz lat z danych pokazuje szerszy, stały zakres, żeby użytkownik
        mógł wybrać inny rok bez ręcznego wpisywania i bez zależności od tego,
        czy dla danego roku są już zapisane służby.
        """
        today_year = date.today().year
        years = {int(year) for year in self.available_year_values() if str(year).isdigit()}
        years.update(range(today_year - 10, today_year + 11))
        if default_year is not None:
            years.update(range(default_year - 3, default_year + 4))
        return [str(year) for year in sorted(years) if 1900 <= year <= 2100]

    def create_month_picker(self, parent: ttk.Frame, use_grid: bool = False, row: int = 0, column: int = 0) -> tuple[ttk.Combobox, ttk.Combobox]:
        year_combo = ttk.Combobox(
            parent,
            textvariable=self.target_year_var,
            values=self.available_year_values(),
            width=8,
            state="readonly",
        )
        month_combo = ttk.Combobox(
            parent,
            textvariable=self.target_month_var,
            values=MONTH_VALUES,
            width=6,
            state="readonly",
        )
        # Rok i miesiąc korzystają ze wspólnego, stabilnego mechanizmu list.
        # Dzięki temu lista otwiera się tak samo na stronie Start, w Planowaniu
        # i w pozostałych zakładkach używających wyboru miesiąca.
        self.setup_combobox_dropdown(year_combo, self.available_year_values)
        self.setup_combobox_dropdown(month_combo, lambda: MONTH_VALUES)
        if use_grid:
            ttk.Label(parent, text="Rok:").grid(row=row, column=column, sticky="w")
            year_combo.grid(row=row + 1, column=column, sticky="w", padx=(0, 10), pady=(3, 0))
            ttk.Label(parent, text="Miesiąc:").grid(row=row, column=column + 1, sticky="w")
            month_combo.grid(row=row + 1, column=column + 1, sticky="w", padx=(0, 10), pady=(3, 0))
        else:
            ttk.Label(parent, text="Rok:").pack(side="left")
            year_combo.pack(side="left", padx=(6, 10))
            ttk.Label(parent, text="Miesiąc:").pack(side="left")
            month_combo.pack(side="left", padx=(6, 10))
        year_combo.bind("<<ComboboxSelected>>", lambda _event: self.on_target_month_changed())
        month_combo.bind("<<ComboboxSelected>>", lambda _event: self.on_target_month_changed())
        return year_combo, month_combo


