    def open_duty_picker_for_var(self, target_var: tk.StringVar, title: str = "Wybierz służbę") -> None:
        """Otwórz czytelną listę służb i wpisz wybraną pozycję do wskazanego pola."""
        self.load_reference_data(update_month=False)
        picker = tk.Toplevel(self)
        picker.title(title)
        picker.geometry("900x560")
        picker.transient(self)
        picker.grab_set()

        frame = ttk.Frame(picker, padding=10)
        frame.pack(fill="both", expand=True)
        search_var = tk.StringVar()
        ttk.Label(frame, text="Szukaj służby po numerze, nazwie, linii lub godzinach:").pack(anchor="w")
        search_entry = ttk.Entry(frame, textvariable=search_var)
        search_entry.pack(fill="x", pady=(3, 8))

        cols = ("code", "name", "line", "shift", "time", "rbh")
        tree = ttk.Treeview(frame, columns=cols, show="headings", selectmode="browse")
        headings = {
            "code": "Służba",
            "name": "Opis",
            "line": "Linia",
            "shift": "Zmiana",
            "time": "Godziny",
            "rbh": "rbh",
        }
        widths = {"code": 90, "name": 300, "line": 90, "shift": 90, "time": 160, "rbh": 80}
        for col in cols:
            tree.heading(col, text=headings[col])
            tree.column(col, width=widths[col], anchor="center" if col in {"code", "line", "shift", "rbh"} else "w")
        tree.pack(side="left", fill="both", expand=True)
        scrollbar = ttk.Scrollbar(frame, orient="vertical", command=tree.yview)
        scrollbar.pack(side="right", fill="y")
        tree.configure(yscrollcommand=scrollbar.set)
        self.configure_tree_zebra(tree)

        rows = self.rows(
            """
            SELECT id, code, name, line, shift, work_range, rbh
            FROM duties
            ORDER BY CASE WHEN code GLOB '[0-9]*' THEN 0 ELSE 1 END,
                     CASE WHEN code GLOB '[0-9]*' THEN CAST(code AS INTEGER) ELSE 9999 END,
                     code COLLATE NOCASE
            """
        )

        def label_for_duty_id(duty_id: int) -> str:
            for label, value in self.duty_label_to_id.items():
                if value == duty_id:
                    return label
            for row in rows:
                if int(row["id"]) == int(duty_id):
                    code = row["code"] or ""
                    name = row["name"] or ""
                    time = row["work_range"] or ""
                    return " | ".join(part for part in (str(code), str(name), str(time)) if part)
            return ""

        def fill() -> None:
            for item in tree.get_children():
                tree.delete(item)
            query = search_var.get().strip().lower()
            for row in rows:
                haystack = " ".join(str(row[key] or "") for key in ("code", "name", "line", "shift", "work_range", "rbh")).lower()
                if query and query not in haystack:
                    continue
                self.insert_tree_row(
                    tree,
                    str(row["id"]),
                    (
                        row["code"] or "",
                        row["name"] or "",
                        row["line"] or "",
                        row["shift"] or "",
                        row["work_range"] or "",
                        row["rbh"] or "",
                    ),
                )

        def choose(_event=None) -> None:
            selection = tree.selection()
            if not selection:
                return
            duty_id = int(selection[0])
            label = label_for_duty_id(duty_id)
            if label:
                target_var.set(label)
            picker.destroy()

        button_bar = ttk.Frame(picker, padding=(10, 0, 10, 10))
        button_bar.pack(fill="x")
        ttk.Button(button_bar, text="Wybierz", command=choose).pack(side="right", padx=(8, 0))
        ttk.Button(button_bar, text="Anuluj", command=picker.destroy).pack(side="right")

        search_var.trace_add("write", lambda *_args: fill())
        tree.bind("<Double-1>", choose)
        tree.bind("<Return>", choose)
        self.install_driver_tree_typeahead(tree, name_column="#2")
        fill()
        search_entry.focus_set()

