    def schedule_plan_list_filter_refresh(self, delay_ms: int = 180) -> None:
        """Odśwież listę ręcznych wpisów z krótkim opóźnieniem po pisaniu.

        Bez tego każde naciśnięcie klawisza przebudowywało dużą tabelę i
        ponownie dopasowywało kolumny. Na wolniejszych komputerach wyglądało to
        jak zawieszenie listy. Debounce scala kilka znaków wpisanych po sobie w
        jedno odświeżenie.
        """
        if not hasattr(self, "plan_list_tree"):
            return
        job = getattr(self, "_plan_list_filter_after_id", None)
        if job:
            try:
                self.after_cancel(job)
            except Exception:
                pass
        try:
            self._plan_list_filter_after_id = self.after(int(delay_ms), self._run_plan_list_filter_refresh)
        except Exception:
            self.load_plan_list_tree()

    def _run_plan_list_filter_refresh(self) -> None:
        self._plan_list_filter_after_id = None
        self.load_plan_list_tree()

    def clear_plan_filter_and_show_all(self) -> None:
        if hasattr(self, "plan_filter_var"):
            self.plan_filter_var.set("")
        job = getattr(self, "_plan_list_filter_after_id", None)
        if job:
            try:
                self.after_cancel(job)
            except Exception:
                pass
            self._plan_list_filter_after_id = None
        self.load_plan_list_tree()

    def on_plan_list_mousewheel(self, event: tk.Event) -> str:
        """Przewijaj listę ręcznych wpisów, a nie całą zakładkę.

        Zakładka jest osadzona w przewijanym panelu, który przechwytuje kółko
        myszy. Zwrócenie "break" zatrzymuje to przechwycenie i pozwala
        przewijać samą tabelę ręcznych wpisów.
        """
        if not hasattr(self, "plan_list_tree"):
            return "break"
        try:
            num = getattr(event, "num", None)
            if num == 4:
                self.plan_list_tree.yview_scroll(-3, "units")
            elif num == 5:
                self.plan_list_tree.yview_scroll(3, "units")
            else:
                delta = int(getattr(event, "delta", 0) or 0)
                if delta == 0:
                    return "break"
                step = -1 * int(delta / 120)
                if step == 0:
                    step = -1 if delta > 0 else 1
                self.plan_list_tree.yview_scroll(step, "units")
        except Exception:
            pass
        return "break"

