    def planned_month_label(self, month_key: str) -> str:
        try:
            year_text, month_text = month_key.split("-", 1)
            month_name = dict(POLISH_MONTHS).get(f"{int(month_text):02d}", month_text)
            return f"{month_name} {int(year_text)}"
        except Exception:
            return month_key

    def selected_planned_month_key(self) -> str | None:
        if not hasattr(self, "planned_months_tree"):
            return None
        selection = self.planned_months_tree.selection()
        if not selection:
            messagebox.showinfo("Zaplanowane miesiące", "Zaznacz miesiąc na liście.")
            return None
        return self.planned_month_tree_keys.get(selection[0])

    def set_target_month_from_key(self, month_key: str) -> tuple[str, str] | None:
        try:
            year_text, month_text = month_key.split("-", 1)
            year = int(year_text)
            month = int(month_text)
            start, end = self.month_range(year, month)
        except Exception:
            messagebox.showerror("Zaplanowane miesiące", f"Nieprawidłowy miesiąc: {month_key}")
            return None
        self.target_year_var.set(str(year))
        self.target_month_var.set(f"{month:02d}")
        if hasattr(self, "result_start_var"):
            self.result_start_var.set(start)
        if hasattr(self, "result_end_var"):
            self.result_end_var.set(end)
        return start, end

    def load_planned_months_tree(self) -> None:
        if not hasattr(self, "planned_months_tree"):
            return
        for item in self.planned_months_tree.get_children():
            self.planned_months_tree.delete(item)
        self.planned_month_tree_keys.clear()
        rows = self.rows(
            """
            SELECT substr(p.plan_date, 1, 7) AS month_key,
                   COUNT(*) AS entry_count,
                   COUNT(DISTINCT p.driver_id) AS driver_count,
                   COUNT(DISTINCT p.duty_id) AS duty_count,
                   COALESCE(SUM(CAST(REPLACE(COALESCE(d.work_hours, '0'), ',', '.') AS REAL)), 0) AS rbh_sum,
                   MAX(COALESCE(p.updated_at, p.created_at, p.plan_date)) AS last_update
            FROM planned_schedule p
            LEFT JOIN duties d ON d.id = p.duty_id
            GROUP BY substr(p.plan_date, 1, 7)
            ORDER BY month_key ASC
            """
        )
        for row in rows:
            month_key = str(row["month_key"] or "")
            if not month_key:
                continue
            iid = f"month-{month_key}"
            self.planned_month_tree_keys[iid] = month_key
            self.insert_tree_row(
                self.planned_months_tree,
                iid,
                (
                    month_key,
                    self.planned_month_label(month_key),
                    int(row["entry_count"] or 0),
                    int(row["driver_count"] or 0),
                    int(row["duty_count"] or 0),
                    self.format_rbh_value(float(row["rbh_sum"] or 0.0)),
                    row["last_update"] or "",
                ),
            )
        text = f"Zaplanowane miesiące: {len(rows)}" if rows else "Brak zaplanowanych miesięcy."
        if hasattr(self, "planned_months_status_var"):
            self.planned_months_status_var.set(text)

    def open_selected_planned_month(self) -> None:
        month_key = self.selected_planned_month_key()
        if not month_key:
            return
        if self.set_target_month_from_key(month_key) is None:
            return
        self.load_result_plan_tree()
        self.select_tab(self.result_plan_tab)
        self.set_status(f"Pokazano gotowy plan dla miesiąca {month_key}.", "Good.TLabel")

    def print_selected_planned_month(self) -> None:
        month_key = self.selected_planned_month_key()
        if not month_key:
            return
        if self.set_target_month_from_key(month_key) is None:
            return
        self.print_result_plan()

    def preview_selected_planned_month(self) -> None:
        """Pokaż wybrany miesiąc w przeglądarce bez automatycznego drukowania."""
        month_key = self.selected_planned_month_key()
        if not month_key:
            return
        if self.set_target_month_from_key(month_key) is None:
            return
        try:
            print_options = self.ask_print_options(
                action_label="PODGLĄD",
                title_text="Podgląd planu za jeden miesiąc",
            )
            if print_options is None:
                return
            payload = self.build_print_payload(print_options)
            if payload is None:
                return
            payload = dict(payload)
            payload["auto_print"] = False
            path = self.create_print_html(**payload)
            self.open_print_preview_file(path)
        except Exception as exc:
            messagebox.showerror("Podgląd", f"Nie udało się przygotować podglądu:\n{exc}")

    def export_pdf_selected_planned_month(self) -> None:
        month_key = self.selected_planned_month_key()
        if not month_key:
            return
        if self.set_target_month_from_key(month_key) is None:
            return
        self.export_plan_pdf()

    def delete_selected_planned_month(self) -> None:
        month_key = self.selected_planned_month_key()
        if not month_key:
            return
        date_range = self.set_target_month_from_key(month_key)
        if date_range is None:
            return
        start, end = date_range
        total_count = int(self.one_value("SELECT COUNT(*) FROM planned_schedule WHERE plan_date BETWEEN ? AND ?", (start, end), default="0"))
        keep_manual = self.manual_plan_keep_condition_sql()
        manual_count = int(self.one_value(
            f"""
            SELECT COUNT(*)
            FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND {keep_manual}
            """,
            (start, end),
            default="0",
        ))
        removable_count = max(total_count - manual_count, 0)
        if total_count <= 0:
            messagebox.showinfo("Wykasuj miesiąc", f"Miesiąc {month_key} nie ma wpisów planu.")
            self.load_planned_months_tree()
            return
        if removable_count <= 0:
            messagebox.showinfo(
                "Wykasuj miesiąc",
                f"Miesiąc {month_key} zawiera tylko wpisy ręczne.\n\nNie usunięto ręcznego planowania służb dla kierowców.",
            )
            self.load_planned_months_tree()
            return
        if not messagebox.askyesno(
            "Wykasuj miesiąc",
            f"Wykasować zaplanowany automatycznie plan dla miesiąca {month_key}?\n\n"
            f"Wpisy ręczne zostaną zachowane.\n"
            f"Wpisy do usunięcia: {removable_count}\n"
            f"Wpisy ręczne pozostawione: {manual_count}",
        ):
            return
        cur = self.conn.cursor()
        cur.execute(
            f"""
            DELETE FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND NOT {keep_manual}
            """,
            (start, end),
        )
        removed = int(cur.rowcount if cur.rowcount is not None else removable_count)
        cur.execute("DELETE FROM compliance_violations WHERE scope_start=? AND scope_end=?", (start, end))
        cur.execute("DELETE FROM compliance_violations WHERE plan_date BETWEEN ? AND ?", (start, end))
        self.conn.commit()
        self.force_cold_start_month_context(start, end, month_key, commit=True)
        self.load_reference_data(update_month=False)
        self.refresh_all()
        self.set_status(
            f"Wykasowano automatyczny plan miesiąca {month_key}: {removed} wpisów. Wpisy ręczne zachowane: {manual_count}.",
            "Good.TLabel",
        )
        messagebox.showinfo(
            "Wykasuj miesiąc",
            f"Wykasowano automatyczny plan dla miesiąca {month_key}.\n"
            f"Usunięte wpisy: {removed}\n"
            f"Pozostawione wpisy ręczne: {manual_count}",
        )

