        ttk.Button(top, text="Drukuj plan...", command=self.print_result_plan).pack(side="right")
        ttk.Button(top, text="Podgląd wydruku", command=self.preview_print_result_plan).pack(side="right", padx=(0, 8))
        ttk.Button(top, text="Drukuj propozycje", command=self.print_change_proposals_report).pack(side="right", padx=(0, 8))
        ttk.Button(top, text="Pokaż propozycje zmian", command=self.preview_change_proposals_report).pack(side="right", padx=(0, 8))
        ttk.Button(top, text="Eksportuj PDF", command=self.export_plan_pdf).pack(side="right", padx=(0, 8))
