    def show_selected_duty_details(self) -> None:
        duty_id = self.selected_duty_id_from_tree()
        if duty_id is None:
            return
        row = self.conn.execute(
            """
            SELECT id, code, name, line, duty_type, shift, start_time, end_time,
                   work_range, work_hours, break_start, break_end, break_range,
                   break_duration, occurrences, source_sheet,
                   COALESCE(auto_plan_enabled, 1) AS auto_plan_enabled,
                   COALESCE(can_plan_weekdays, 1) AS can_plan_weekdays,
                   COALESCE(can_plan_saturday, 1) AS can_plan_saturday,
                   COALESCE(can_plan_sunday, 1) AS can_plan_sunday
            FROM duties
            WHERE id=?
            """,
            (duty_id,),
        ).fetchone()
        if not row:
            return
        month_key = self.target_month_key() or ""
        excluded = "tak" if self.is_duty_excluded_for_month(duty_id) else "nie"
        self.show_details_window(
            f"Służba {row['code']}",
            [
                ("Kod służby", row["code"]),
                ("Nazwa", row["name"]),
                ("Linia", row["line"]),
                ("Typ", row["duty_type"]),
                ("Zmiana", row["shift"]),
                ("Godzina rozpoczęcia", row["start_time"]),
                ("Godzina zakończenia", row["end_time"]),
                ("Czas pracy", row["work_range"]),
                ("rbh", row["work_hours"]),
                ("Przerwa od", row["break_start"]),
                ("Przerwa do", row["break_end"]),
                ("Przerwa", row["break_range"]),
                ("Przerwa [h]", row["break_duration"]),
                ("Planować automatycznie", "tak" if int(row["auto_plan_enabled"] or 0) else "nie - tylko ręcznie"),
                ("Planować poniedziałek-piątek", "tak" if int(row["can_plan_weekdays"] or 0) else "nie"),
                ("Planować soboty", "tak" if int(row["can_plan_saturday"] or 0) else "nie"),
                ("Planować niedziele", "tak" if int(row["can_plan_sunday"] or 0) else "nie"),
                (f"Nie planować w miesiącu {month_key}", excluded),
                ("Źródło", row["source_sheet"]),
                ("Nie planować dla kierowców", self.duty_driver_exclusions_summary(duty_id)),
            ],
        )

    def on_plan_list_select_load_to_form(self, event: tk.Event | None = None) -> None:
        """Po kliknięciu wczytaj zaznaczony wpis do formularza edycji."""
        self.load_plan_selection_to_form(auto=True)

    def on_plan_list_motion_load_to_form(self, event: tk.Event) -> None:
        """Po najechaniu myszą na wpis wczytaj jego dane do formularza.

        Nie otwieramy okna szczegółów i nie przełączamy zakładek; formularz
        w tej samej zakładce aktualizuje się od razu.
        """
        if not hasattr(self, "plan_list_tree"):
            return
        iid = self.plan_list_tree.identify_row(event.y)
        if not iid:
            return
        if getattr(self, "_last_hover_plan_iid", None) == iid:
            return
        self._last_hover_plan_iid = iid
        try:
            self.plan_list_tree.selection_set(iid)
            self.plan_list_tree.focus(iid)
        except tk.TclError:
            return
        self.load_plan_selection_to_form(auto=True)

    def on_plan_list_mouse_leave(self, event: tk.Event | None = None) -> None:
        self._last_hover_plan_iid = None

    def on_plan_list_double_click(self, event: tk.Event) -> str:
        """Dwuklik na ręcznym wpisie ma służyć do edycji, bez okna szczegółów.

        Wcześniej dwuklik jednocześnie wczytywał wpis i otwierał okno informacji
        o ręcznie zaplanowanym wydarzeniu. Teraz tylko zaznacza wiersz, ładuje go
        do formularza i ustawia tryb aktualizacji istniejącego wpisu.
        """
        iid = self.plan_list_tree.identify_row(event.y) or self.plan_list_tree.focus()
        if not iid:
            return "break"
        self.plan_list_tree.selection_set(iid)
        self.plan_list_tree.focus(iid)
        self.load_plan_selection_to_form(auto=False)
        return "break"

    def show_plan_entry_details_by_id(self, plan_id: object) -> None:
        if not plan_id:
            return
        ids = self.plan_list_item_plan_ids(str(plan_id)) if hasattr(self, "plan_list_item_plan_ids") else []
        if not ids:
            try:
                ids = [int(str(plan_id))]
            except ValueError:
                return
        plan_id_int = int(ids[0])
        row = self.conn.execute(
            """
            SELECT p.id, p.plan_date, p.note, p.pair_no,
                   COALESCE(dr.name, '') AS driver_name, COALESCE(dr.lp, '') AS driver_lp,
                   d.code, d.name AS duty_name, d.line, d.duty_type, d.shift,
                   d.start_time, d.end_time, d.work_range, d.work_hours,
                   d.break_start, d.break_end, d.break_range, d.break_duration
            FROM planned_schedule p
            JOIN duties d ON d.id = p.duty_id
            LEFT JOIN drivers dr ON dr.id = p.driver_id
            WHERE p.id=?
            """,
            (plan_id_int,),
        ).fetchone()
        if not row:
            return
        self.show_details_window(
            f"Wpis planu: {row['plan_date']} | {row['driver_name'] or NO_DRIVER} | {row['code']}",
            [
                ("Data", row["plan_date"]),
                ("Dzień tygodnia", self.date_heading(str(row["plan_date"]))),
                ("Kierowca", row["driver_name"] or NO_DRIVER),
                ("Lp kierowcy", row["driver_lp"]),
                ("Para", row["pair_no"]),
                ("Służba", row["code"]),
                ("Nazwa służby", row["duty_name"]),
                ("Linia", row["line"]),
                ("Typ", row["duty_type"]),
                ("Zmiana", row["shift"]),
                ("Godzina rozpoczęcia", row["start_time"]),
                ("Godzina zakończenia", row["end_time"]),
                ("Czas pracy", row["work_range"]),
                ("rbh", row["work_hours"]),
                ("Przerwa od", row["break_start"]),
                ("Przerwa do", row["break_end"]),
                ("Przerwa", row["break_range"]),
                ("Przerwa [h]", row["break_duration"]),
                ("Uwagi", row["note"]),
            ],
        )

    def on_result_tree_double_click(self, event: tk.Event) -> None:
        iid = self.result_tree.identify_row(event.y) or self.result_tree.focus()
        column_id = self.result_tree.identify_column(event.x)
        if not iid or not column_id:
            return
        if iid:
            self.result_tree.selection_set(iid)
        # Kolumny opisowe oraz końcowe podsumowania pokazują szczegóły kierowcy; kolumny dN pokazują dni planu.
        try:
            display_index = int(column_id.replace("#", "")) - 1
        except ValueError:
            return
        cols = list(self.result_tree["columns"])
        if display_index < 0 or display_index >= len(cols):
            return
        col_name = cols[display_index]
        if not str(iid).startswith("driver-"):
            return
        driver_id = int(str(iid).split("-", 1)[1])
        if col_name in {"lp", "driver", "norma", "rbh"}:
            self.show_driver_details_by_id(driver_id)
            return
        if not col_name.startswith("d"):
            return
        try:
            date_index = int(col_name[1:])
        except ValueError:
            return
        date_range = self.validate_optional_date_range(self.result_start_var.get(), self.result_end_var.get())
        if date_range is None:
            return
        dates = self.each_date(*date_range)
        if date_index < 0 or date_index >= len(dates):
            return
        target_date = dates[date_index]
        plan_id = self.one_value(
            "SELECT id FROM planned_schedule WHERE plan_date=? AND driver_id=?",
            (target_date, driver_id),
            default="",
        )
        if plan_id:
            self.show_plan_entry_details_by_id(plan_id)
        else:
            name = self.one_value("SELECT name FROM drivers WHERE id=?", (driver_id,), default="")
            messagebox.showinfo("Info planu", f"Brak zaplanowanej służby dla kierowcy {name} w dniu {target_date}.")

    def show_driver_details_by_id(self, driver_id: int) -> None:
        row = self.conn.execute(
            """
            SELECT d.id, d.lp, d.name,
                   COUNT(p.id) AS planned_count
            FROM drivers d
            LEFT JOIN planned_schedule p ON p.driver_id = d.id
            WHERE d.id=?
            GROUP BY d.id
            """,
            (driver_id,),
        ).fetchone()
        if not row:
            return
        self.show_details_window(
            f"Kierowca: {row['name']}",
            [
                ("Lp", row["lp"]),
                ("Kierowca", row["name"]),
                ("Liczba wpisów w planach", row["planned_count"]),
            ],
        )

