    def save_compliance_settings(self) -> None:
        float_keys = [
            "max_daily_work_hours",
            "min_daily_rest_hours",
            "max_weekly_work_hours",
            "max_consecutive_work_days",
            "avg_weekly_work_hours",
            "min_weekly_rest_hours",
            "regular_weekly_rest_hours",
            "reduced_weekly_rest_hours",
        ]
        values: dict[str, str] = {}
        for key in float_keys:
            raw = str(self.compliance_vars[key].get()).strip().replace(",", ".")
            try:
                value = float(raw)
            except ValueError:
                messagebox.showerror("Błędne ustawienia", "Limity czasu pracy muszą być liczbami, np. 12 lub 11,5.")
                return
            if value <= 0:
                messagebox.showerror("Błędne ustawienia", "Limity czasu pracy muszą być większe od zera.")
                return
            values[key] = str(value).rstrip("0").rstrip(".") if "." in str(value) else str(value)

        values["check_weekly_rest"] = "1" if int(self.compliance_vars["check_weekly_rest"].get()) else "0"
        values["check_average_weekly"] = "1" if int(self.compliance_vars["check_average_weekly"].get()) else "0"
        values["check_regulation_561_weekly_rest"] = "1" if int(self.compliance_vars["check_regulation_561_weekly_rest"].get()) else "0"

        cur = self.conn.cursor()
        for key, value in values.items():
            cur.execute("INSERT OR REPLACE INTO compliance_settings(key, value) VALUES (?, ?)", (key, value))
        self.conn.commit()
        self.run_compliance_audit_for_result_range(show_message=False)
        messagebox.showinfo("Ustawienia", "Zapisano ustawienia kontroli czasu pracy.")

    def run_compliance_audit_for_result_range(self, show_message: bool = True) -> int:
        start = self.validate_date(self.result_start_var.get())
        end = self.validate_date(self.result_end_var.get())
        if not start or not end:
            if show_message:
                messagebox.showerror("Błędny zakres", "Podaj zakres dat w zakładce Gotowy plan.")
            return 0
        if start > end:
            if show_message:
                messagebox.showerror("Błędny zakres", "Data 'Od' nie może być późniejsza niż data 'Do'.")
            return 0
        count = self.audit_and_store(start, end)
        self.load_compliance_tree()
        self.load_result_plan_tree()
        if show_message:
            if count:
                messagebox.showwarning("Kontrola czasu", f"Wykryto {count} ostrzeżeń: {start} - {end}.")
            else:
                messagebox.showinfo("Kontrola czasu", f"Brak naruszeń: {start} - {end}.")
        return count

    def load_compliance_tree(self) -> None:
        if not hasattr(self, "compliance_tree"):
            return
        for item in self.compliance_tree.get_children():
            self.compliance_tree.delete(item)

        start = self.validate_date(self.result_start_var.get())
        end = self.validate_date(self.result_end_var.get())
        if not start or not end or start > end:
            self.compliance_summary_label.configure(text="Podaj poprawny zakres dat.")
            return

        rows = self.rows(
            """
            SELECT v.id, v.severity, v.plan_date, COALESCE(dr.name, '') AS driver_name, COALESCE(d.code, '') AS duty_code,
                   v.rule_code, v.message, v.details, COALESCE(v.suggestion, '') AS suggestion
            FROM compliance_violations v
            LEFT JOIN drivers dr ON dr.id = v.driver_id
            LEFT JOIN duties d ON d.id = v.duty_id
            WHERE v.scope_start=? AND v.scope_end=?
            ORDER BY CASE v.severity WHEN 'BŁĄD' THEN 0 WHEN 'OSTRZEŻENIE' THEN 1 ELSE 2 END,
                     dr.name, v.plan_date, v.rule_code
            """,
            (start, end),
        )
        for row in rows:
            tag = "error" if row["severity"] == "BŁĄD" else "warn"
            self.insert_tree_row(
                self.compliance_tree,
                str(row["id"]),
                (
                    row["severity"], row["plan_date"] or "", row["driver_name"], row["duty_code"],
                    row["rule_code"], row["message"], row["details"] or "", row["suggestion"] or "",
                ),
                extra_tags=(tag,),
            )
        self.compliance_summary_label.configure(text=f"{start} - {end}: {len(rows)} ostrzeżeń")

    def audit_and_store(self, start: str, end: str) -> int:
        violations = self.build_compliance_violations(start, end)
        cur = self.conn.cursor()
        cur.execute("DELETE FROM compliance_violations WHERE scope_start=? AND scope_end=?", (start, end))
        cur.executemany(
            """
            INSERT INTO compliance_violations(scope_start, scope_end, plan_date, driver_id, duty_id, severity, rule_code, message, details, suggestion)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            [
                (
                    start,
                    end,
                    v.get("plan_date"),
                    v.get("driver_id"),
                    v.get("duty_id"),
                    v["severity"],
                    v["rule_code"],
                    v["message"],
                    v.get("details", ""),
                    v.get("suggestion", ""),
                )
                for v in violations
            ],
        )
        self.conn.commit()
        return len(violations)

    def compliance_suggestion(self, rule_code: str) -> str:
        suggestions = {
            "DOBOWY_CZAS_PRACY": "Skróć lub zmień kierowcę.",
            "ODPOCZYNEK_DOBOWY": "Przesuń służbę lub zmień kierowcę.",
            "TYGODNIOWY_CZAS_PRACY": "Zdejmij lub skróć służbę.",
            "CIAG_DNI_PRACY": "Zmień obsadę albo zostaw dzień odpoczynku; W/WG/urlop są liczone jako odpoczynek.",
            "SREDNIA_TYGODNIOWA": "Dodaj wolne lub skróć służby.",
            "MIESIECZNA_NORMA_RBH": "Zdejmij lub skróć służbę.",
            "ODPOCZYNEK_TYGODNIOWY": "Sprawdź sąsiednie realne służby; W/WG/urlop są liczone jako odpoczynek.",
            "ODPOCZYNEK_TYGODNIOWY_561": "Sprawdź realne służby i rekompensatę; W/WG/urlop są liczone jako odpoczynek.",
            "PRACA_SOBOTA_NIEDZIELA": "Zmień niedzielną służbę.",
            "DWA_WEEKENDY_POD_RZAD": "Zamień weekend.",
            "SLUZBA_ZAKAZ_DLA_KIEROWCY": "Usuń zakaz lub zmień obsadę.",
        }
        return suggestions.get(rule_code, "Sprawdź sąsiednie dni.")

    def is_wg_duty(self, duty: sqlite3.Row | dict[str, object]) -> bool:
        """WG traktuj zawsze jako wolne grafikowe, czyli dzień wolny."""
        try:
            code = self.normalize_code(duty["code"])
        except Exception:
            code = ""
        if code in {"WG", "W"}:
            return True
        text_parts: list[str] = []
        for key in ("code", "name", "duty_type", "shift", "line"):
            try:
                text_parts.append(str(duty[key] or ""))
            except Exception:
                pass
        normalized = self.normalize_code(" ".join(text_parts))
        return "WOLNE GRAFIKOWE" in normalized

    def is_full_day_manual_special_duty(self, duty: sqlite3.Row | dict[str, object]) -> bool:
        """NAJEM/NAJEM2 traktuj jako całodniowy ręczny wpis bez godzin odpoczynku.

        Wpis blokuje całą komórkę kierowcy w danym dniu i może liczyć RBH, ale
        nie tworzy przedziału start-koniec do kontroli odpoczynku. Dzięki temu
        program nie dopisuje sztucznego WG przed NAJEM tylko dlatego, że w bazie
        NAJEM ma techniczne godziny.
        """
        try:
            code = self.normalize_code(duty["code"])
        except Exception:
            code = ""
        return code in FULL_DAY_MANUAL_SPECIAL_CODES

    def is_day_off_duty(self, duty: sqlite3.Row | dict[str, object]) -> bool:
        """Czy wpis ma być traktowany jako dzień wolny do odpoczynków.

        v259: UW ma być odpoczynkiem dla wszystkich kierowców niezależnie od
        opisu typu służby w bazie. RBH urlopu mogą nadal pomniejszać normę,
        ale UW nie tworzy realnego przedziału pracy do odpoczynków.
        """
        if self.is_rn_duty(duty):
            return False
        try:
            code = self.normalize_code(duty["code"])
        except Exception:
            code = ""
        if code in {"UW", "UO", "UB", "CH"} or self.is_vacation_duty_code(code):
            return True
        if self.is_wg_duty(duty):
            return True
        duty_type = ""
        try:
            duty_type = str(duty["duty_type"] or "").lower()
        except Exception:
            pass
        return "wolne" in duty_type or "nieobec" in duty_type

    def is_rest_relevant_duty(self, duty: sqlite3.Row | dict[str, object]) -> bool:
        """Czy wpis ma być traktowany jako realna praca do odpoczynków.

        RN/rezerwa nocna jest zawsze dniem pracy. Kody typu UW, UO, UB, CH,
        WG, W oraz inne wpisy o typie wolne/nieobecność mogą liczyć RBH, ale
        nie mają realnych godzin jazdy. Nie wolno więc wyliczać im sztucznego
        zakresu 00:00-08:00, bo potem odpoczynki i automatyczne planowanie
        mogą zostać błędnie zablokowane.
        """
        if self.is_rn_duty(duty):
            return True
        if self.is_full_day_manual_special_duty(duty):
            return False
        return not self.is_day_off_duty(duty)

    def is_vacation_duty_code(self, code: object) -> bool:
        return self.normalize_code(code) in {"UW", "UO", "CH"}

    def is_paid_rest_only_for_compliance(self, duty: sqlite3.Row | dict[str, object]) -> bool:
        """Płatna nieobecność liczona do RBH, ale nie do kontroli czasu pracy.

        UW ma naliczać 8 rbh w bilansie planu, natomiast przy kontroli odpoczynku,
        ciągu dni pracy, limitu tygodniowego, średniej i normy miesięcznej ma być
        traktowany jak WG, czyli dzień bez realnej pracy.
        """
        try:
            code = self.normalize_code(duty["code"])
        except Exception:
            code = ""
        return code == "UW"

    def is_manual_vacation_note_on_day_off(self, duty: sqlite3.Row | dict[str, object], note: object) -> bool:
        """Czy ręczne WG/W opisano jako urlop wypoczynkowy.

        v431: WG/W zwykle ma 0 RBH i nadal nie dobija godzin. Wyjątkiem jest
        starszy/ręczny wpis, w którym użytkownik zostawił kod WG/W, ale opis
        jednoznacznie mówi o urlopie wypoczynkowym. Taki wpis nie jest zamieniany
        na służbę i nie jest ruszany przez automat, ale w bilansie RBH ma działać
        jak UW, bo inaczej kierowca zostaje sztucznie poniżej nominału.
        """
        try:
            code = self.normalize_code(duty["code"])
        except Exception:
            code = ""
        if code not in {"WG", "W"}:
            return False
        note_norm = self.normalize_text(str(note or ""))
        return "urlop" in note_norm and "wypoczynk" in note_norm

    def planned_entry_rbh_hours(self, duty: sqlite3.Row | dict[str, object], plan_date: str | date, note: object = "") -> float:
        """RBH pojedynczego wpisu planu z poprawką dla ręcznego urlopu zapisanego jako WG/W."""
        try:
            day_obj = datetime.strptime(plan_date, "%Y-%m-%d").date() if isinstance(plan_date, str) else plan_date
        except Exception:
            day_obj = None
        if day_obj is not None and self.is_manual_vacation_note_on_day_off(duty, note):
            if self.is_calendar_workday_for_norm(day_obj):
                return 8.0
            return 0.0
        if not self.should_count_duty_rbh_on_date(duty, plan_date):
            return 0.0
        try:
            return self.parse_duration_hours(duty["work_hours"])
        except Exception:
            return 0.0

    def should_count_duty_rbh_on_date(self, duty: sqlite3.Row | dict[str, object], plan_date: str | date) -> bool:
        try:
            code = self.normalize_code(duty["code"])
        except Exception:
            code = ""
        # v429: WG/W/UB to dni wolne i nigdy nie dobijają RBH.
        # RBH może dobić tylko realna służba albo rezerwa R/R2.
        # UW/UO/CH pozostają obsługiwane niżej przez logikę urlopów/chorób.
        if code in {"WG", "W", "UB"}:
            return False
        if isinstance(plan_date, str):
            try:
                day_obj = datetime.strptime(plan_date, "%Y-%m-%d").date()
            except Exception:
                return True
        else:
            day_obj = plan_date
        # Urlopu i choroby CH nie liczymy w dni wolne: soboty, niedziele i święta. Dotyczy też starszych wpisów ręcznych,
        # jeżeli zostały kiedyś zapisane w dniu wolnym.
        if self.should_hide_vacation_on_date(duty, day_obj):
            return False
        return True

    def should_hide_vacation_on_date(self, duty: sqlite3.Row | dict[str, object], plan_date: str | date) -> bool:
        """Czy ukryć urlop w komórkach planu/drukach/eksportach.

        Urlop UW/UO oraz choroba CH zapisane w dni wolne nie powinien być ani liczony do RBH,
        ani pokazywany w planie. Dni wolne obejmują soboty, niedziele oraz święta
        traktowane w programie jak soboty.
        """
        try:
            code = duty["code"]
        except Exception:
            code = ""
        if not self.is_vacation_duty_code(code):
            return False
        if isinstance(plan_date, str):
            try:
                day_obj = datetime.strptime(plan_date, "%Y-%m-%d").date()
            except Exception:
                return False
        else:
            day_obj = plan_date
        return self.is_planning_weekend_or_holiday(day_obj)

    def wg_duty_ids(self) -> set[int]:
        result: set[int] = set()
        for row in self.rows("SELECT id, code, name, duty_type, shift, line FROM duties"):
            if self.is_wg_duty(row):
                result.add(int(row["id"]))
        return result

    def duty_id_by_code(self, code: str) -> int | None:
        wanted = self.normalize_code(code)
        for row in self.rows("SELECT id, code FROM duties"):
            if self.normalize_code(row["code"]) == wanted:
                return int(row["id"])
        return None

    def find_wg_swap_candidate(self, driver_id: int | None, plan_date: object, scope_start: str, scope_end: str) -> str:
        """Znajdź konkretne WG innego kierowcy jako propozycję zamiany dnia wolnego."""
        wg_ids = self.wg_duty_ids()
        if not wg_ids:
            return ""
        try:
            target_date = datetime.strptime(str(plan_date or scope_start), "%Y-%m-%d").date()
        except ValueError:
            target_date = datetime.strptime(scope_start, "%Y-%m-%d").date()
        scope_start_date = datetime.strptime(scope_start, "%Y-%m-%d").date()
        scope_end_date = datetime.strptime(scope_end, "%Y-%m-%d").date()
        search_start = max(scope_start_date, target_date - timedelta(days=7))
        search_end = min(scope_end_date, target_date + timedelta(days=7))
        rows = self.rows(
            """
            SELECT p.plan_date, p.driver_id, COALESCE(dr.name, '') AS driver_name, d.code
            FROM planned_schedule p
            JOIN duties d ON d.id = p.duty_id
            LEFT JOIN drivers dr ON dr.id = p.driver_id
            WHERE p.plan_date BETWEEN ? AND ?
              AND p.driver_id IS NOT NULL
              AND p.duty_id IN ({})
            """.format(",".join("?" for _ in wg_ids)),
            (search_start.isoformat(), search_end.isoformat(), *sorted(wg_ids)),
        )
        candidates = []
        for row in rows:
            candidate_driver_id = int(row["driver_id"])
            if driver_id is not None and candidate_driver_id == int(driver_id):
                continue
            try:
                candidate_date = datetime.strptime(str(row["plan_date"]), "%Y-%m-%d").date()
            except ValueError:
                continue
            distance = abs((candidate_date - target_date).days)
            same_day_bonus = 0 if candidate_date == target_date else 1
            candidates.append((same_day_bonus, distance, str(row["driver_name"] or f"kierowca {candidate_driver_id}"), candidate_date.isoformat()))
        if not candidates:
            return ""
        candidates.sort()
        _same, distance, driver_name, wg_date = candidates[0]
        if distance == 0:
            return f"{driver_name}: WG {wg_date}."
        return f"{driver_name}: WG blisko {wg_date}."

    def contextual_compliance_suggestion(self, violation: dict[str, object], scope_start: str, scope_end: str) -> str:
        base = self.compliance_suggestion(str(violation.get("rule_code", "")))
        driver_id_obj = violation.get("driver_id")
        try:
            driver_id = int(driver_id_obj) if driver_id_obj is not None else None
        except Exception:
            driver_id = None
        swap = self.find_wg_swap_candidate(driver_id, violation.get("plan_date"), scope_start, scope_end)
        if swap:
            return f"{base} WG: {swap}"
        return f"{base} Sprawdź WG ręcznie."

    def build_compliance_violations(self, start: str, end: str) -> list[dict[str, object]]:
        max_daily = self.compliance_float("max_daily_work_hours", 12.0)
        min_daily_rest = self.compliance_float("min_daily_rest_hours", 11.0)
        max_weekly = self.compliance_float("max_weekly_work_hours", 60.0)
        max_consecutive_work_days = max(1, int(round(self.compliance_float("max_consecutive_work_days", 6.0))))
        avg_weekly = self.compliance_float("avg_weekly_work_hours", 48.0)
        min_weekly_rest = self.compliance_float("min_weekly_rest_hours", 35.0)
        regular_weekly_rest = self.compliance_float("regular_weekly_rest_hours", 45.0)
        reduced_weekly_rest = self.compliance_float("reduced_weekly_rest_hours", 24.0)
        check_weekly_rest = self.compliance_bool("check_weekly_rest", True)
        check_regulation_561 = self.compliance_bool("check_regulation_561_weekly_rest", True)
        check_average = self.compliance_bool("check_average_weekly", True)

        rows = self.rows(
            """
            SELECT p.plan_date, p.driver_id, p.duty_id,
                   COALESCE(dr.name, '') AS driver_name,
                   d.code, d.name AS duty_name, d.duty_type, d.start_time, d.end_time, d.work_range,
                   d.total_time, d.work_hours, d.break_duration, d.break_range
            FROM planned_schedule p
            JOIN duties d ON d.id = p.duty_id
            LEFT JOIN drivers dr ON dr.id = p.driver_id
            WHERE p.plan_date BETWEEN ? AND ? AND p.driver_id IS NOT NULL
            ORDER BY p.driver_id, p.plan_date, d.start_time, d.code
            """,
            (start, end),
        )

        entries_by_driver: dict[int, list[dict[str, object]]] = defaultdict(list)
        rbh_entries_by_driver: dict[int, list[dict[str, object]]] = defaultdict(list)
        violations: list[dict[str, object]] = []

        for row in rows:
            active_work = self.is_rest_relevant_duty(row)
            if active_work:
                start_dt, end_dt = self.duty_datetimes(row["plan_date"], row["start_time"], row["end_time"], row["total_time"], row["work_range"])
                span_hours = max(0.0, (end_dt - start_dt).total_seconds() / 3600)
            else:
                try:
                    day_obj = datetime.strptime(str(row["plan_date"]), "%Y-%m-%d").date()
                except Exception:
                    day_obj = date.today()
                start_dt = datetime.combine(day_obj, datetime.min.time())
                end_dt = start_dt
                span_hours = 0.0
            work_hours = self.parse_duration_hours(row["work_hours"])
            break_hours = self.parse_duration_hours(row["break_duration"])
            duty_type = (row["duty_type"] or "").lower()
            entry = {
                "plan_date": row["plan_date"],
                "driver_id": int(row["driver_id"]),
                "duty_id": int(row["duty_id"]),
                "driver_name": row["driver_name"],
                "code": row["code"],
                "start_dt": start_dt,
                "end_dt": end_dt,
                "work_hours": work_hours,
                "break_hours": break_hours,
                "span_hours": span_hours,
                "active_work": active_work,
            }
            if active_work:
                entries_by_driver[int(row["driver_id"])].append(entry)
            # v306/v342: NAJEM/NAJEM2 liczy RBH jako całodniowy wpis ręczny, ale
            # nie wchodzi do listy godzinowych przedziałów odpoczynku. UW liczy 8 rbh
            # w bilansie planu, ale w kontroli czasu pracy ma być jak WG, więc nie
            # dokładamy go do godzin sprawdzanych limitami tygodnia/miesiąca/średniej.
            if (active_work or self.is_full_day_manual_special_duty(row)) and not self.is_paid_rest_only_for_compliance(row):
                rbh_entries_by_driver[int(row["driver_id"])].append(entry)

            if active_work and work_hours > max_daily + 1e-6:
                violations.append({
                    "severity": "BŁĄD",
                    "plan_date": row["plan_date"],
                    "driver_id": int(row["driver_id"]),
                    "duty_id": int(row["duty_id"]),
                    "rule_code": "DOBOWY_CZAS_PRACY",
                    "message": "Przekroczona doba.",
                    "details": f"{row['code']}: {self.format_hours(work_hours)}>{self.format_hours(max_daily)} h.",
                })

        for driver_id in sorted(set(entries_by_driver) | set(rbh_entries_by_driver)):
            entries = entries_by_driver.get(driver_id, [])
            entries.sort(key=lambda item: item["start_dt"])

            for prev, current in zip(entries, entries[1:]):
                rest_hours = max(0.0, (current["start_dt"] - prev["end_dt"]).total_seconds() / 3600)
                if rest_hours < min_daily_rest - 1e-6:
                    violations.append({
                        "severity": "BŁĄD",
                        "plan_date": current["plan_date"],
                        "driver_id": driver_id,
                        "duty_id": current["duty_id"],
                        "rule_code": "ODPOCZYNEK_DOBOWY",
                        "message": "Za krótki odpoczynek.",
                        "details": (
                            f"{prev['code']}→{current['code']}: {self.format_hours(rest_hours)}<{self.format_hours(min_daily_rest)} h."
                        ),
                    })

            work_dates = {entry["start_dt"].date() for entry in entries}
            if max_consecutive_work_days > 0 and work_dates:
                sorted_work_dates = sorted(work_dates)
                run_start = sorted_work_dates[0]
                prev_day = sorted_work_dates[0]
                for day_obj in sorted_work_dates[1:] + [None]:
                    if day_obj is not None and day_obj == prev_day + timedelta(days=1):
                        prev_day = day_obj
                        continue
                    run_len = (prev_day - run_start).days + 1
                    if run_len > max_consecutive_work_days:
                        violations.append({
                            "severity": "BŁĄD",
                            "plan_date": run_start.isoformat(),
                            "driver_id": driver_id,
                            "duty_id": None,
                            "rule_code": "CIAG_DNI_PRACY",
                            "message": "Za dużo dni pracy z rzędu.",
                            "details": f"{run_start.isoformat()} - {prev_day.isoformat()}: {run_len}>{max_consecutive_work_days} dni. RN liczony jako praca.",
                        })
                    if day_obj is not None:
                        run_start = prev_day = day_obj
            for entry in entries:
                entry_day = entry["start_dt"].date()
                if entry_day.weekday() == 6 and (entry_day - timedelta(days=1)) in work_dates:
                    violations.append({
                        "severity": "BŁĄD",
                        "plan_date": entry["plan_date"],
                        "driver_id": driver_id,
                        "duty_id": entry["duty_id"],
                        "rule_code": "PRACA_SOBOTA_NIEDZIELA",
                        "message": "Sobota + niedziela.",
                        "details": "Niedziela po sobocie.",
                    })

            weekend_starts = {self.weekend_start_for_calendar_date(day) for day in work_dates if day.weekday() in {5, 6}}
            for weekend_start in sorted(weekend_starts):
                if weekend_start - timedelta(days=7) in weekend_starts:
                    violations.append({
                        "severity": "OSTRZEŻENIE",
                        "plan_date": weekend_start.isoformat(),
                        "driver_id": driver_id,
                        "duty_id": None,
                        "rule_code": "DWA_WEEKENDY_POD_RZAD",
                        "message": "Dwa weekendy pod rząd.",
                        "details": f"Weekend {weekend_start.isoformat()}.",
                    })

            week_hours: dict[tuple[int, int], float] = defaultdict(float)
            for entry in rbh_entries_by_driver.get(driver_id, entries):
                iso = entry["start_dt"].date().isocalendar()
                week_hours[(iso.year, iso.week)] += float(entry["work_hours"])
            for (iso_year, iso_week), hours in week_hours.items():
                if hours > max_weekly + 1e-6:
                    monday = date.fromisocalendar(iso_year, iso_week, 1)
                    violations.append({
                        "severity": "BŁĄD",
                        "plan_date": monday.isoformat(),
                        "driver_id": driver_id,
                        "duty_id": None,
                        "rule_code": "TYGODNIOWY_CZAS_PRACY",
                        "message": "Przekroczony tydzień.",
                        "details": f"W{iso_week:02d}: {self.format_hours(hours)}>{self.format_hours(max_weekly)} h.",
                    })

            range_norm_hours = self.work_norm_hours_for_range(start, end)
            total_hours = sum(float(entry["work_hours"]) for entry in rbh_entries_by_driver.get(driver_id, entries))
            if total_hours > range_norm_hours + 1e-6:
                violations.append({
                    "severity": "BŁĄD",
                    "plan_date": start,
                    "driver_id": driver_id,
                    "duty_id": None,
                    "rule_code": "MIESIECZNA_NORMA_RBH",
                    "message": "Przekroczona norma rbh.",
                    "details": f"{self.format_hours(total_hours)}>{self.format_hours(range_norm_hours)} rbh.",
                })

            if check_average:
                start_date = datetime.strptime(start, "%Y-%m-%d").date()
                end_date = datetime.strptime(end, "%Y-%m-%d").date()
                days = (end_date - start_date).days + 1
                average = total_hours * 7.0 / max(days, 1)
                if average > avg_weekly + 1e-6:
                    violations.append({
                        "severity": "OSTRZEŻENIE",
                        "plan_date": start,
                        "driver_id": driver_id,
                        "duty_id": None,
                        "rule_code": "SREDNIA_TYGODNIOWA",
                        "message": "Przekroczona średnia tyg.",
                        "details": f"{self.format_hours(average)}>{self.format_hours(avg_weekly)} h/tydz.",
                    })

            if check_weekly_rest:
                violations.extend(self.weekly_rest_violations(driver_id, entries, start, end, min_weekly_rest, regular_weekly_rest, reduced_weekly_rest, check_regulation_561))

        for violation in violations:
            violation["suggestion"] = self.contextual_compliance_suggestion(violation, start, end)
        return violations

    def week_window_monday_sunday(self, day: date) -> tuple[datetime, datetime]:
        week_start = day - timedelta(days=day.weekday())
        return datetime.combine(week_start, datetime.min.time()), datetime.combine(week_start + timedelta(days=7), datetime.min.time())

    def max_rest_gap_in_window(
        self,
        intervals: list[tuple[datetime, datetime]],
        window_start: datetime,
        window_end: datetime,
    ) -> float:
        """Najdłuższy odpoczynek w oknie, liczony od końca służby.

        v253: odpoczynek tygodniowy i rekompensata 561 nie mogą zaczynać się
        sztucznie od granicy tygodnia, np. od poniedziałku 00:00, jeżeli nie
        wynika to z faktycznego zakończenia służby. Odpoczynek liczony jest od
        godziny zakończenia poprzedniej realnej służby do rozpoczęcia następnej
        służby albo do końca badanego okna. Dzięki temu służby kończące się po
        północy skracają odpoczynek poprawnie, a program nie zawyża odpoczynku
        samym początkiem tygodnia.
        """
        if window_end <= window_start:
            return 0.0

        cleaned: list[tuple[datetime, datetime]] = []
        for start_dt, end_dt in intervals:
            if start_dt is None or end_dt is None:
                continue
            if start_dt >= end_dt:
                continue
            # Zostawiamy również służby sąsiednie, bo odpoczynek w badanym
            # tygodniu może zaczynać się po służbie z poprzedniego dnia/tygodnia.
            if end_dt <= window_start - timedelta(days=14):
                continue
            if start_dt >= window_end + timedelta(days=14):
                continue
            cleaned.append((start_dt, end_dt))

        if not cleaned:
            return (window_end - window_start).total_seconds() / 3600

        cleaned.sort()
        merged: list[tuple[datetime, datetime]] = []
        for start_dt, end_dt in cleaned:
            if not merged or start_dt > merged[-1][1]:
                merged.append((start_dt, end_dt))
            elif end_dt > merged[-1][1]:
                merged[-1] = (merged[-1][0], end_dt)

        max_gap = 0.0
        previous: tuple[datetime, datetime] | None = None

        for interval_start, interval_end in merged:
            if interval_end <= window_start:
                previous = (interval_start, interval_end)
                continue

            if interval_start >= window_end:
                if previous is not None:
                    gap_start = previous[1]
                    gap_end = interval_start
                    if gap_end > gap_start and gap_end > window_start and gap_start < window_end:
                        max_gap = max(max_gap, (gap_end - gap_start).total_seconds() / 3600)
                break

            if previous is not None:
                gap_start = previous[1]
                gap_end = interval_start
                if gap_end > gap_start and gap_end > window_start and gap_start < window_end:
                    max_gap = max(max_gap, (gap_end - gap_start).total_seconds() / 3600)

            previous = (interval_start, interval_end)

        if previous is not None and previous[1] < window_end:
            max_gap = max(max_gap, (window_end - previous[1]).total_seconds() / 3600)

        return max_gap

    def rest_gaps_in_window(
        self,
        intervals: list[tuple[datetime, datetime]],
        window_start: datetime,
        window_end: datetime,
    ) -> list[tuple[datetime, datetime, float]]:
        """Zwróć rzeczywiste przerwy między służbami w oknie tygodnia.

        Używane przy 561 w v304: rekompensaty za skrócony odpoczynek nie
        wolno doliczać do tego samego ciągłego odpoczynku tygodniowego.
        Rekompensata musi być oddana jako osobny dzień/gap odpoczynku, czyli
        poza głównym regularnym odpoczynkiem tygodniowym.
        """
        if window_end <= window_start:
            return []

        cleaned: list[tuple[datetime, datetime]] = []
        for start_dt, end_dt in intervals:
            if start_dt is None or end_dt is None:
                continue
            if start_dt >= end_dt:
                continue
            if end_dt <= window_start - timedelta(days=14):
                continue
            if start_dt >= window_end + timedelta(days=14):
                continue
            cleaned.append((start_dt, end_dt))

        if not cleaned:
            hours = (window_end - window_start).total_seconds() / 3600
            return [(window_start, window_end, hours)]

        cleaned.sort()
        merged: list[tuple[datetime, datetime]] = []
        for start_dt, end_dt in cleaned:
            if not merged or start_dt > merged[-1][1]:
                merged.append((start_dt, end_dt))
            elif end_dt > merged[-1][1]:
                merged[-1] = (merged[-1][0], end_dt)

        gaps: list[tuple[datetime, datetime, float]] = []
        previous: tuple[datetime, datetime] | None = None
        for interval_start, interval_end in merged:
            if interval_end <= window_start:
                previous = (interval_start, interval_end)
                continue

            if interval_start >= window_end:
                if previous is not None:
                    gap_start = previous[1]
                    gap_end = interval_start
                    if gap_end > gap_start and gap_end > window_start and gap_start < window_end:
                        gaps.append((gap_start, gap_end, (gap_end - gap_start).total_seconds() / 3600))
                break

            if previous is not None:
                gap_start = previous[1]
                gap_end = interval_start
                if gap_end > gap_start and gap_end > window_start and gap_start < window_end:
                    gaps.append((gap_start, gap_end, (gap_end - gap_start).total_seconds() / 3600))

            previous = (interval_start, interval_end)

        if previous is not None and previous[1] < window_end:
            gap_start = previous[1]
            gap_end = window_end
            gaps.append((gap_start, gap_end, (gap_end - gap_start).total_seconds() / 3600))

        return gaps

    def has_regular_weekly_rest_and_separate_compensation(
        self,
        intervals: list[tuple[datetime, datetime]],
        window_start: datetime,
        window_end: datetime,
        regular_weekly_rest: float,
        compensation_hours: float,
    ) -> bool:
        """Czy tydzień ma 45 h odpoczynku oraz osobny gap rekompensaty 561.

        v304: rekompensata za skrócony odpoczynek nie może być kumulowana w
        tym samym ciągłym odpoczynku tygodniowym, np. jako 45+21 h. Musi być
        oddana poza głównym regularnym odpoczynkiem, czyli w innym dniu/gapie.
        """
        if compensation_hours <= 1e-6:
            return True
        gaps = self.rest_gaps_in_window(intervals, window_start, window_end)
        regular_gaps = [gap for gap in gaps if gap[2] >= regular_weekly_rest - 1e-6]
        if not regular_gaps:
            return False
        weekly_gap = max(regular_gaps, key=lambda gap: gap[2])
        weekly_start, weekly_end, _weekly_hours = weekly_gap
        for gap_start, gap_end, gap_hours in gaps:
            if gap_hours < compensation_hours - 1e-6:
                continue
            # Rekompensata musi być poza głównym ciągłym odpoczynkiem tygodniowym.
            if gap_end <= weekly_start or gap_start >= weekly_end:
                return True
        return False

    def has_vacation_rest_day_for_driver_between(self, driver_id: int, start_day: date, end_day: date) -> bool:
        """Czy kierowca ma urlop UW/UO w podanym zakresie dat.

        Urlop traktujemy jak dzień wolny/odpoczynek, więc sam fakt urlopu
        nie może powodować naliczania dodatkowej rekompensaty 561 po urlopie.
        Zakres jest półotwarty: start_day <= data < end_day.
        """
        try:
            driver_id_int = int(driver_id)
        except Exception:
            return False
        if end_day <= start_day:
            return False
        try:
            rows = self.rows(
                """
                SELECT 1
                FROM planned_schedule p
                JOIN duties d ON d.id = p.duty_id
                WHERE p.driver_id=?
                  AND p.plan_date>=?
                  AND p.plan_date<?
                  AND UPPER(COALESCE(d.code, '')) IN ('UW', 'UO')
                LIMIT 1
                """,
                (driver_id_int, start_day.isoformat(), end_day.isoformat()),
            )
        except Exception:
            return False
        return bool(rows)

    def weekly_rest_violations(
        self,
        driver_id: int,
        entries: list[dict[str, object]],
        start: str,
        end: str,
        min_weekly_rest: float,
        regular_weekly_rest: float,
        reduced_weekly_rest: float,
        check_regulation_561: bool,
    ) -> list[dict[str, object]]:
        if not entries:
            return []
        start_date = datetime.strptime(start, "%Y-%m-%d").date()
        end_date = datetime.strptime(end, "%Y-%m-%d").date()
        first_monday = start_date - timedelta(days=start_date.weekday())
        last_monday = end_date - timedelta(days=end_date.weekday())
        result: list[dict[str, object]] = []
        intervals = [(entry["start_dt"], entry["end_dt"]) for entry in entries]
        week_gaps: list[tuple[date, float]] = []

        week_start = first_monday
        while week_start <= last_monday:
            week_end = week_start + timedelta(days=7)
            full_week_in_range = week_start >= start_date and week_end <= (end_date + timedelta(days=1))
            if not full_week_in_range:
                week_start += timedelta(days=7)
                continue

            week_start_dt = datetime.combine(week_start, datetime.min.time())
            week_end_dt = datetime.combine(week_end, datetime.min.time())
            max_gap = self.max_rest_gap_in_window(intervals, week_start_dt, week_end_dt)
            week_gaps.append((week_start, max_gap))
            week_start += timedelta(days=7)

        for index, (week_start, max_gap) in enumerate(week_gaps):
            iso = week_start.isocalendar()
            week_end = week_start + timedelta(days=7)
            week_label = f"W{iso.week:02d} ({week_start.isoformat()} - {(week_end - timedelta(days=1)).isoformat()})"
            week_has_vacation_rest = self.has_vacation_rest_day_for_driver_between(driver_id, week_start, week_end)
            next_week_has_vacation_rest = self.has_vacation_rest_day_for_driver_between(driver_id, week_end, week_end + timedelta(days=7))
            # v353: UO/UW jest dniem wolnym/odpoczynkiem. Jeżeli w tygodniu jest urlop,
            # nie wyliczamy dla tego tygodnia odpoczynku tygodniowego ani układu 561.
            if week_has_vacation_rest:
                continue
            if max_gap < min_weekly_rest - 1e-6:
                result.append({
                    "severity": "BŁĄD",
                    "plan_date": week_start.isoformat(),
                    "driver_id": driver_id,
                    "duty_id": None,
                    "rule_code": "ODPOCZYNEK_TYGODNIOWY",
                    "message": "Brak odp. tyg.",
                    "details": f"{week_label}: {self.format_hours(max_gap)}<{self.format_hours(min_weekly_rest)} h.",
                })
            elif check_regulation_561 and max_gap < regular_weekly_rest - 1e-6 and not next_week_has_vacation_rest:
                deficit = max(0.0, regular_weekly_rest - max_gap)
                next_gap = None
                if index + 1 < len(week_gaps) and week_gaps[index + 1][0] == week_start + timedelta(days=7):
                    next_gap = week_gaps[index + 1][1]
                compensated_next_week = False
                if next_gap is not None and next_gap >= regular_weekly_rest - 1e-6:
                    next_week_start_dt = datetime.combine(week_start + timedelta(days=7), datetime.min.time())
                    next_week_end_dt = next_week_start_dt + timedelta(days=7)
                    compensated_next_week = self.has_regular_weekly_rest_and_separate_compensation(
                        intervals,
                        next_week_start_dt,
                        next_week_end_dt,
                        regular_weekly_rest,
                        deficit,
                    )
                if not compensated_next_week:
                    result.append({
                        "severity": "OSTRZEŻENIE",
                        "plan_date": week_start.isoformat(),
                        "driver_id": driver_id,
                        "duty_id": None,
                        "rule_code": "ODPOCZYNEK_TYGODNIOWY_SKROCONY",
                        "message": "Skrócony odp. tyg.",
                        "details": (
                            f"{week_label}: {self.format_hours(max_gap)} h; brak osobnego dnia/gapu rekompensaty {self.format_hours(deficit)} h w kolejnym tygodniu."
                        ),
                    })

            if check_regulation_561 and max_gap < reduced_weekly_rest - 1e-6:
                result.append({
                    "severity": "BŁĄD",
                    "plan_date": week_start.isoformat(),
                    "driver_id": driver_id,
                    "duty_id": None,
                    "rule_code": "ODPOCZYNEK_TYGODNIOWY_561",
                    "message": "Za krótki odp. tyg.",
                    "details": f"{week_label}: {self.format_hours(max_gap)}<{self.format_hours(reduced_weekly_rest)} h.",
                })

        if check_regulation_561:
            for (week_a, gap_a), (week_b, gap_b) in zip(week_gaps, week_gaps[1:]):
                has_regular = gap_a >= regular_weekly_rest - 1e-6 or gap_b >= regular_weekly_rest - 1e-6
                both_at_least_reduced = gap_a >= reduced_weekly_rest - 1e-6 and gap_b >= reduced_weekly_rest - 1e-6
                if self.has_vacation_rest_day_for_driver_between(driver_id, week_a, week_a + timedelta(days=7)) or self.has_vacation_rest_day_for_driver_between(driver_id, week_b, week_b + timedelta(days=7)):
                    continue
                if not (has_regular and both_at_least_reduced):
                    result.append({
                        "severity": "BŁĄD",
                        "plan_date": week_b.isoformat(),
                        "driver_id": driver_id,
                        "duty_id": None,
                        "rule_code": "ODPOCZYNEK_TYGODNIOWY_561",
                        "message": "Błędny układ 2 tyg.",
                        "details": (
                            f"{week_a.isoformat()} - {(week_a + timedelta(days=6)).isoformat()} / {week_b.isoformat()} - {(week_b + timedelta(days=6)).isoformat()}: {self.format_hours(gap_a)}/{self.format_hours(gap_b)} h."
                        ),
                    })
        return result

    def parse_clock(self, value: object) -> tuple[int, int] | None:
        text = "" if value is None else str(value).strip()
        if not text:
            return None
        parts = text.replace(".", ":").split(":")
        if len(parts) < 2:
            return None
        hour_text = parts[0].strip()
        minute_text = parts[1].strip()
        try:
            hour = int(hour_text)
            # v172: zapis typu 3:3 oznacza 03:30, nie 03:03.
            # Jeżeli użytkownik chce trzy minuty po trzeciej, powinien wpisać 3:03.
            minute = int(minute_text) * 10 if len(minute_text) == 1 else int(minute_text[:2])
        except ValueError:
            return None
        if not (0 <= hour <= 23 and 0 <= minute <= 59):
            return None
        return hour, minute

    def format_clock_tuple(self, clock: tuple[int, int] | None) -> str:
        if not clock:
            return ""
        return f"{int(clock[0]):02d}:{int(clock[1]):02d}"

    def normalize_clock_text(self, value: object) -> str:
        clock = self.parse_clock(value)
        return self.format_clock_tuple(clock) if clock else ("" if value is None else str(value).strip())

    def parse_clock_range(self, *values: object) -> tuple[tuple[int, int], tuple[int, int]] | None:
        """Wyciagnij zakres godzin z tekstu typu 04:55-14:55 albo 04.55 do 14.55.

        Uzywane przy kontroli odpoczynkow, aby koniec poprzedniej sluzby
        byl liczony z realnej godziny zakonczenia sluzby, a nie z 00:00.
        Od v172 akceptuje tez zapis z jedna cyfra minut, np. 3:3 = 03:30.
        """
        for value in values:
            text = "" if value is None else str(value).strip()
            if not text:
                continue
            text = (
                text.replace("\u2013", "-")
                    .replace("\u2014", "-")
                    .replace("\u2212", "-")
                    .replace(" do ", "-")
                    .replace("DO", "-")
                    .replace("Do", "-")
            )
            matches = re.findall(r"(?<!\d)([0-2]?\d)[\.:]([0-5]\d?)(?!\d)", text)
            clocks: list[tuple[int, int]] = []
            for hour_text, minute_text in matches:
                clock = self.parse_clock(f"{hour_text}:{minute_text}")
                if clock:
                    clocks.append(clock)
            if len(clocks) >= 2:
                return clocks[0], clocks[1]
        return None

    def normalize_clock_range_text(self, value: object) -> str:
        text = "" if value is None else str(value).strip()
        if not text:
            return ""
        parsed = self.parse_clock_range(text)
        if not parsed:
            return text
        return f"{self.format_clock_tuple(parsed[0])}-{self.format_clock_tuple(parsed[1])}"

    def normalize_existing_duty_clock_values(self) -> None:
        try:
            rows = self.rows("SELECT id, start_time, end_time, work_range FROM duties")
        except Exception:
            return
        for row in rows:
            start_time = self.normalize_clock_text(row["start_time"])
            end_time = self.normalize_clock_text(row["end_time"])
            work_range = self.normalize_clock_range_text(row["work_range"])
            if start_time != (row["start_time"] or "") or end_time != (row["end_time"] or "") or work_range != (row["work_range"] or ""):
                self.conn.execute(
                    "UPDATE duties SET start_time=?, end_time=?, work_range=? WHERE id=?",
                    (start_time, end_time, work_range, int(row["id"])),
                )


    def parse_duration_hours(self, value: object) -> float:
        text = "" if value is None else str(value).strip().replace(",", ".")
        if not text:
            return 0.0
        if ":" in text:
            parts = text.split(":")
            try:
                minute_text = parts[1].strip()
                minutes = int(minute_text) * 10 if len(minute_text) == 1 else int(minute_text[:2])
                return int(parts[0]) + minutes / 60.0
            except (ValueError, IndexError):
                return 0.0
        if "." in text:
            whole, frac = text.split(".", 1)
            try:
                hours = int(whole or "0")
                minutes = int((frac + "0")[:2])
            except ValueError:
                return 0.0
            if 0 <= minutes <= 59:
                return hours + minutes / 60.0
            try:
                return float(text)
            except ValueError:
                return 0.0
        try:
            return float(text)
        except ValueError:
            return 0.0

    def duty_datetimes(
        self,
        plan_date: str,
        start_time: object,
        end_time: object,
        total_time: object,
        work_range: object = None,
    ) -> tuple[datetime, datetime]:
        """Zwróć realny przedział służby używany do odpoczynków.

        v305: odpoczynki mają wynikać z godzin zapisanych przy służbie.
        Priorytet odczytu:
        1) pełny zakres `work_range`, np. 04:35-15:25,
        2) pola start_time/end_time,
        3) start_time + total_time,
        4) awaryjnie 00:00 + 8 h.
        Jeżeli koniec jest wcześniejszy albo równy początkowi, służba kończy
        się po północy następnego dnia.
        """
        day = datetime.strptime(plan_date, "%Y-%m-%d").date()

        range_clock = self.parse_clock_range(work_range)
        if range_clock:
            start_clock, end_clock = range_clock
        else:
            start_clock = self.parse_clock(start_time)
            end_clock = self.parse_clock(end_time)

        if start_clock:
            start_dt = datetime.combine(day, datetime.min.time()).replace(hour=start_clock[0], minute=start_clock[1])
        else:
            start_dt = datetime.combine(day, datetime.min.time())

        if end_clock:
            end_dt = datetime.combine(day, datetime.min.time()).replace(hour=end_clock[0], minute=end_clock[1])
            if end_dt <= start_dt:
                end_dt += timedelta(days=1)
        else:
            duration = self.parse_duration_hours(total_time)
            end_dt = start_dt + timedelta(hours=duration if duration > 0 else 8)
        return start_dt, end_dt

    def format_hours(self, hours: float) -> str:
        rounded = round(float(hours) + 1e-9, 2)
        if abs(rounded - round(rounded)) < 1e-6:
            return str(int(round(rounded)))
        return f"{rounded:.2f}".replace(".", ",")



    # ---------- duty checkbox actions ----------
    def selected_duty_ids_from_tree(self) -> list[int]:
        selection = self.duties_tree.selection()
        ids: list[int] = []
        for iid in selection:
            duty_id = self.duty_tree_ids.get(iid)
            if duty_id is not None:
                ids.append(duty_id)
        return ids

    def selected_duty_id_from_tree(self) -> int | None:
        ids = self.selected_duty_ids_from_tree()
        return ids[0] if ids else None

    def on_duty_tree_click(self, event: tk.Event) -> str | None:
        region = self.duties_tree.identify("region", event.x, event.y)
        column = self.duties_tree.identify_column(event.x)
        iid = self.duties_tree.identify_row(event.y)
        if region == "cell" and iid:
            current_selection = set(self.duties_tree.selection())
            if iid not in current_selection:
                self.duties_tree.selection_set(iid)
            if column == "#1":
                self.after(1, self.toggle_selected_duties_month_exclusion)
                return "break"
            if column == "#2":
                self.after(1, self.toggle_selected_duty_auto_plan_enabled)
                return "break"
            if column in {"#3", "#4", "#5"}:
                column_map = {"#3": "can_plan_weekdays", "#4": "can_plan_saturday", "#5": "can_plan_sunday"}
                self.after(1, lambda c=column_map[column]: self.toggle_selected_duty_day_flag(c))
                return "break"
        return None

    def toggle_selected_duty_auto_plan_enabled(self) -> None:
        duty_ids = self.selected_duty_ids_from_tree()
        if not duty_ids:
            return
        rows = self.rows(f"SELECT id, COALESCE(auto_plan_enabled, 1) AS flag FROM duties WHERE id IN ({','.join('?' for _ in duty_ids)})", tuple(duty_ids))
        current = {int(row["id"]): int(row["flag"] or 0) for row in rows}
        cur = self.conn.cursor()
        for duty_id in duty_ids:
            new_value = 0 if current.get(int(duty_id), 1) else 1
            cur.execute("UPDATE duties SET auto_plan_enabled=? WHERE id=?", (new_value, int(duty_id)))
            if new_value:
                cur.execute("DELETE FROM excluded_duties WHERE duty_id=?", (int(duty_id),))
            else:
                cur.execute("INSERT OR IGNORE INTO excluded_duties(duty_id) VALUES (?)", (int(duty_id),))
        self.conn.commit()
        self.load_reference_data(update_month=False)
        self.refresh_all()
        self.auto_status_label.configure(text=f"Zmieniono tryb automatu dla {len(duty_ids)} służb.")

    def toggle_selected_duty_day_flag(self, column_name: str) -> None:
        if column_name not in {"can_plan_weekdays", "can_plan_saturday", "can_plan_sunday"}:
            return
        duty_ids = self.selected_duty_ids_from_tree()
        if not duty_ids:
            return
        rows = self.rows(f"SELECT id, COALESCE({column_name}, 1) AS flag FROM duties WHERE id IN ({','.join('?' for _ in duty_ids)})", tuple(duty_ids))
        current = {int(row["id"]): int(row["flag"] or 0) for row in rows}
        cur = self.conn.cursor()
        for duty_id in duty_ids:
            new_value = 0 if current.get(int(duty_id), 1) else 1
            cur.execute(f"UPDATE duties SET {column_name}=? WHERE id=?", (new_value, int(duty_id)))
        self.conn.commit()
        self.load_reference_data(update_month=False)
        self.refresh_all()
        names = {"can_plan_weekdays": "pn.-pt.", "can_plan_saturday": "soboty", "can_plan_sunday": "niedziele"}
        self.auto_status_label.configure(text=f"Zmieniono planowanie w dni: {names[column_name]} dla {len(duty_ids)} służb.")

    def suggest_duty_day_flags_from_form(self) -> None:
        duty = {
            "code": self.duty_db_code_var.get(),
            "name": self.duty_db_name_var.get(),
            "duty_type": self.duty_db_type_var.get(),
            "shift": self.duty_db_shift_var.get(),
            "line": self.duty_db_line_var.get(),
        }
        weekdays, saturday, sunday, reason = self.suggest_day_flags_for_duty(duty)
        self.duty_db_weekdays_var.set(weekdays)
        self.duty_db_saturday_var.set(saturday)
        self.duty_db_sunday_var.set(sunday)
        self.auto_status_label.configure(text=f"Zasugerowano dni planowania służby: {reason}.")

    def clear_duty_form(self) -> None:
        self.duty_db_selected_id = None
        for variable in (
            self.duty_db_code_var, self.duty_db_name_var, self.duty_db_line_var, self.duty_db_type_var,
            self.duty_db_shift_var, self.duty_db_start_var, self.duty_db_end_var, self.duty_db_work_range_var,
            self.duty_db_work_hours_var, self.duty_db_break_start_var, self.duty_db_break_end_var,
            self.duty_db_break_range_var, self.duty_db_break_duration_var,
        ):
            variable.set("")
        if hasattr(self, "duty_db_assigned_car_var"):
            self.duty_db_assigned_car_var.set("(bez auta)")
        if hasattr(self, "duty_db_vehicle_type_var"):
            self.duty_db_vehicle_type_var.set("")
        self.duty_db_auto_plan_var.set(1)
        self.duty_db_weekdays_var.set(1)
        self.duty_db_saturday_var.set(1)
        self.duty_db_sunday_var.set(1)
        if hasattr(self, "duties_tree"):
            self.duties_tree.selection_remove(self.duties_tree.selection())

    def on_duties_tree_select(self, _event: tk.Event | None = None) -> None:
        # Pojedyncze zaznaczenie służby od razu wypełnia formularz edycji.
        # Dwuklik pozostaje zarezerwowany do okna pełnego opisu.
        self.copy_selected_duty_to_driver_exclusion_combo(show_message=False)
        self.load_duty_record_to_form(show_message=False)

    def load_duty_record_to_form(self, show_message: bool = True) -> None:
        duty_id = self.selected_duty_id_from_tree()
        if duty_id is None:
            if show_message:
                messagebox.showinfo("Baza służb", "Zaznacz służbę.")
            return
        rows = self.rows(
            """
            SELECT id, code, name, duty_type, shift, line, start_time, end_time, work_range, total_time,
                   work_hours, break_start, break_end, break_range, break_duration,
                   COALESCE(assigned_car_id, 0) AS assigned_car_id,
                   COALESCE(assigned_vehicle_type, '') AS assigned_vehicle_type,
                   COALESCE(auto_plan_enabled, 1) AS auto_plan_enabled,
                   COALESCE(can_plan_weekdays, 1) AS can_plan_weekdays,
                   COALESCE(can_plan_saturday, 1) AS can_plan_saturday,
                   COALESCE(can_plan_sunday, 1) AS can_plan_sunday
            FROM duties WHERE id=?
            """,
            (duty_id,),
        )
        if not rows:
            return
        row = rows[0]
        self.duty_db_selected_id = int(row["id"])
        self.duty_db_code_var.set(row["code"] or "")
        self.duty_db_name_var.set(row["name"] or "")
        self.duty_db_line_var.set(row["line"] or "")
        self.duty_db_type_var.set(row["duty_type"] or "")
        self.duty_db_shift_var.set(row["shift"] or "")
        self.duty_db_start_var.set(row["start_time"] or "")
        self.duty_db_end_var.set(row["end_time"] or "")
        self.duty_db_work_range_var.set(row["work_range"] or "")
        self.duty_db_work_hours_var.set(row["work_hours"] or "")
        self.duty_db_break_start_var.set(row["break_start"] or "")
        self.duty_db_break_end_var.set(row["break_end"] or "")
        self.duty_db_break_range_var.set(row["break_range"] or "")
        self.duty_db_break_duration_var.set(row["break_duration"] or "")
        if hasattr(self, "duty_db_assigned_car_var"):
            assigned_car_id = int(row["assigned_car_id"] or 0)
            assigned_label = "(bez auta)"
            for label, known_id in getattr(self, "car_label_to_id", {"(bez auta)": None}).items():
                if known_id is not None and int(known_id) == assigned_car_id:
                    assigned_label = label
                    break
            self.duty_db_assigned_car_var.set(assigned_label)
        if hasattr(self, "duty_db_vehicle_type_var"):
            self.duty_db_vehicle_type_var.set(self.normalize_vehicle_type_label(row["assigned_vehicle_type"] or ""))
        self.duty_db_auto_plan_var.set(1 if int(row["auto_plan_enabled"] or 0) else 0)
        self.duty_db_weekdays_var.set(1 if int(row["can_plan_weekdays"] or 0) else 0)
        self.duty_db_saturday_var.set(1 if int(row["can_plan_saturday"] or 0) else 0)
        self.duty_db_sunday_var.set(1 if int(row["can_plan_sunday"] or 0) else 0)

    def save_duty_record(self) -> None:
        code = self.duty_db_code_var.get().strip()
        if not code:
            messagebox.showerror("Baza służb", "Podaj kod / numer służby.")
            return
        values = {
            "code": code,
            "name": self.duty_db_name_var.get().strip(),
            "line": self.duty_db_line_var.get().strip(),
            "duty_type": self.duty_db_type_var.get().strip(),
            "shift": self.duty_db_shift_var.get().strip(),
            "start_time": self.duty_db_start_var.get().strip(),
            "end_time": self.duty_db_end_var.get().strip(),
            "work_range": self.duty_db_work_range_var.get().strip(),
            "work_hours": self.duty_db_work_hours_var.get().strip(),
            "break_start": self.duty_db_break_start_var.get().strip(),
            "break_end": self.duty_db_break_end_var.get().strip(),
            "break_range": self.duty_db_break_range_var.get().strip(),
            "break_duration": self.duty_db_break_duration_var.get().strip(),
            "assigned_car_id": self.car_label_to_id.get(self.duty_db_assigned_car_var.get()) if hasattr(self, "duty_db_assigned_car_var") else None,
            "assigned_vehicle_type": self.normalize_vehicle_type_label(self.duty_db_vehicle_type_var.get()) if hasattr(self, "duty_db_vehicle_type_var") else "",
            "auto_plan_enabled": 1 if int(self.duty_db_auto_plan_var.get()) else 0,
            "can_plan_weekdays": 1 if int(self.duty_db_weekdays_var.get()) else 0,
            "can_plan_saturday": 1 if int(self.duty_db_saturday_var.get()) else 0,
            "can_plan_sunday": 1 if int(self.duty_db_sunday_var.get()) else 0,
        }
        try:
            if self.duty_db_selected_id:
                self.conn.execute(
                    """
                    UPDATE duties
                    SET code=:code, name=:name, line=:line, duty_type=:duty_type, shift=:shift,
                        start_time=:start_time, end_time=:end_time, work_range=:work_range, work_hours=:work_hours,
                        break_start=:break_start, break_end=:break_end, break_range=:break_range, break_duration=:break_duration,
                        assigned_car_id=:assigned_car_id, assigned_vehicle_type=:assigned_vehicle_type,
                        auto_plan_enabled=:auto_plan_enabled,
                        can_plan_weekdays=:can_plan_weekdays, can_plan_saturday=:can_plan_saturday, can_plan_sunday=:can_plan_sunday
                    WHERE id=:id
                    """,
                    {**values, "id": int(self.duty_db_selected_id)},
                )
                action = "Zmieniono służbę."
            else:
                self.conn.execute(
                    """
                    INSERT INTO duties(code, name, line, duty_type, shift, start_time, end_time, work_range, work_hours,
                                       break_start, break_end, break_range, break_duration, assigned_car_id, assigned_vehicle_type,
                                       auto_plan_enabled, can_plan_weekdays, can_plan_saturday, can_plan_sunday, occurrences, source_sheet)
                    VALUES (:code, :name, :line, :duty_type, :shift, :start_time, :end_time, :work_range, :work_hours,
                            :break_start, :break_end, :break_range, :break_duration, :assigned_car_id, :assigned_vehicle_type,
                            :auto_plan_enabled, :can_plan_weekdays, :can_plan_saturday, :can_plan_sunday, 0, 'użytkownik')
                    """,
                    values,
                )
                action = "Dodano służbę."
            saved_id = int(self.duty_db_selected_id or self.one_value("SELECT id FROM duties WHERE code=?", (code,), default="0") or 0)
            if values.get("assigned_vehicle_type"):
                self.remember_vehicle_type_category(values["assigned_vehicle_type"])
            if saved_id:
                if values["auto_plan_enabled"]:
                    self.conn.execute("DELETE FROM excluded_duties WHERE duty_id=?", (saved_id,))
                else:
                    self.conn.execute("INSERT OR IGNORE INTO excluded_duties(duty_id) VALUES (?)", (saved_id,))
            self.conn.commit()
        except sqlite3.IntegrityError as exc:
            messagebox.showerror("Baza służb", f"Nie można zapisać służby. Kod musi być unikalny.\n\n{exc}")
            return
        self.load_reference_data(update_month=False)
        self.refresh_all()
        self.auto_status_label.configure(text=action)
        if not self.duty_db_selected_id:
            self.clear_duty_form()

    def delete_selected_duty_record(self) -> None:
        duty_id = self.duty_db_selected_id or self.selected_duty_id_from_tree()
        if duty_id is None:
            messagebox.showinfo("Baza służb", "Zaznacz służbę do usunięcia.")
            return
        rows = self.rows("SELECT code, name FROM duties WHERE id=?", (duty_id,))
        if not rows:
            return
        row = rows[0]
        code = row["code"] or ""
        used_plan = int(self.one_value("SELECT COUNT(*) FROM planned_schedule WHERE duty_id=?", (duty_id,), default="0"))
        used_pattern = int(self.one_value("SELECT COUNT(*) FROM original_schedule WHERE duty_id=?", (duty_id,), default="0"))
        if not messagebox.askyesno(
            "Usuń służbę",
            f"Usunąć służbę {code}?\n\nZostaną usunięte jej wpisy planu, wykluczenia i stałe przypisania. Wpisy planu: {used_plan}. Wpisy wzoru: {used_pattern}.",
        ):
            return
        cur = self.conn.cursor()
        cur.execute("DELETE FROM planned_schedule WHERE duty_id=?", (duty_id,))
        cur.execute("DELETE FROM original_schedule WHERE duty_id=?", (duty_id,))
        cur.execute("DELETE FROM compliance_violations WHERE duty_id=?", (duty_id,))
        cur.execute("DELETE FROM monthly_excluded_duties WHERE duty_id=?", (duty_id,))
        cur.execute("DELETE FROM excluded_duties WHERE duty_id=?", (duty_id,))
        cur.execute("DELETE FROM fixed_driver_duties WHERE duty_id=? OR duty1_id=? OR duty2_id=?", (duty_id, duty_id, duty_id))
        cur.execute("DELETE FROM duties WHERE id=?", (duty_id,))
        self.conn.commit()
        self.clear_duty_form()
        self.load_reference_data(update_month=False)
        self.refresh_all()
        self.auto_status_label.configure(text=f"Usunięto służbę {code}.")

    def set_selected_duties_month_exclusion(self, excluded: bool) -> None:
        duty_ids = self.selected_duty_ids_from_tree()
        if not duty_ids:
            messagebox.showinfo("Zaznaczenia służb", "Zaznacz jedną lub kilka służb w bazie.")
            return
        month_key = self.target_month_key()
        if not month_key:
            return
        cur = self.conn.cursor()
        removed_from_plan = 0
        if excluded:
            cur.executemany(
                "INSERT OR IGNORE INTO monthly_excluded_duties(month_key, duty_id) VALUES (?, ?)",
                [(month_key, duty_id) for duty_id in duty_ids],
            )
            removed_from_plan = self.remove_duties_from_plan_for_month(month_key, duty_ids)
            action = "zaznaczono jako 'nie planować'"
        else:
            cur.executemany(
                "DELETE FROM monthly_excluded_duties WHERE month_key=? AND duty_id=?",
                [(month_key, duty_id) for duty_id in duty_ids],
            )
            action = "odznaczono"
        self.conn.commit()
        self.load_reference_data(update_month=False)
        self.refresh_all()
        status = f"{len(duty_ids)} służb: {action} w miesiącu {month_key}."
        if removed_from_plan:
            status += f" Usunięto {removed_from_plan} już zaplanowanych wpisów z tymi służbami."
        self.auto_status_label.configure(text=status)

    def toggle_selected_duties_month_exclusion(self) -> None:
        duty_ids = self.selected_duty_ids_from_tree()
        if not duty_ids:
            messagebox.showinfo("Zaznaczenia służb", "Zaznacz jedną lub kilka służb w bazie.")
            return
        month_key = self.target_month_key()
        if not month_key:
            return
        cur = self.conn.cursor()
        checked = 0
        unchecked = 0
        newly_excluded_ids: list[int] = []
        self.load_monthly_excluded_duty_ids()
        for duty_id in duty_ids:
            if duty_id in self.monthly_excluded_duty_ids:
                cur.execute("DELETE FROM monthly_excluded_duties WHERE month_key=? AND duty_id=?", (month_key, duty_id))
                unchecked += 1
            else:
                cur.execute("INSERT OR IGNORE INTO monthly_excluded_duties(month_key, duty_id) VALUES (?, ?)", (month_key, duty_id))
                newly_excluded_ids.append(duty_id)
                checked += 1
        removed_from_plan = self.remove_duties_from_plan_for_month(month_key, newly_excluded_ids)
        self.conn.commit()
        self.load_reference_data(update_month=False)
        self.refresh_all()
        status = f"Miesiąc {month_key}: zaznaczono {checked}, odznaczono {unchecked}."
        if removed_from_plan:
            status += f" Usunięto {removed_from_plan} już zaplanowanych wpisów z zaznaczonymi służbami."
        self.auto_status_label.configure(text=status)

    def clear_month_exclusions(self) -> None:
        month_key = self.target_month_key()
        if not month_key:
            return
        count = int(self.one_value("SELECT COUNT(*) FROM monthly_excluded_duties WHERE month_key=?", (month_key,), default="0"))
        if count and not messagebox.askyesno("Wyczyść zaznaczenia", f"Usunąć {count} zaznaczeń 'nie planować' dla miesiąca {month_key}?"):
            return
        self.conn.execute("DELETE FROM monthly_excluded_duties WHERE month_key=?", (month_key,))
        self.conn.commit()
        self.load_reference_data(update_month=False)
        self.load_duties_tree()
        self.auto_status_label.configure(text=f"Wyczyszczono zaznaczenia dla miesiąca {month_key}.")


    # ---------- wyszukiwanie kierowców ----------
    def normalize_search_fragment(self, value: str) -> str:
        """Ujednolicenie tekstu do szybkiego wyszukiwania po nazwisku."""
        text = str(value or "").replace("Ł", "L").replace("ł", "l")
        text = unicodedata.normalize("NFKD", text)
        text = "".join(ch for ch in text if not unicodedata.combining(ch))
        return re.sub(r"\s+", " ", text).strip().lower()

    def driver_surname_from_name(self, name: str) -> str:
        """Zwróć nazwisko z etykiety kierowcy lub z pola nazwisko i imię."""
        text = str(name or "").strip()
        # Etykiety w comboboxach mają format: LP 12 - KOWALSKI JAN.
        m = re.match(r"LP\s+[^-]+\s+-\s+(.*)", text, re.IGNORECASE)
        if m:
            text = m.group(1).strip()
        # W bazie kierowców imię jest zwykle po nazwisku; do szukania bierzemy pierwszy człon.
        return (text.split()[0] if text.split() else text).strip()

    def driver_matches_search(self, query: str, lp: object, name: object, employee_no: object = "") -> bool:
        text = self.normalize_search_fragment(query)
        if not text:
            return True
        # v328: numer pracownika nie bierze już udziału w wyszukiwaniu, bo został usunięty z widoków.
        haystack = self.normalize_search_fragment(f"{lp or ''} {name or ''}")
        return text in haystack

    def install_driver_tree_typeahead(self, tree: ttk.Treeview, *, name_column: str) -> None:
        """Pozwala zaznaczyć kierowcę na liście przez wpisanie pierwszych liter nazwiska."""
        self.install_tree_typeahead(tree, columns=(name_column,), driver_mode=True)

    def install_tree_typeahead(self, tree: ttk.Treeview, *, columns: tuple[str, ...], driver_mode: bool = False) -> None:
        """Uniwersalne wyszukiwanie na listach: wpisywanie liter przenosi zaznaczenie do pasującego wiersza."""
        tree._planer_typeahead_buffer = ""  # type: ignore[attr-defined]
        tree._planer_typeahead_after_id = None  # type: ignore[attr-defined]
        tree._planer_typeahead_columns = tuple(columns)  # type: ignore[attr-defined]
        tree._planer_typeahead_driver_mode = bool(driver_mode)  # type: ignore[attr-defined]
        tree.bind("<KeyPress>", lambda event, t=tree: self.on_tree_typeahead(event, t), add="+")

    def on_driver_tree_typeahead(self, event: tk.Event, tree: ttk.Treeview, name_column: str) -> str | None:
        return self.on_tree_typeahead(event, tree, fallback_columns=(name_column,), driver_mode=True)

    def on_tree_typeahead(
        self,
        event: tk.Event,
        tree: ttk.Treeview,
        fallback_columns: tuple[str, ...] | None = None,
        driver_mode: bool | None = None,
    ) -> str | None:
        char = getattr(event, "char", "") or ""
        keysym = getattr(event, "keysym", "") or ""
        buffer = str(getattr(tree, "_planer_typeahead_buffer", ""))
        if keysym in {"BackSpace", "Delete"}:
            buffer = buffer[:-1]
        elif len(char) == 1 and char.isprintable() and not (getattr(event, "state", 0) & 0x0004):
            buffer += char
        else:
            return None
        tree._planer_typeahead_buffer = buffer  # type: ignore[attr-defined]
        query = self.normalize_search_fragment(buffer)
        after_id = getattr(tree, "_planer_typeahead_after_id", None)
        if after_id:
            try:
                self.after_cancel(after_id)
            except Exception:
                pass
        try:
            tree._planer_typeahead_after_id = self.after(1400, lambda t=tree: self.clear_tree_typeahead_buffer(t))  # type: ignore[attr-defined]
        except tk.TclError:
            tree._planer_typeahead_after_id = None  # type: ignore[attr-defined]
        if not query:
            return "break"
        columns = fallback_columns or tuple(getattr(tree, "_planer_typeahead_columns", ()))
        use_driver_mode = bool(getattr(tree, "_planer_typeahead_driver_mode", False) if driver_mode is None else driver_mode)
        if not columns:
            return "break"
        for iid in tree.get_children(""):
            texts: list[str] = []
            for column in columns:
                try:
                    texts.append(str(tree.set(iid, column) or ""))
                except tk.TclError:
                    pass
            for text_value in texts:
                normalized = self.normalize_search_fragment(text_value)
                if use_driver_mode:
                    surname = self.normalize_search_fragment(self.driver_surname_from_name(text_value))
                    if surname.startswith(query) or normalized.startswith(query) or query in normalized:
                        tree.selection_set(iid)
                        tree.focus(iid)
                        tree.see(iid)
                        return "break"
                elif normalized.startswith(query) or query in normalized:
                    tree.selection_set(iid)
                    tree.focus(iid)
                    tree.see(iid)
                    return "break"
        return "break"

    def clear_tree_typeahead_buffer(self, tree: ttk.Treeview) -> None:
        try:
            tree._planer_typeahead_buffer = ""  # type: ignore[attr-defined]
            tree._planer_typeahead_after_id = None  # type: ignore[attr-defined]
        except Exception:
            pass

    def clear_driver_typeahead_buffer(self) -> None:
        self._driver_typeahead_buffer = ""
        self._driver_typeahead_after_id = None

    def load_drivers_tree(self) -> None:
        if not hasattr(self, "drivers_tree"):
            return
        for item in self.drivers_tree.get_children():
            self.drivers_tree.delete(item)
        self.drivers_tree_ids.clear()
        query = getattr(self, "driver_db_search_var", tk.StringVar()).get().strip()
        planned_counts = {
            int(row["driver_id"]): int(row["cnt"])
            for row in self.rows("SELECT driver_id, COUNT(*) AS cnt FROM planned_schedule WHERE driver_id IS NOT NULL GROUP BY driver_id")
        }
        for row in self.rows("SELECT id, lp, name, employee_no, COALESCE(no_plan_rn, 0) AS no_plan_rn FROM drivers ORDER BY name COLLATE NOCASE, CAST(lp AS INTEGER)"):
            if not self.driver_matches_search(query, row["lp"], row["name"]):
                continue
            driver_id = int(row["id"])
            iid = f"driverdb-{driver_id}"
            self.drivers_tree_ids[iid] = driver_id
            self.insert_tree_row(
                self.drivers_tree,
                iid,
                (row["lp"] or "", self.ui_driver_label_from_row(row), "☑" if int(row["no_plan_rn"] or 0) else "☐", planned_counts.get(driver_id, 0)),
            )
        self.auto_fit_tree_columns(self.drivers_tree, max_width=280, min_width=46)

    def selected_driver_record_id(self) -> int | None:
        if not hasattr(self, "drivers_tree"):
            return None
        selection = self.drivers_tree.selection()
        if not selection:
            return None
        return self.drivers_tree_ids.get(selection[0])

    def clear_driver_form(self) -> None:
        self.driver_db_selected_id = None
        self.driver_db_lp_var.set("")
        self.driver_db_name_var.set("")
        self.driver_db_employee_var.set("")
        if hasattr(self, "driver_db_no_rn_var"):
            self.driver_db_no_rn_var.set(0)
        if hasattr(self, "drivers_tree"):
            self.drivers_tree.selection_remove(self.drivers_tree.selection())

    def prepare_new_driver_record(self) -> None:
        """Przygotuj formularz do dodania nowego kierowcy."""
        self.clear_driver_form()
        self.driver_db_lp_var.set(self.next_driver_lp())
        if hasattr(self, "driver_db_name_entry"):
            self.driver_db_name_entry.focus_set()
        if hasattr(self, "auto_status_label"):
            self.auto_status_label.configure(text="Wpisz dane nowego kierowcy i kliknij Zapisz / aktualizuj.")

    def load_driver_record_to_form(self) -> None:
        driver_id = self.selected_driver_record_id()
        if driver_id is None:
            messagebox.showinfo("Baza kierowców", "Zaznacz kierowcę.")
            return
        row = self.rows("SELECT id, lp, name, employee_no, COALESCE(no_plan_rn, 0) AS no_plan_rn FROM drivers WHERE id=?", (driver_id,))
        if not row:
            return
        driver = row[0]
        self.driver_db_selected_id = int(driver["id"])
        self.driver_db_lp_var.set(driver["lp"] or "")
        self.driver_db_name_var.set(driver["name"] or "")
        self.driver_db_employee_var.set("")
        if hasattr(self, "driver_db_no_rn_var"):
            self.driver_db_no_rn_var.set(1 if int(driver["no_plan_rn"] or 0) else 0)

    def save_driver_record(self) -> None:
        lp = self.driver_db_lp_var.get().strip()
        name = self.driver_db_name_var.get().strip()
        employee_no = ""
        no_plan_rn = 1 if (hasattr(self, "driver_db_no_rn_var") and int(self.driver_db_no_rn_var.get())) else 0
        if not name:
            messagebox.showerror("Baza kierowców", "Podaj nazwisko i imię kierowcy.")
            return
        if not lp:
            lp = self.next_driver_lp()
            self.driver_db_lp_var.set(lp)
        try:
            if self.driver_db_selected_id:
                self.conn.execute(
                    "UPDATE drivers SET lp=?, name=?, employee_no=?, no_plan_rn=? WHERE id=?",
                    (lp, name, employee_no, no_plan_rn, int(self.driver_db_selected_id)),
                )
                action = "Zmieniono dane kierowcy."
            else:
                cur = self.conn.execute(
                    "INSERT INTO drivers(lp, name, employee_no, no_plan_rn) VALUES (?, ?, ?, ?)",
                    (lp, name, employee_no, no_plan_rn),
                )
                self.driver_db_selected_id = int(cur.lastrowid) if cur.lastrowid else None
                action = "Dodano kierowcę."
            self.conn.commit()
        except sqlite3.IntegrityError as exc:
            messagebox.showerror("Baza kierowców", f"Nie można zapisać kierowcy. Sprawdź, czy nie ma duplikatu.\n\n{exc}")
            return
        saved_driver_id = self.driver_db_selected_id
        self.load_reference_data(update_month=False)
        self.refresh_all()
        if saved_driver_id and hasattr(self, "drivers_tree"):
            iid = f"driverdb-{saved_driver_id}"
            if iid in self.drivers_tree.get_children(""):
                self.drivers_tree.selection_set(iid)
                self.drivers_tree.focus(iid)
                self.drivers_tree.see(iid)
                self.driver_db_selected_id = saved_driver_id
        self.auto_status_label.configure(text=action)

    def next_driver_lp(self) -> str:
        """Zwróć kolejny wolny numer LP dla nowego kierowcy."""
        rows = self.rows("SELECT lp FROM drivers")
        used: list[int] = []
        for row in rows:
            value = str(row["lp"] or "").strip()
            if value.isdigit():
                used.append(int(value))
        return str((max(used) if used else 0) + 1)

    def assign_missing_driver_lps(self) -> None:
        """Uzupełnij brakujące LP bez zmiany istniejących numerów."""
        rows = self.rows("SELECT id, lp, name FROM drivers ORDER BY name")
        used: set[int] = set()
        missing: list[sqlite3.Row] = []
        for row in rows:
            value = str(row["lp"] or "").strip()
            if value.isdigit():
                used.add(int(value))
            else:
                missing.append(row)
        if not missing:
            messagebox.showinfo("Baza kierowców", "Wszyscy kierowcy mają już LP.")
            return
        next_lp = 1
        updates: list[tuple[str, int]] = []
        for row in missing:
            while next_lp in used:
                next_lp += 1
            updates.append((str(next_lp), int(row["id"])))
            used.add(next_lp)
            next_lp += 1
        self.conn.executemany("UPDATE drivers SET lp=? WHERE id=?", updates)
        self.conn.commit()
        self.load_reference_data(update_month=False)
        self.refresh_all()
        self.auto_status_label.configure(text=f"Uzupełniono LP dla {len(updates)} kierowców.")

    def delete_selected_driver_record(self) -> None:
        driver_id = self.driver_db_selected_id or self.selected_driver_record_id()
        if driver_id is None:
            messagebox.showinfo("Baza kierowców", "Zaznacz kierowcę do usunięcia.")
            return
        row = self.rows("SELECT name FROM drivers WHERE id=?", (driver_id,))
        if not row:
            return
        name = row[0]["name"] or ""
        planned_count = int(self.one_value("SELECT COUNT(*) FROM planned_schedule WHERE driver_id=?", (driver_id,), default="0"))
        if not messagebox.askyesno(
            "Usuń kierowcę",
            f"Usunąć kierowcę: {name}?\n\nZostaną usunięte także jego wpisy planu, wykluczenia, stałe służby i przypisania w parach. Wpisy planu: {planned_count}.",
        ):
            return
        cur = self.conn.cursor()
        cur.execute("DELETE FROM planned_schedule WHERE driver_id=?", (driver_id,))
        cur.execute("DELETE FROM original_schedule WHERE driver_id=?", (driver_id,))
        cur.execute("DELETE FROM compliance_violations WHERE driver_id=?", (driver_id,))
        cur.execute("DELETE FROM monthly_excluded_drivers WHERE driver_id=?", (driver_id,))
        cur.execute("DELETE FROM fixed_driver_duties WHERE driver_id=?", (driver_id,))
        cur.execute("DELETE FROM driver_pairs WHERE driver1_id=? OR driver2_id=?", (driver_id, driver_id))
        cur.execute("DELETE FROM drivers WHERE id=?", (driver_id,))
        self.conn.commit()
        self.clear_driver_form()
        self.load_reference_data(update_month=False)
        self.refresh_all()
        self.auto_status_label.configure(text=f"Usunięto kierowcę: {name}.")


    # ---------- driver exclusions, fixed duties, cars and pairs ----------
    def load_monthly_excluded_driver_ids(self) -> None:
        month_key = self.target_month_key()
        if not month_key:
            self.monthly_excluded_driver_ids = set()
            return
        self.monthly_excluded_driver_ids = {int(row["driver_id"]) for row in self.rows("SELECT driver_id FROM monthly_excluded_drivers WHERE month_key=?", (month_key,))}

    def excluded_driver_ids_for_month(self, month_key: str) -> set[int]:
        return {int(row["driver_id"]) for row in self.rows("SELECT driver_id FROM monthly_excluded_drivers WHERE month_key=?", (month_key,))}

    def excluded_driver_ids_for_date_range(self, start: str, end: str) -> set[int]:
        """Zwraca kierowców wyłączonych z planowania w miesiącach objętych zakresem wydruku/raportu."""
        month_keys = sorted({date_value[:7] for date_value in self.each_date(start, end)})
        if not month_keys:
            return set()
        placeholders = ",".join("?" for _ in month_keys)
        return {
            int(row["driver_id"])
            for row in self.rows(
                f"SELECT DISTINCT driver_id FROM monthly_excluded_drivers WHERE month_key IN ({placeholders})",
                tuple(month_keys),
            )
        }

    def remove_drivers_from_plan_for_month(self, month_key: str, driver_ids: list[int] | set[int]) -> int:
        clean_ids = sorted({int(driver_id) for driver_id in driver_ids})
        if not clean_ids:
            return 0
        try:
            year_text, month_text = month_key.split("-", 1)
            start, end = self.month_range(int(year_text), int(month_text))
        except Exception:
            return 0
        placeholders = ",".join("?" for _ in clean_ids)
        cur = self.conn.execute(
            f"""
            DELETE FROM planned_schedule
            WHERE plan_date BETWEEN ? AND ?
              AND COALESCE(entry_source, 'manual')='auto'
              AND driver_id IN ({placeholders})
            """,
            (start, end, *clean_ids),
        )
        removed = int(cur.rowcount if cur.rowcount is not None else 0)
        if removed:
            self.audit_and_store(start, end)
        return removed

    def selected_driver_ids_from_exclusion_tree(self) -> list[int]:
        if not hasattr(self, "driver_exclusion_tree"):
            return []
        ids: list[int] = []
        for iid in self.driver_exclusion_tree.selection():
            driver_id = self.driver_exclusion_tree_ids.get(iid)
            if driver_id is not None:
                ids.append(int(driver_id))
        return ids

    def load_driver_exclusions_tree(self) -> None:
        if not hasattr(self, "driver_exclusion_tree"):
            return
        for item in self.driver_exclusion_tree.get_children():
            self.driver_exclusion_tree.delete(item)
        self.driver_exclusion_tree_ids.clear()
        month_key = self.target_month_key()
        if not month_key:
            return
        self.load_monthly_excluded_driver_ids()
        start, end = self.selected_month_range() or self.source_date_range()
        planned_counts = {
            int(row["driver_id"]): int(row["cnt"])
            for row in self.rows(
                "SELECT driver_id, COUNT(*) AS cnt FROM planned_schedule WHERE plan_date BETWEEN ? AND ? AND driver_id IS NOT NULL GROUP BY driver_id",
                (start, end),
            )
        }
        query = getattr(self, "driver_exclusion_search_var", tk.StringVar()).get().strip()
        for row in self.rows("SELECT id, lp, name, employee_no FROM drivers ORDER BY name COLLATE NOCASE, CAST(lp AS INTEGER)"):
            if not self.driver_matches_search(query, row["lp"], row["name"]):
                continue
            driver_id = int(row["id"])
            iid = f"driverexclude-{driver_id}"
            self.driver_exclusion_tree_ids[iid] = driver_id
            self.insert_tree_row(
                self.driver_exclusion_tree,
                iid,
                ("☑" if driver_id in self.monthly_excluded_driver_ids else "☐", row["lp"] or "", self.ui_driver_label_from_row(row), planned_counts.get(driver_id, 0)),
            )
        self.auto_fit_tree_columns(self.driver_exclusion_tree, max_width=260, min_width=52)

    def on_driver_exclusion_tree_click(self, event: tk.Event) -> str | None:
        if not hasattr(self, "driver_exclusion_tree"):
            return None
        region = self.driver_exclusion_tree.identify("region", event.x, event.y)
        column = self.driver_exclusion_tree.identify_column(event.x)
        if region == "cell" and column == "#1":
            row_id = self.driver_exclusion_tree.identify_row(event.y)
            if row_id:
                # Jeżeli użytkownik zaznaczył wiele wierszy Ctrl/Shift, kliknięcie kratki
                # zmienia cały zaznaczony zestaw zamiast kasować wybór do jednego kierowcy.
                current = set(self.driver_exclusion_tree.selection())
                if row_id not in current:
                    self.driver_exclusion_tree.selection_set(row_id)
                self.toggle_selected_drivers_month_exclusion()
                return "break"
        return None

    def visible_driver_ids_from_exclusion_tree(self) -> list[int]:
        if not hasattr(self, "driver_exclusion_tree"):
            return []
        ids: list[int] = []
        for iid in self.driver_exclusion_tree.get_children(""):
            driver_id = self.driver_exclusion_tree_ids.get(iid)
            if driver_id is not None:
                ids.append(int(driver_id))
        return ids

    def select_visible_driver_exclusion_rows(self) -> None:
        if not hasattr(self, "driver_exclusion_tree"):
            return
        items = list(self.driver_exclusion_tree.get_children(""))
        if not items:
            messagebox.showinfo("Nie planuj kierowców", "Brak widocznych kierowców do zaznaczenia.")
            return
        self.driver_exclusion_tree.selection_set(items)
        try:
            self.driver_exclusion_tree.focus(items[0])
            self.driver_exclusion_tree.see(items[0])
        except tk.TclError:
            pass
        if hasattr(self, "driver_exclusion_status_label"):
            self.driver_exclusion_status_label.configure(text=f"Zaznaczono {len(items)} widocznych kierowców.")

    def set_visible_drivers_month_exclusion(self, excluded: bool) -> None:
        month_key = self.target_month_key()
        if not month_key:
            return
        driver_ids = self.visible_driver_ids_from_exclusion_tree()
        if not driver_ids:
            messagebox.showinfo("Nie planuj kierowców", "Brak widocznych kierowców do zmiany.")
            return
        cur = self.conn.cursor()
        removed_from_plan = 0
        if excluded:
            cur.executemany("INSERT OR IGNORE INTO monthly_excluded_drivers(month_key, driver_id) VALUES (?, ?)", [(month_key, driver_id) for driver_id in driver_ids])
            removed_from_plan = self.remove_drivers_from_plan_for_month(month_key, driver_ids)
            action = "zaznaczono jako 'nie planować' wszystkich widocznych"
        else:
            cur.executemany("DELETE FROM monthly_excluded_drivers WHERE month_key=? AND driver_id=?", [(month_key, driver_id) for driver_id in driver_ids])
            action = "odznaczono wszystkich widocznych"
        self.conn.commit()
        self.load_monthly_excluded_driver_ids()
        self.refresh_all()
        status = f"Miesiąc {month_key}: {action} ({len(driver_ids)} kierowców)."
        if removed_from_plan:
            status += f" Usunięto {removed_from_plan} wpisów z gotowego planu."
        if hasattr(self, "auto_status_label"):
            self.auto_status_label.configure(text=status)
        if hasattr(self, "driver_exclusion_status_label"):
            self.driver_exclusion_status_label.configure(text=status)

    def set_selected_drivers_month_exclusion(self, excluded: bool) -> None:
        month_key = self.target_month_key()
        if not month_key:
            return
        driver_ids = self.selected_driver_ids_from_exclusion_tree()
        if not driver_ids:
            messagebox.showinfo("Nie planuj kierowców", "Zaznacz jednego lub kilku kierowców.")
            return
        cur = self.conn.cursor()
        removed_from_plan = 0
        if excluded:
            cur.executemany("INSERT OR IGNORE INTO monthly_excluded_drivers(month_key, driver_id) VALUES (?, ?)", [(month_key, driver_id) for driver_id in driver_ids])
            removed_from_plan = self.remove_drivers_from_plan_for_month(month_key, driver_ids)
            action = "zaznaczono jako 'nie planować'"
        else:
            cur.executemany("DELETE FROM monthly_excluded_drivers WHERE month_key=? AND driver_id=?", [(month_key, driver_id) for driver_id in driver_ids])
            action = "odznaczono"
        self.conn.commit()
        self.load_monthly_excluded_driver_ids()
        self.refresh_all()
        status = f"Miesiąc {month_key}: {action} {len(driver_ids)} kierowców."
        if removed_from_plan:
            status += f" Usunięto {removed_from_plan} wpisów z gotowego planu."
        self.auto_status_label.configure(text=status)
        if hasattr(self, "driver_exclusion_status_label"):
            self.driver_exclusion_status_label.configure(text=status)

    def toggle_selected_drivers_month_exclusion(self) -> None:
        month_key = self.target_month_key()
        if not month_key:
            return
        driver_ids = self.selected_driver_ids_from_exclusion_tree()
        if not driver_ids:
            messagebox.showinfo("Nie planuj kierowców", "Zaznacz jednego lub kilku kierowców.")
            return
        self.load_monthly_excluded_driver_ids()
        cur = self.conn.cursor()
        newly_excluded: list[int] = []
        for driver_id in driver_ids:
            if driver_id in self.monthly_excluded_driver_ids:
                cur.execute("DELETE FROM monthly_excluded_drivers WHERE month_key=? AND driver_id=?", (month_key, driver_id))
            else:
                cur.execute("INSERT OR IGNORE INTO monthly_excluded_drivers(month_key, driver_id) VALUES (?, ?)", (month_key, driver_id))
                newly_excluded.append(driver_id)
        removed_from_plan = self.remove_drivers_from_plan_for_month(month_key, newly_excluded)
        self.conn.commit()
        self.load_monthly_excluded_driver_ids()
        self.refresh_all()
        status = f"Miesiąc {month_key}: zmieniono zaznaczenie {len(driver_ids)} kierowców."
        if removed_from_plan:
            status += f" Usunięto {removed_from_plan} wpisów z gotowego planu."
        self.auto_status_label.configure(text=status)
        if hasattr(self, "driver_exclusion_status_label"):
            self.driver_exclusion_status_label.configure(text=status)

    def replan_current_month_from_driver_exclusions(self) -> None:
        """Uruchom ponowne planowanie miesiąca po zmianach w zakładce 'Nie planuj kierowców'."""
        target = self.get_target_year_month()
        if target is None:
            messagebox.showinfo("Zaplanuj ponownie", "Wybierz poprawny rok i miesiąc.")
            return
        year, month = target
        month_key = f"{year:04d}-{month:02d}"
        excluded_count = int(self.one_value(
            "SELECT COUNT(*) FROM monthly_excluded_drivers WHERE month_key=?",
            (month_key,),
            default="0",
        ))
        if not messagebox.askyesno(
            "Zaplanuj ponownie",
            f"Przeliczyć automatycznie plan dla miesiąca {month_key}?\n\n"
            f"Kierowcy oznaczeni jako 'nie planować': {excluded_count}.\n"
            "Istniejący plan miesiąca zostanie zastąpiony po dodatkowym potwierdzeniu, "
            "a program zapisze kopię do cofnięcia.",
        ):
            return
        self.auto_plan_all_drivers()
        if hasattr(self, "driver_exclusion_status_label"):
            self.driver_exclusion_status_label.configure(text=f"Przeliczono plan dla {month_key}.")

    def clear_driver_exclusions(self) -> None:
        month_key = self.target_month_key()
        if not month_key:
            return
        count = int(self.one_value("SELECT COUNT(*) FROM monthly_excluded_drivers WHERE month_key=?", (month_key,), default="0"))
        if count and not messagebox.askyesno("Wyczyść zaznaczenia", f"Usunąć {count} zaznaczeń kierowców 'nie planować' dla miesiąca {month_key}?"):
            return
        self.conn.execute("DELETE FROM monthly_excluded_drivers WHERE month_key=?", (month_key,))
        self.conn.commit()
        self.refresh_all()

    def load_fixed_assignments_tree(self) -> None:
        if not hasattr(self, "fixed_tree"):
            return
        for item in self.fixed_tree.get_children():
            self.fixed_tree.delete(item)
        self.fixed_assignment_tree_ids.clear()
        month_key = self.target_month_key()
        if not month_key:
            return
        for row in self.rows(
            """
            SELECT f.driver_id,
                   COALESCE(f.duty1_id, f.duty_id) AS duty1_id,
                   COALESCE(f.duty2_id, f.duty_id) AS duty2_id,
                   dr.lp, dr.name AS driver_name, dr.employee_no,
                   d1.code AS code1, d1.name AS name1, d1.work_range AS work1,
                   d2.code AS code2, d2.name AS name2, d2.work_range AS work2
            FROM fixed_driver_duties f
            JOIN drivers dr ON dr.id = f.driver_id
            LEFT JOIN duties d1 ON d1.id = COALESCE(f.duty1_id, f.duty_id)
            LEFT JOIN duties d2 ON d2.id = COALESCE(f.duty2_id, f.duty_id)
            WHERE f.month_key=?
            ORDER BY CAST(dr.lp AS INTEGER), dr.name
            """,
            (month_key,),
        ):
            iid = f"fixed-{row['driver_id']}"
            self.fixed_assignment_tree_ids[iid] = int(row["driver_id"])
            driver_label = self.normalize_display_text(row["driver_name"])
            duty1_label = self.ui_duty_label_from_parts(row["code1"], row["duty1_id"]) if row["duty1_id"] is not None else ""
            duty2_label = self.ui_duty_label_from_parts(row["code2"], row["duty2_id"]) if row["duty2_id"] is not None else ""
            self.insert_tree_row(self.fixed_tree, iid, (driver_label, duty1_label, row["work1"] or "", duty2_label, row["work2"] or ""))
        self.auto_fit_tree_columns(self.fixed_tree, max_width=260, min_width=70)

    def open_fixed_driver_picker(self) -> None:
        """Otwórz czytelną listę kierowców dla zakładki Stałe służby."""
        self.load_reference_data(update_month=False)
        picker = tk.Toplevel(self)
        picker.title("Wybierz kierowcę do stałej służby")
        picker.geometry("720x520")
        picker.transient(self)
        picker.grab_set()

        frame = ttk.Frame(picker, padding=10)
        frame.pack(fill="both", expand=True)
        search_var = tk.StringVar()
        ttk.Label(frame, text="Szukaj kierowcy:").pack(anchor="w")
        search_entry = ttk.Entry(frame, textvariable=search_var)
        search_entry.pack(fill="x", pady=(3, 8))

        cols = ("lp", "name")
        tree = ttk.Treeview(frame, columns=cols, show="headings", selectmode="browse")
        tree.heading("lp", text="LP")
        tree.heading("name", text="Kierowca")
        tree.column("lp", width=80, anchor="center")
        tree.column("name", width=560, anchor="w")
        tree.pack(side="left", fill="both", expand=True)
        scrollbar = ttk.Scrollbar(frame, orient="vertical", command=tree.yview)
        scrollbar.pack(side="right", fill="y")
        tree.configure(yscrollcommand=scrollbar.set)
        self.configure_tree_zebra(tree)

        def fill() -> None:
            for item in tree.get_children():
                tree.delete(item)
            query = search_var.get().strip().lower()
            for label in self.driver_labels:
                driver_id = self.driver_label_to_id.get(label)
                if driver_id is None:
                    continue
                name = label
                if not self.driver_matches_search(query, "", name):
                    continue
                self.insert_tree_row(tree, str(driver_id), ("", name))

        def choose(_event=None) -> None:
            selection = tree.selection()
            if not selection:
                return
            driver_id = int(selection[0])
            for label, value in self.driver_label_to_id.items():
                if value == driver_id:
                    self.fixed_driver_var.set(label)
                    break
            picker.destroy()

        button_bar = ttk.Frame(picker, padding=(10, 0, 10, 10))
        button_bar.pack(fill="x")
        ttk.Button(button_bar, text="Wybierz", command=choose).pack(side="right", padx=(8, 0))
        ttk.Button(button_bar, text="Anuluj", command=picker.destroy).pack(side="right")

        search_var.trace_add("write", lambda *_args: fill())
        tree.bind("<Double-1>", choose)
        tree.bind("<Return>", choose)
        self.install_driver_tree_typeahead(tree, name_column="#2")
        fill()
        search_entry.focus_set()

    def save_fixed_driver_duty(self) -> None:
        month_key = self.target_month_key()
        if not month_key:
            return
        driver_id = self.resolve_driver_id_from_text(self.fixed_driver_var.get(), allow_none=False)
        duty1_id = self.resolve_duty_id_from_text(self.fixed_duty_var.get()) if hasattr(self, "fixed_duty_var") else None
        duty2_id = self.resolve_duty_id_from_text(self.fixed_duty2_var.get()) if hasattr(self, "fixed_duty2_var") else None
        if not driver_id:
            messagebox.showinfo("Stałe służby", "Wybierz konkretnego kierowcę.")
            return
        if duty1_id is None and duty2_id is None:
            messagebox.showinfo("Stałe służby", "Wybierz służbę I zmiany, służbę II zmiany albo obie.")
            return
        excluded = self.excluded_duty_ids_for_month(month_key)
        excluded_selected = [duty_id for duty_id in (duty1_id, duty2_id) if duty_id is not None and int(duty_id) in excluded]
        if excluded_selected:
            if not messagebox.askyesno("Służba wykluczona", "Jedna z wybranych służb jest oznaczona jako 'nie planować' w tym miesiącu. Zapisać mimo to jako stałą? Automat i tak jej nie użyje, dopóki jest wykluczona."):
                return
        main_duty_id = int(duty1_id if duty1_id is not None else duty2_id)
        self.conn.execute(
            """
            INSERT INTO fixed_driver_duties(month_key, driver_id, duty_id, duty1_id, duty2_id, updated_at)
            VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
            ON CONFLICT(month_key, driver_id) DO UPDATE SET
                duty_id=excluded.duty_id,
                duty1_id=excluded.duty1_id,
                duty2_id=excluded.duty2_id,
                updated_at=CURRENT_TIMESTAMP
            """,
            (month_key, int(driver_id), main_duty_id, int(duty1_id) if duty1_id is not None else None, int(duty2_id) if duty2_id is not None else None),
        )
        self.conn.commit()
        self.refresh_all()
        self.auto_status_label.configure(text=f"Miesiąc {month_key}: zapisano stałe służby I/II zmiany dla kierowcy.")

    def delete_selected_fixed_driver_duty(self) -> None:
        month_key = self.target_month_key()
        if not month_key:
            return
        selection = self.fixed_tree.selection() if hasattr(self, "fixed_tree") else []
        if not selection:
            messagebox.showinfo("Stałe służby", "Zaznacz przypisanie do usunięcia.")
            return
        driver_id = self.fixed_assignment_tree_ids.get(selection[0])
        if not driver_id:
            return
        self.conn.execute("DELETE FROM fixed_driver_duties WHERE month_key=? AND driver_id=?", (month_key, driver_id))
        self.conn.commit()
        self.refresh_all()

    def load_fixed_selection_to_form(self) -> None:
        selection = self.fixed_tree.selection() if hasattr(self, "fixed_tree") else []
        if not selection:
            return
        driver_id = self.fixed_assignment_tree_ids.get(selection[0])
        month_key = self.target_month_key()
        if not driver_id or not month_key:
            return
        row = self.conn.execute(
            """
            SELECT COALESCE(duty1_id, duty_id) AS duty1_id,
                   COALESCE(duty2_id, duty_id) AS duty2_id
            FROM fixed_driver_duties WHERE month_key=? AND driver_id=?
            """,
            (month_key, driver_id),
        ).fetchone()
        if not row:
            return
        for label, value in self.driver_label_to_id.items():
            if value == driver_id:
                self.fixed_driver_var.set(label)
                break
        self.fixed_duty_var.set("")
        self.fixed_duty2_var.set("")
        duty1 = row["duty1_id"]
        duty2 = row["duty2_id"]
        if duty1 is not None:
            label = self.duty_id_to_label.get(int(duty1))
            if label:
                self.fixed_duty_var.set(label)
        if duty2 is not None:
            label = self.duty_id_to_label.get(int(duty2))
            if label:
                self.fixed_duty2_var.set(label)

    def fixed_duties_for_month(self, month_key: str) -> dict[int, dict[str, int]]:
        result: dict[int, dict[str, int]] = {}
        for row in self.rows(
            """
            SELECT driver_id,
                   COALESCE(duty1_id, duty_id) AS duty1_id,
                   COALESCE(duty2_id, duty_id) AS duty2_id
            FROM fixed_driver_duties
            WHERE month_key=?
            """,
            (month_key,),
        ):
            per_shift: dict[str, int] = {}
            if row["duty1_id"] is not None:
                per_shift["morning"] = int(row["duty1_id"])
            if row["duty2_id"] is not None:
                per_shift["afternoon"] = int(row["duty2_id"])
            if per_shift:
                result[int(row["driver_id"])] = per_shift
        return result

    def fixed_duty_for_driver_shift(self, fixed_duties: dict[int, dict[str, int]], driver_id: int, preferred_shift: str) -> int | None:
        """Zwróć stałą służbę kierowcy dla aktualnej zmiany tygodnia."""
        per_shift = fixed_duties.get(int(driver_id))
        if not per_shift:
            return None
        if preferred_shift == "morning":
            return per_shift.get("morning")
        if preferred_shift == "afternoon":
            return per_shift.get("afternoon")
        return per_shift.get("morning") or per_shift.get("afternoon")

    def normalize_vehicle_type_label(self, value: object) -> str:
        """Ujednolić wpis kategorii pojazdu bez kasowania własnych nazw użytkownika."""
        text = " ".join(str(value or "").strip().split())
        if not text:
            return ""
        lowered = text.lower()
        for default_type in DEFAULT_VEHICLE_TYPE_CATEGORIES:
            if lowered == default_type.lower():
                return default_type
        for known_type in self.vehicle_type_options(include_empty=False):
            if lowered == str(known_type).lower():
                return str(known_type)
        return text

    def vehicle_type_categories_from_meta(self) -> list[str]:
        raw = ""
        try:
            raw = self.get_meta(VEHICLE_TYPE_CATEGORIES_META_KEY, "")
        except Exception:
            raw = ""
        values: list[str] = []
        if raw:
            try:
                decoded = json.loads(raw)
                if isinstance(decoded, list):
                    values = [str(item) for item in decoded]
                else:
                    values = [str(decoded)]
            except Exception:
                values = re.split(r"[,;\n]+", raw)
        result: list[str] = []
        seen: set[str] = set()
        for value in values:
            label = " ".join(str(value or "").strip().split())
            if not label:
                continue
            key = label.lower()
            if key not in seen:
                seen.add(key)
                result.append(label)
        return result

    def vehicle_type_options(self, include_empty: bool = True) -> list[str]:
        """Kategorie pojazdów widoczne w zakładce Samochody i pary."""
        options: list[str] = []
        if include_empty:
            options.append("")
        seen = {""} if include_empty else set()

        def add(value: object) -> None:
            label = " ".join(str(value or "").strip().split())
            if not label:
                return
            key = label.lower()
            if key in seen:
                return
            seen.add(key)
            options.append(label)

        for value in DEFAULT_VEHICLE_TYPE_CATEGORIES:
            add(value)
        for value in self.vehicle_type_categories_from_meta():
            add(value)
        try:
            rows = self.rows("SELECT DISTINCT COALESCE(vehicle_type, '') AS vehicle_type FROM cars WHERE TRIM(COALESCE(vehicle_type, ''))<>'' ORDER BY vehicle_type COLLATE NOCASE")
            for row in rows:
                add(row["vehicle_type"])
        except Exception:
            pass
        return options

    def remember_vehicle_type_category(self, value: object) -> None:
        label = self.normalize_vehicle_type_label(value)
        if not label:
            return
        categories = self.vehicle_type_categories_from_meta()
        if not any(label.lower() == item.lower() for item in categories):
            categories.append(label)
            self.set_meta(VEHICLE_TYPE_CATEGORIES_META_KEY, json.dumps(categories, ensure_ascii=False))
            try:
                self.conn.commit()
            except Exception:
                pass

    def refresh_vehicle_type_combo_values(self) -> None:
        if hasattr(self, "car_type_combo"):
            current = self.car_type_var.get() if hasattr(self, "car_type_var") else ""
            self.car_type_combo.configure(values=self.vehicle_type_options())
            if current:
                self.car_type_var.set(current)
        if hasattr(self, "duty_block_vehicle_type_combo"):
            current = self.duty_block_vehicle_type_var.get() if hasattr(self, "duty_block_vehicle_type_var") else ""
            self.duty_block_vehicle_type_combo.configure(values=self.vehicle_type_options())
            if current:
                self.duty_block_vehicle_type_var.set(current)
        if hasattr(self, "duty_db_vehicle_type_combo"):
            current = self.duty_db_vehicle_type_var.get() if hasattr(self, "duty_db_vehicle_type_var") else ""
            self.duty_db_vehicle_type_combo.configure(values=self.vehicle_type_options())
            if current:
                self.duty_db_vehicle_type_var.set(current)

    def remember_duty_vehicle_type_category(self) -> None:
        if not hasattr(self, "duty_db_vehicle_type_var"):
            return
        label = self.normalize_vehicle_type_label(self.duty_db_vehicle_type_var.get())
        if label:
            self.remember_vehicle_type_category(label)
            self.duty_db_vehicle_type_var.set(label)
            self.refresh_vehicle_type_combo_values()

    def remember_duty_block_vehicle_type_category(self) -> None:
        """Zapamiętaj własny rodzaj auta wpisany przy blokadzie służb."""
        if not hasattr(self, "duty_block_vehicle_type_var"):
            return
        label = self.normalize_vehicle_type_label(self.duty_block_vehicle_type_var.get())
        if label:
            self.remember_vehicle_type_category(label)
            self.duty_block_vehicle_type_var.set(label)
            self.refresh_vehicle_type_combo_values()

    def remember_vehicle_type_category_from_form(self, event: tk.Event | None = None) -> None:
        """Zapamiętaj kategorię wpisaną lub wybraną w polu rodzaju pojazdu."""
        if not hasattr(self, "car_type_var"):
            return
        label = self.normalize_vehicle_type_label(self.car_type_var.get())
        if label:
            self.remember_vehicle_type_category(label)
            self.refresh_vehicle_type_combo_values()

    def auto_save_selected_car_vehicle_type(self, event: tk.Event | None = None) -> None:
        """Po wyborze kategorii z listy zapisz ją od razu przy zaznaczonym aucie."""
        if getattr(self, "_loading_car_form", False):
            return
        if not hasattr(self, "car_type_var"):
            return
        label = self.normalize_vehicle_type_label(self.car_type_var.get())
        if label:
            self.remember_vehicle_type_category(label)
        selected_id = getattr(self, "car_selected_id", None)
        if selected_id is None and hasattr(self, "cars_tree") and self.cars_tree.selection():
            selected_id = self.car_tree_ids.get(self.cars_tree.selection()[0])
        if not selected_id:
            self.refresh_vehicle_type_combo_values()
            return
        self.conn.execute("UPDATE cars SET vehicle_type=?, updated_at=CURRENT_TIMESTAMP WHERE id=?", (label, int(selected_id)))
        self.conn.commit()
        self.car_selected_id = int(selected_id)
        self.refresh_vehicle_type_combo_values()
        self.load_car_reference_data()
        self.load_cars_tree()
        if hasattr(self, "cars_tree"):
            iid = f"car-{int(selected_id)}"
            if iid in self.cars_tree.get_children(""):
                self.cars_tree.selection_set(iid)
                self.cars_tree.focus(iid)
                self.cars_tree.see(iid)
        try:
            self.load_result_plan_tree()
        except Exception:
            pass
        if hasattr(self, "pair_status_label"):
            self.pair_status_label.configure(text=f"Zapisano kategorię pojazdu: {label or '(brak)'}.")

    def save_vehicle_type_category_from_form(self) -> None:
        """Dopisz kategorię pojazdu i natychmiast pokaż ją na liście wyboru.

        v330: poprzednio użytkownik musiał wpisywać kategorię bezpośrednio w pole
        Combobox, które w aplikacji jest obsługiwane własnym rozwijanym oknem.
        Na części Windows/Tk uniemożliwiało to normalne dopisywanie. Dlatego
        kategoria jest wpisywana w osobnym polu „Dopisz kategorię”, a po dodaniu
        od razu pojawia się na liście i może zostać zapisana przy zaznaczonym aucie.
        """
        if not hasattr(self, "car_type_var"):
            return
        raw = ""
        if hasattr(self, "car_new_type_var"):
            raw = self.car_new_type_var.get().strip()
        if not raw:
            raw = self.car_type_var.get().strip()
        label = self.normalize_vehicle_type_label(raw)
        if not label:
            messagebox.showinfo("Kategorie pojazdów", "Wpisz nazwę kategorii, np. MAN, EUROLIDER, LIDER albo BUS.")
            return
        self.remember_vehicle_type_category(label)
        self.car_type_var.set(label)
        if hasattr(self, "car_new_type_var"):
            self.car_new_type_var.set("")
        self.refresh_vehicle_type_combo_values()
        # Jeżeli auto jest zaznaczone, przypisz kategorię od razu, bez drugiego kliknięcia.
        self.auto_save_selected_car_vehicle_type()
        if hasattr(self, "pair_status_label"):
            self.pair_status_label.configure(text=f"Dodano kategorię pojazdu: {label}. Możesz od razu wpisać następną w polu Dopisz kategorię albo w polu Kategoria / rodzaj autobusu.")
        try:
            if hasattr(self, "car_new_type_entry"):
                self.car_new_type_entry.focus_set()
        except tk.TclError:
            pass
        messagebox.showinfo("Kategorie pojazdów", f"Kategoria '{label}' została dodana do listy wyboru. Możesz wpisać kolejną kategorię ręcznie.")

    def load_car_reference_data(self) -> None:
        self.car_label_to_id = {"(bez auta)": None}
        self.manual_car_label_to_id = {"(bez auta)": None}
        self.manual_car_id_to_label = {}
        self.car_id_to_registration = {}
        self.car_id_to_sort_order = {}
        labels = ["(bez auta)"]
        manual_labels = ["(bez auta)"]
        try:
            rows = self.rows("SELECT id, registration_no, description, COALESCE(vehicle_type, '') AS vehicle_type, COALESCE(sort_order, 0) AS sort_order FROM cars WHERE active=1 ORDER BY CASE WHEN COALESCE(sort_order, 0)>0 THEN 0 ELSE 1 END, COALESCE(sort_order, 0), registration_no COLLATE NOCASE")
        except sqlite3.OperationalError:
            return
        for row in rows:
            car_id = int(row["id"])
            reg = str(row["registration_no"] or "").strip()
            desc = str(row["description"] or "").strip()
            vehicle_type = str(row["vehicle_type"] or "").strip()
            label = reg
            if desc:
                label += f" | {desc}"
            if vehicle_type:
                label += f" | {vehicle_type}"
            manual_label = f"{desc} | {reg}" if desc else reg
            if vehicle_type:
                manual_label += f" | {vehicle_type}"
            if manual_label in self.manual_car_label_to_id:
                manual_label = f"{manual_label} | ID {car_id}"
            self.car_label_to_id[label] = car_id
            self.manual_car_label_to_id[manual_label] = car_id
            self.manual_car_id_to_label[car_id] = manual_label
            self.car_id_to_registration[car_id] = reg
            self.car_id_to_sort_order[car_id] = int(row["sort_order"] or 0)
            labels.append(label)
            manual_labels.append(manual_label)
        if hasattr(self, "pair_car_combo"):
            self.pair_car_combo.configure(values=labels)
            if self.pair_car_var.get() not in self.car_label_to_id:
                self.pair_car_var.set("(bez auta)")
        if hasattr(self, "manual_car_combo"):
            self.manual_car_combo.configure(values=manual_labels)
            if self.manual_car_var.get() not in self.manual_car_label_to_id:
                self.manual_car_var.set("(bez auta)")
        if hasattr(self, "duty_db_assigned_car_combo"):
            self.duty_db_assigned_car_combo.configure(values=labels)
            if self.duty_db_assigned_car_var.get() not in self.car_label_to_id:
                self.duty_db_assigned_car_var.set("(bez auta)")

    def car_plan_order_key(self, car_id: int | None, registration_no: str | None = None) -> tuple[int, int, str]:
        """Kolejność auta w planie: najpierw ręczna kolejność, potem nr rejestracyjny."""
        if car_id is None:
            return (1, 999999, "")
        order = int(self.car_id_to_sort_order.get(int(car_id), 0) or 0)
        reg = (registration_no or self.car_id_to_registration.get(int(car_id), "") or "").strip().upper()
        return (0, order if order > 0 else 999999, reg)

    def ensure_default_cars_and_refresh(self) -> None:
        """Zgodność ze starszym przyciskiem: od v86 tylko odświeża widok aut."""
        self.refresh_cars_and_pairs_views()
        count = int(self.one_value("SELECT COUNT(*) FROM cars", default="0") or 0)
        if hasattr(self, "pair_status_label"):
            self.pair_status_label.configure(text=f"Auta w bazie: {count}")
        messagebox.showinfo("Baza samochodów", f"Lista aut została odświeżona. Auta w bazie: {count}.")

    def reset_cars_from_gui_v86(self) -> None:
        """Ręczny reset listy aut z zakładki Samochody i pary."""
        if not messagebox.askyesno(
            "Reset listy aut",
            "Wyczyścić listę samochodów i stałe pary aut?\n\n"
            "Kierowcy, służby i zaplanowany grafik nie zostaną usunięte. "
            "Pary miesięczne zostaną bez przypisanego auta.",
        ):
            return
        self.reset_cars_tables_v86(commit=True)
        self.clear_car_form()
        self.clear_pair_form()
        self.refresh_cars_and_pairs_views()
