            def manual_w_wg_dates_for_driver(driver_id: int) -> list[str]:
                result: list[str] = []
                for ctx_date, ctx_driver_id, ctx_duty_id, ctx_note, _ctx_car, _ctx_pair in planned_context_entries:
                    try:
                        if int(ctx_driver_id) != int(driver_id):
                            continue
                        duty = duty_rows_by_id.get(int(ctx_duty_id))
                        code = self.normalize_code(duty["code"] if duty is not None else "")
                        note_lower = str(ctx_note or "").lower()
                    except Exception:
                        continue
                    if code in {"W", "WG"} and (note_lower.startswith("ręcznie") or note_lower.startswith("recznie")):
                        result.append(str(ctx_date))
                return sorted(set(result))

            manual_wg_block_lines: list[str] = []
